window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["b"]={"Bartosz": "<b>Bartosz</b> – staropolska skrócona forma imienia <a href=\"https://pl.wikipedia.org/wiki/Bart%C5%82omiej\" target=\"_blank\" rel=\"noopener noreferrer\">Bartłomiej</a> (jedna z wielu wówczas istniejących, inne to np. Bartek, Bartko, Bartusz czy Bartysz). W Polsce używane w średniowieczu (pierwszy zapis w 1216 r.). Imię popularne w tej formie stało się ponownie w ostatnich dziesięcioleciach XX w.", "Bartłomiej": "<b>Bartłomiej</b> (od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aram.</a>&#160;&#8207;בר-תולמי&#8206; – „syn oracza” lub „syn Tolmy”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a>.", "Bogdan": "<b>Bogdan</b>, <b>Bogudan</b>, <b>Bogodan</b>, <b>Bohdan</b>, <b>Bodan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Bogusław": "<b>Bogusław</b>, <b>Bogosław</b>, <b>Bohusław</b>, <b>Bogsław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Imię <i>Bogusław</i> jest przykładem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego</a>, złożonego, osobowego imienia dwuczłonowego, które jest <a href=\"https://pl.wikipedia.org/wiki/Relikt\" target=\"_blank\" rel=\"noopener noreferrer\">reliktem</a> <a href=\"https://pl.wikipedia.org/wiki/Poga%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">pogańskich</a> imion używanych we wczesnym średniowieczu przez <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">Słowian</a>. Składa się z członu <i>Bogu-</i> („Bóg”, „Boga”, ale pierwotnie „los, dola, szczęście”) oraz <i>-sław</i> („sława”). Być może znaczyło pierwotnie „ten, który sławi los”, a później „sławiący Boga”. <a href=\"https://pl.wikipedia.org/wiki/Witold_Taszycki\" target=\"_blank\" rel=\"noopener noreferrer\">Witold Taszycki</a> zaliczył je do grupy najstarszych polskich imion osobowych&#8201;.", "Bronisław": "<b>Bronisław</b>, <b>Bronsław</b>, <b>Barnisław</b>, (zniem.) <b>Brunisław</b>, <b>Brosław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Błażej": "<b>Błażej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa „blaesus” oznaczającego „seplenić”.", "Bolesław": "<b>Bolesław</b> (<i>bole(j)</i> + <i>sław</i> – „bardziej sławny”) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Dawniej zapisywane również w formie skróconej Bosław lub Bolko. Imię dynastyczne w polskiej dynastii <a href=\"https://pl.wikipedia.org/wiki/Piastowie\" target=\"_blank\" rel=\"noopener noreferrer\">Piastów</a> oraz czeskiej <a href=\"https://pl.wikipedia.org/wiki/Przemy%C5%9Blidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Przemyślidów</a>. Do dynastii piastowskiej zostało zapożyczone od <a href=\"https://pl.wikipedia.org/wiki/Przemy%C5%9Blidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Przemyślidów</a> poprzez dziedziczenie po linii żeńskiej (imię kognacyjne). Ostatnim jego piastowskim przedstawicielem był Piast mazowiecki <a href=\"https://pl.wikipedia.org/wiki/Boles%C5%82aw_V_warszawski\" target=\"_blank\" rel=\"noopener noreferrer\">Bolesław V, książę warszawski</a> (XV w.).", "Bernard": "<b>Bernard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „silny niedźwiedź”. (staroniemieckie: bero, bern – niedźwiedź i hart – silny). Wśród patronów – św. <a href=\"https://pl.wikipedia.org/wiki/Bernard_z_Clairvaux\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard z Clairvaux</a>. Formą oboczna tego imienia jest imię <i>Berard</i> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>Berardus</i>), zapisywane czasami jako: Berald(us), Gerard(us).", "Bohdan": "<b>Bohdan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Borys": "<b>Borys</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Protobu%C5%82garzy\" target=\"_blank\" rel=\"noopener noreferrer\">protobułgarskiego</a>. W języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_protobu%C5%82garski\" target=\"_blank\" rel=\"noopener noreferrer\">protobułgarskim</a> imię to oznaczało, według jednych opracowań, „wilk”, „irbis śnieżny”, według innych „mały”, „niski”, lub „waleczny”.", "Bruno": "<b>Bruno, Brunon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa <i>brün</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Nied%C5%BAwied%C5%BA_brunatny\" target=\"_blank\" rel=\"noopener noreferrer\">niedźwiedź</a>” lub „brunatny”. Forma <b>Brunon</b> powstała pod wpływem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim</a>. W Polsce imię Bruno po raz pierwszy zanotowano w <a href=\"https://pl.wikipedia.org/wiki/1236\" target=\"_blank\" rel=\"noopener noreferrer\">1236</a> roku.", "Bogumił": "<b>Bogumił</b>, <b>Bogomił</b>, <b>Bogmił</b>, <b>Bogomieł</b>, <b>Bogmieł</b>, <b>Bogumieł</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Wywodzi się ze złożenia członów: <i>Bog-</i> („Bóg”, ale pierwotnie w znaczeniu „los, dola, szczęście”) oraz <i>-mił</i> („miły”). Oznacza więc: „miły Bogu” (lecz uprzednio mogło znaczyć „ten, któremu los sprzyja”). <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Imiona słowiańskie</a> ze składnikami <i>Bog-</i> (np. Bogumił czy Bogusław) mogą być także słowiańskim naśladownictwem irańskich imion używanych w czasach od <a href=\"https://pl.wikipedia.org/wiki/VI_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">VI</a> do <a href=\"https://pl.wikipedia.org/wiki/IV_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">IV wieku p.n.e.</a>, takich jak Bagafarna („mający sławę od Boga”).", "Benedykt": "<b>Benedykt</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>benedictus</i>, oznaczającego „tego, o którym się dobrze mówi”; „tego, któremu się dobrze życzy”. Znanym imiennikiem był <a href=\"https://pl.wikipedia.org/wiki/Benedykt_z_Nursji\" target=\"_blank\" rel=\"noopener noreferrer\">Benedykt z Nursji</a>, założyciel <a href=\"https://pl.wikipedia.org/wiki/Benedyktyni\" target=\"_blank\" rel=\"noopener noreferrer\">opactwa benedyktyńskiego</a> na <a href=\"https://pl.wikipedia.org/wiki/Monte_Cassino\" target=\"_blank\" rel=\"noopener noreferrer\">Monte Cassino</a>, i <a href=\"https://pl.wikipedia.org/wiki/Baruch_Spinoza\" target=\"_blank\" rel=\"noopener noreferrer\">Spinoza</a>.", "Beniamin": "<b>Beniamin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia biblijnego, oznaczające dosłownie „syn południa” lub „syn prawicy” (w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języku hebrajskim</a> północ jest utożsamiana z lewą, a południe z prawą stroną). Beniamin <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/31_marca\" target=\"_blank\" rel=\"noopener noreferrer\">31 marca</a> i <a href=\"https://pl.wikipedia.org/wiki/19_grudnia\" target=\"_blank\" rel=\"noopener noreferrer\">19 grudnia</a>.", "Brajan": "<b>Brajan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>Brian</em>, <i>Bryan</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>, wywodzące się najprawdopodobniej od słów <i>bruaich</i> „wzgórze”, <i>brigh</i> „wysoki”; „szlachetnie urodzony” lub <i>bri</i> „silny”. Do Polski trafiło z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">języka angielskiego</a> i zaczęło być nadawane częściej dopiero w latach 90. XX wieku. Popularne jest w krajach anglosaskich, gdzie funkcjonuje zarówno jako samodzielne imię, jak i jako forma <a href=\"https://pl.wikipedia.org/wiki/Zdrobnienie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobniała</a> od <a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernarda</a> i <a href=\"https://pl.wikipedia.org/wiki/Barnaba\" target=\"_blank\" rel=\"noopener noreferrer\">Barnaby</a>.", "Brunon": "<b>Bruno, Brunon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa <i>brün</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Nied%C5%BAwied%C5%BA_brunatny\" target=\"_blank\" rel=\"noopener noreferrer\">niedźwiedź</a>” lub „brunatny”. Forma <b>Brunon</b> powstała pod wpływem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim</a>. W Polsce imię Bruno po raz pierwszy zanotowano w <a href=\"https://pl.wikipedia.org/wiki/1236\" target=\"_blank\" rel=\"noopener noreferrer\">1236</a> roku.", "Benjamin": "<p>Benjamin może odnosić się do: Benjamin Netanyahu Benjamin Franklin Benjamin Harrison</p>", "Brian": "<b>Brajan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>Brian</em>, <i>Bryan</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>, wywodzące się najprawdopodobniej od słów <i>bruaich</i> „wzgórze”, <i>brigh</i> „wysoki”; „szlachetnie urodzony” lub <i>bri</i> „silny”. Do Polski trafiło z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">języka angielskiego</a> i zaczęło być nadawane częściej dopiero w latach 90. XX wieku. Popularne jest w krajach anglosaskich, gdzie funkcjonuje zarówno jako samodzielne imię, jak i jako forma <a href=\"https://pl.wikipedia.org/wiki/Zdrobnienie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobniała</a> od <a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernarda</a> i <a href=\"https://pl.wikipedia.org/wiki/Barnaba\" target=\"_blank\" rel=\"noopener noreferrer\">Barnaby</a>.", "Bonifacy": "<b>Bonifacy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>bonum</em> „dobro” i <em>facere</em> „czynić”, czyli oznacza czyniącego dobro.", "Bazyli": "<b>Bazyli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">późnogreckiego</a>. Pochodzi ono od przymiotnika „królewski, cesarski” (<i>basíleios</i>, od <a href=\"https://pl.wikipedia.org/wiki/II_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">II wieku</a> wymawiane <i>basílios</i>), od rzeczownika <i>basileus</i> – „król, wódz, cesarz”. Jego formą oboczną jest Bazyliusz, a żeńskim odpowiednikiem – <a href=\"https://pl.wikipedia.org/wiki/Bazyla\" target=\"_blank\" rel=\"noopener noreferrer\">Bazyla</a>.", "Bożydar": "<b>Bożydar</b>, <b>Bożdar</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie złożone z członów <i>Boż(y)-</i> („Boga”, ale pierwotnie „losu, doli, szczęścia”) i <i>-dar</i> („upominek, dar, ofiara”). Być może oznaczało „tego, kto jest darem losu”. Imię to (wraz z <a href=\"https://pl.wikipedia.org/wiki/Bogodar\" target=\"_blank\" rel=\"noopener noreferrer\">Bogodarem</a>) uważa się za równoważnik znaczeniowy imienia <i>Adeodat</i> (łacińskiego <i>Adeodatus</i>), czy greckiego <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a> lub <a href=\"https://pl.wikipedia.org/wiki/Bogdan\" target=\"_blank\" rel=\"noopener noreferrer\">Bogdan</a>, a zatem Bożydar obchodzi imieniny w dniach wspomnienia św. Adeodatów, których jest kilku.", "Bahadur": "Za historykami <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">chińskiej</a> <a href=\"https://pl.wikipedia.org/wiki/Dynastia_Sui\" target=\"_blank\" rel=\"noopener noreferrer\">dynastii Sui</a> można przyjąć, że tytuł ten był używany przez ludy stepowe żyjące na północ i zachód od <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">Chin</a> co najmniej od <a href=\"https://pl.wikipedia.org/wiki/VII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VII wieku</a>. W <a href=\"https://pl.wikipedia.org/wiki/Pierwszy_kaganat_turecki\" target=\"_blank\" rel=\"noopener noreferrer\">kaganacie starotureckim</a> przyjmował on formę <i>batur</i>, <a href=\"https://pl.wikipedia.org/wiki/Protobu%C5%82garzy\" target=\"_blank\" rel=\"noopener noreferrer\">Protobułgarzy</a> w <a href=\"https://pl.wikipedia.org/wiki/IX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IX wieku</a> używali formy <i>bagatur</i>. <a href=\"https://pl.wikipedia.org/wiki/Czyngis-chan\" target=\"_blank\" rel=\"noopener noreferrer\">Czyngis-chan</a> (w którego czasach występował on w formach <i>bagatur</i> i <i>baatur</i>) nadał go jako oficjalny tytuł honorowy około tysiącu osób ze swojej armii, które chciał szczególnie wyróżnić za odwagę lub wierną służbę. W analogiczny sposób nadawali go władcy państw powstałych po rozpadzie <a href=\"https://pl.wikipedia.org/wiki/Imperium_mongolskie\" target=\"_blank\" rel=\"noopener noreferrer\">imperium mongolskiego</a>, w tym także <a href=\"https://pl.wikipedia.org/wiki/Wielcy_Mogo%C5%82owie\" target=\"_blank\" rel=\"noopener noreferrer\">Wielcy Mogołowie</a>. Od czasów <a href=\"https://pl.wikipedia.org/wiki/Ilchanidzi\" target=\"_blank\" rel=\"noopener noreferrer\">ilchana</a> <a href=\"https://pl.wikipedia.org/wiki/Abu_Sa%E2%80%99id\" target=\"_blank\" rel=\"noopener noreferrer\">Abu Sa’ida</a> (<a href=\"https://pl.wikipedia.org/wiki/1317\" target=\"_blank\" rel=\"noopener noreferrer\">1317</a>–<a href=\"https://pl.wikipedia.org/wiki/1335\" target=\"_blank\" rel=\"noopener noreferrer\">1335</a>) tytułu <i>bahadur</i> używano także jako części tytulatury władcy - postępowali tak <a href=\"https://pl.wikipedia.org/wiki/D%C5%BCalajirydzi\" target=\"_blank\" rel=\"noopener noreferrer\">Dżalajirydzi</a>, <a href=\"https://pl.wikipedia.org/wiki/Timurydzi\" target=\"_blank\" rel=\"noopener noreferrer\">Timurydzi</a>, <a href=\"https://pl.wikipedia.org/wiki/Kara_Kojunlu\" target=\"_blank\" rel=\"noopener noreferrer\">Kara Kojunlu</a>, <a href=\"https://pl.wikipedia.org/wiki/Ak_Kojunlu\" target=\"_blank\" rel=\"noopener noreferrer\">Ak Kojunlu</a>, Wielcy Mogołowie, a w szczególności władcy państw <a href=\"https://pl.wikipedia.org/wiki/Uzbecy\" target=\"_blank\" rel=\"noopener noreferrer\">uzbeckich</a>. Od tego tytułu wywodzi się <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polski</a> termin <a href=\"https://pl.wikipedia.org/wiki/Bohater\" target=\"_blank\" rel=\"noopener noreferrer\">bohater</a>.", "Boris": "<p>Boris (japońska ボリス) - japońska eksperymentalna grupa utworzona w 1992 roku w Tokio.</p>", "Benon": "<b>Benon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, powstałe jako zdrobnienie <i>Bennon</i> od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> <i>Bernhard </i> (<a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard</a>). W Polsce jest to prawdopodobnie skrót <i>Bień</i> od <a href=\"https://pl.wikipedia.org/wiki/Benedykt\" target=\"_blank\" rel=\"noopener noreferrer\">imienia Benedykt</a>.", "Baltazar": "<b>Baltazar</b> – biblijny zapis akadyjskiego imienia <i>Bēl-šar-ușur</i> (tłum. „(boże) <a href=\"https://pl.wikipedia.org/wiki/Bel_(b%C3%B3stwo)\" target=\"_blank\" rel=\"noopener noreferrer\">Belu</a> króla strzeż!”), noszonego przez syna babilońskiego króla <a href=\"https://pl.wikipedia.org/wiki/Nabonid\" target=\"_blank\" rel=\"noopener noreferrer\">Nabonida</a> (biblijny <a href=\"https://pl.wikipedia.org/wiki/Baltazar_(babilo%C5%84ski_ksi%C4%85%C5%BC%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Baltazar</a>). Imię Baltazar pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> <i>basileus</i> i oznaczało króla.", "Ben": "<p>Ben (rucko ⁇ Ben ⁇) - drugi solowy album studiowy amerykańskiego piosenkarza Michaela Jacksona.</p>", "Bastian": "<p>Bastian to niemiecka skrótka Sebastiana.</p>", "Barnaba": "<b>Barnaba</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a>. Wywodzi się od <i>Bar-nebuch</i> i oznacza syna pocieszenia, syna proroctwa.", "Bernhard": "<p>Bernard (Bernard Schwabski; niemiecki Bernhard; 870-es - 891 lub 892) - urodzony poza małżeństwem jedyny syn imperatora Karola III Tłusta z dynastii Karolingi.</p>", "Bonawentura": "<b>Bonawentura</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>, prawdopodobnie sztuczne imię klasztorne. Wywodzi się od słów <i>bona vantura</i> oznaczającego „dobry los”. Imię pierwszy raz użyte przez <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Bonawentura\" target=\"_blank\" rel=\"noopener noreferrer\">św. Bonawenturę</a>, ucznia <a href=\"https://pl.wikipedia.org/wiki/Franciszek_z_Asy%C5%BCu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Franciszka z Asyżu</a>. Jedno z rzadkich w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">języku polskim</a> imion męskich zakończone na -a. (m.in. <a href=\"https://pl.wikipedia.org/wiki/Barnaba\" target=\"_blank\" rel=\"noopener noreferrer\">Barnaba</a>, <a href=\"https://pl.wikipedia.org/wiki/Juda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Juda</a>). Ze względu na końcówkę <i>-a</i> imię bywa błędnie postrzegane jako imię żeńskie.", "Bilal": "<p>Bilal Said Oliver (ang. Bilal Sayeed Oliver, rodzaj.</p>", "Bazyl": "<b>Bazyli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">późnogreckiego</a>. Pochodzi ono od przymiotnika „królewski, cesarski” (<i>basíleios</i>, od <a href=\"https://pl.wikipedia.org/wiki/II_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">II wieku</a> wymawiane <i>basílios</i>), od rzeczownika <i>basileus</i> – „król, wódz, cesarz”. Jego formą oboczną jest Bazyliusz, a żeńskim odpowiednikiem – <a href=\"https://pl.wikipedia.org/wiki/Bazyla\" target=\"_blank\" rel=\"noopener noreferrer\">Bazyla</a>.", "Bariş": "<p>Barış to tureckie słowo oznaczające \"pokój\" i unisex. Nazwa ta rzadko nadaje się kobiecom, przy czym przeważająca większość osób mających tę nazwę to mężczyźni.</p>", "Bruce": "<p>James Bruce (ang. James Bruce; 14 grudnia 1730 - 27 kwietnia 1794) - szkocki podróżnik i pisarz.</p>", "Bertold": "<b>Bertold</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od starogermańskich słów <i>berath</i> „światły” i <i>wald</i> – „władca” i oznaczającego „światły władca”.", "Berk": "<p>Burk, często błędnie przekazywany na język rosyjski jako Burk (ang. Burk, Burke, Bourke, Birk, wycieczka.</p>", "Bo": "<p>Bo lub BO może odnosić się do:</p>", "Bradley": "<p>Bradley to imię i nazwisko w języku angielskim, często używane do nazwiska lub nazwiska mężczyzn. Pochodzi z starożytnego angielskiego słowa \"broad wood\" lub \"broad clearing\".</p>", "Bart": "<p>BART (jap. バート ba:to) - miesięczny japoński czasopism wydany przez firmę Shueisha od maja 1991 do marca 2000 roku.</p>", "Bin": "<p>Bin: /bin - katalog plików wykonywanych w systemach podobnych do Unix. Plik podwójny</p>", "Borysław": "<b>Borzysław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Wywodzi się od słów oznaczających „ten, który zdobywa sławę w boju”. Rosyjskim odpowiednikiem tego imienia jest <i>Borisław (Борислав)</i>.", "Barry": "<p>Barry lub Barry - własne imię (często angielskie). Barry (ang.</p>", "Bojan": "<b>Bojan</b> – <a href=\"https://pl.wikipedia.org/wiki/Derywat_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">derywat</a> od <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskich imion</a> męskich z członem <i>-boj</i> – oznaczającym „bój, bicie, walkę” – takich jak <a href=\"https://pl.wikipedia.org/wiki/Budziboj\" target=\"_blank\" rel=\"noopener noreferrer\">Budziboj</a> lub <a href=\"https://pl.wikipedia.org/wiki/Przyboj\" target=\"_blank\" rel=\"noopener noreferrer\">Przyboj</a>.", "Brendan": "<b>Brendan</b>, <b>Brandon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a> wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_walijski\" target=\"_blank\" rel=\"noopener noreferrer\">walijskiego</a> <i>breenhin</i>, 'książę'. Patronem tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Brendan_%C5%BBeglarz\" target=\"_blank\" rel=\"noopener noreferrer\">Brendan Żeglarz</a>, VI-wieczny mnich i eremita irlandzki, który według legendy w poszukiwaniu odosobnienia wyruszył łodzią na ocean Atlantycki.", "Bernardyn": "<b>Bernardyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia germańskiego, pierwotnie powstałe jako zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard</a> na gruncie łacińsko-włoskim. W Polsce notowane od 1465 r., w formach <i>Bernardyn</i>, <i>Barnardyn</i>, <i>Bernhardyn</i>, <i>Biernardyn</i>, <i>Bernardinus</i>, <i>Barnardinus</i>, <i>Bernhardinus</i>, <i>Biernardinus</i>, z formami pochodnymi Bernasz i Barnasz. Od tego imienia wywodzą się ludowe nazwiska <i>Bernady</i> i <i>Barnady</i>. Istnieje piętnastu świętych lub błogosławionych o tym imieniu.", "Bertrand": "<b>Bertrand</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>berath</i> \"światły\", \"jasny\" i <i>hramm</i> \"kruk\". Znaczy \"biały kruk\". Innym jego wariantem jest <b><a href=\"https://pl.wikipedia.org/wiki/Bertram_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bertram</a></b>. Patronem imienia jest m.in. św. Bertrand z Comminges.", "Berat": "<p>Berat to miasto w hrabstwie Berat w Albanii. To dziewiąte największe miasto w Albanii pod względem ludności.</p>", "Batyr": "<p>Batyr (24 maja 1970 - 26 sierpnia 1993) był azjatyckim słoniem, który został uznany za zdolny do używania niektórych ludzkich wyrażeń. Żyjąc w zoo w sowieckim Kazachstanie, Batyr miał w swojej pamięci ponad 20 słów.</p>", "Bjorn": "<b>Ursus</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od wyrazu <i>ursus</i> oznaczającego „niedźwiedź”. W językach skandynawskich jego odpowiednikiem jest <i>Björn</i>, który cieszy się sporą popularnością. Najwięcej osób nosi to imię w <a href=\"https://pl.wikipedia.org/wiki/Szwecja\" target=\"_blank\" rel=\"noopener noreferrer\">Szwecji</a> (61 099 2006). W <a href=\"https://pl.wikipedia.org/wiki/Norwegia\" target=\"_blank\" rel=\"noopener noreferrer\">Norwegii</a> imię to jest trzecim co do popularności imieniem (nosi je 40 537 osób). Wśród patronów tego imienia – <a href=\"https://pl.wikipedia.org/wiki/Ursus_i_Wiktor\" target=\"_blank\" rel=\"noopener noreferrer\">św. Ursus</a>, męczennik i św. Ursus, biskup (<a href=\"https://pl.wikipedia.org/wiki/VI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VI wiek</a>).", "Brendon": "<p>Brendon - angielskie nazwisko i nazwisko.</p>", "Bülent": "<b>Bülent</b> – tureckie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, oznaczające dosłownie kogoś, kto jest wysoki, wielki, potężny.", "Berthold": "<p>Arnold Adolf Berthold (Arnold Adolf Berthold, 26 lutego 1803, Zost - 3 stycznia 1863, Göttingen) - niemiecki fizjolog i zoolog.</p>", "Bibek": "<p>Bibek jest popularną nazwą wśród mieszkańców Nepali, Bengali i Assam w ogóle, a także wśród Indian w większej skali. Jest to regionalizowana forma Viveka, co oznacza coś w efekcie współczucia, serdecznego uczucia w sanskrcie.</p>", "Baruch": "<b>Baruch</b>, <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia hebrajskiego (ברוך), oznaczające <i>błogosławiony</i>.", "Bharat": "Nazwa „Indie”, której odpowiedniki używane są w wielu językach, pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">języka perskiego</a>. <a href=\"https://pl.wikipedia.org/wiki/Persowie\" target=\"_blank\" rel=\"noopener noreferrer\">Persowie</a>, którzy panowali nad zachodnimi rejonami Indii (dolina Indusu, ob. głównie <a href=\"https://pl.wikipedia.org/wiki/Pakistan\" target=\"_blank\" rel=\"noopener noreferrer\">Pakistan</a>), nazywali je <i>Hindu</i>, od nazwy rzeki <a href=\"https://pl.wikipedia.org/wiki/Indus\" target=\"_blank\" rel=\"noopener noreferrer\">Indus</a> (w sanskrycie <i>Sindhu</i>, po persku <i>Hindu</i>). Nazwy Indii w językach europejskich wywodzą się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka greckiego</a>, w którym inicjalne h słowa perskiego zanikło: stąd Grecy nazywali mieszkańców Indii <i>Indoi</i>, sam zaś kraj <i>India</i>. W islamskim kręgu kulturowym upowszechniła się natomiast nazwa <i>Hindostan</i>.", "Benoit": "<p>Benoît (francuski: [bənwa]) to francuskie imię męskie. Rzadziej jest pisane Benoist.</p>", "Blake": "<p>Blake - skrócie botaniczne, oznaczające, że autorem taksy jest Joseph Blake. Blake (grupa wokalna) - brytyjska grupa wokalna</p>", "Boryslav": "<p>Boryslav (ukrainsky: Борислав) to miasto w Ukrainie. Miasto należy do prowincji Lwowa.</p>", "Bahadir": "<p>Bahadır to powszechne męskie tureckie imię. W języku tureckim \"Bahadır\" oznacza \"odważny\", \"galahad\", \"bohater\", \"odważna\" i/lub \"galanta\".</p>", "Bora": "<p>Borà (włos. Bora, z greckiego.</p>", "Benito": "<b>Benedykt</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>benedictus</i>, oznaczającego „tego, o którym się dobrze mówi”; „tego, któremu się dobrze życzy”. Znanym imiennikiem był <a href=\"https://pl.wikipedia.org/wiki/Benedykt_z_Nursji\" target=\"_blank\" rel=\"noopener noreferrer\">Benedykt z Nursji</a>, założyciel <a href=\"https://pl.wikipedia.org/wiki/Benedyktyni\" target=\"_blank\" rel=\"noopener noreferrer\">opactwa benedyktyńskiego</a> na <a href=\"https://pl.wikipedia.org/wiki/Monte_Cassino\" target=\"_blank\" rel=\"noopener noreferrer\">Monte Cassino</a>, i <a href=\"https://pl.wikipedia.org/wiki/Baruch_Spinoza\" target=\"_blank\" rel=\"noopener noreferrer\">Spinoza</a>.", "Branislav": "<p>Branislav (cyrylicki: Бранислав) jest słowiańskim męskim imieniem, pochodzącym od słowiańskich elementów borna (chronić, bronić) i slava (sława, sławę) i oznacza \"wojownik\", \"obrony chwały\". Kobieta jest nazwą Branislava.</p>", "Bartlomiej": "<p>Bartłomiej to polskie imię męskie, krewny Bartolomeusza. W formie zmniejszających Bartłomiej znajdują się Bartek i Bartosz.</p>", "Bodo": "<p>Bodo (lat. - rodzaj przeciwstawców z klasy kinetoplastidów (Kinetoplastea). W przeciwieństwie do większości pozostałych członków tej grupy, prowadzą swobodny styl życia, zamieszkując zbiorniki wodne.</p>", "Bondo": "<p>Bondo może być: Bondo, plemiona w stanie Odisha w Indiach. Bondo, Kosta D'iwaria, okręg w pobliżu Morza Miękazowego, Francja Bondo, Trento, okręga w prowincji Trento, Włochy Bondo, okręgu w prowincjach Nyanza w Kenii</p>", "Bautista": "<p>David Michael Batista m.in. David Michael Bautista Jr. , rodzaj.</p>", "Boguslaw": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bogusława</b>.</p><b>Bogusława</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Bogus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Bogusław</a> znany od <a href=\"https://pl.wikipedia.org/wiki/1265\" target=\"_blank\" rel=\"noopener noreferrer\">1265</a> roku. Używane były m.in. zdrobnienia <i>Bogusza</i>, <i>Boguszka</i> i <i>Boguchna</i>. W polskim imiennictwie imię to żywe jest do dziś, ze zdrobnieniami: <i>Bogusia</i> czy <i>Boguśka</i>.", "Borislav": "<p>Borislav lub Boryslav (cyrylicki: Борислав) to słowiańskie męskie imię, pochodzące od słowiańskich elementów borti (batal) i slawa (sława, sławę). Kobieta nazywa się Borislava.</p>", "Bauyrzhan": "<p>Bauyrzhan (kazachski: Бауыржан) to kazachskie imię. Nazwa ma dwie części: pierwsza, Bauyr, tradycyjne słowo kazackie oznaczające brata lub krewnego; druga, jan/jaan, perskie i urdu słowo oznaczające duszę lub drogą.</p>", "Bohuslav": "<p>Bohuslav (ukrainsky: Богуслав) to miasto w Ukrainie. Miasto należało do prowincji Kijowa.</p>", "Besarion": "<b>Besarion</b> (<a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">grec.</a> <i>Βησσαρίων</i> – leśny) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego oznaczające pochodzący z miasta Besaro. W niektórych krajach, m.in. w <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosji</a> występuje w <a href=\"https://pl.wikipedia.org/wiki/Greka_bizantyjska\" target=\"_blank\" rel=\"noopener noreferrer\">bizantyjskiej</a> formie <b>Wissarion</b>.", "Bastien": "<p>Bastien to imię pochodzące z francuskiego. To wariant Sebastiana.</p>", "Biju": "<p>Biju (malayalam: ബിജു) to męskie imię i nazwisko w Indiach, zwłaszcza w Bengali, Orissa i Kerali. Znajduje się również w Bangladeszu, gdzie nazwa oznacza \"drugiego syna\".</p>", "Bjørn": "<p>Bjorn Kristensen (ang. Bjorn Christensen; 5 kwietnia 1993 r. w Marsaшлокku, Malta) - maltyjski piłkarz, półobrony klubu ⁇ Hiberniaans ⁇ i zbiornej drużyny Malty.</p>", "Bertram": "<b>Bertram</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>berath</i> „światły”, „jasny” i <i>hramm</i> „kruk”. Znaczy „biały kruk”. Innym jego wariantem jest <b><a href=\"https://pl.wikipedia.org/wiki/Bertrand_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bertrand</a></b>.", "Benno": "<p>Benno (niem. Benno; 1010, Hildeshheim - 16 czerwca 1106, Maisen) - katolicki święty, dziesiąty biskup Maisenskiego (1066 - 1106), syn hrabiego Werner'a von Waldenberga.</p>", "Beslan": "<p>Beslan (rosyjski: Беслан район) jest okręgem samorządowym (raion), w północnej Osetii, Rosja. Ogromnie obszary.</p>", "Bożysław": "<b>Borzysław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Wywodzi się od słów oznaczających „ten, który zdobywa sławę w boju”. Rosyjskim odpowiednikiem tego imienia jest <i>Borisław (Борислав)</i>.", "Bobby": "<p>Robert Olejnik (niem. Robert Olejnek; 26 listopada 1986, Wena, Austria) - austriacki piłkarz pochodzenia polskiego, bramkarz.</p>", "Bartholomew": "<p>Bartholomew był jednym z dwunastu apostołów Jezusa według Nowego Testamentu. Większość współczesnych naukowców uważa, że apostoł św. Batolomeusz jest znany jako Natania w Ewangelii św. Jana (Jana 1:45-51; por.</p>", "Byron": "<p>George Gordon Noel Byron, VI Earl Byron (1788-1824) był angielskim poetykiem romantycznym, często zwanym Lordem Byronem. Jest uważany za jednego z największych poety XIX wieku.</p>", "Bolko": "<b>Bolesław</b> (<i>bole(j)</i> + <i>sław</i> – „bardziej sławny”) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Dawniej zapisywane również w formie skróconej Bosław lub Bolko. Imię dynastyczne w polskiej dynastii <a href=\"https://pl.wikipedia.org/wiki/Piastowie\" target=\"_blank\" rel=\"noopener noreferrer\">Piastów</a> oraz czeskiej <a href=\"https://pl.wikipedia.org/wiki/Przemy%C5%9Blidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Przemyślidów</a>. Do dynastii piastowskiej zostało zapożyczone od <a href=\"https://pl.wikipedia.org/wiki/Przemy%C5%9Blidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Przemyślidów</a> poprzez dziedziczenie po linii żeńskiej (imię kognacyjne). Ostatnim jego piastowskim przedstawicielem był Piast mazowiecki <a href=\"https://pl.wikipedia.org/wiki/Boles%C5%82aw_V_warszawski\" target=\"_blank\" rel=\"noopener noreferrer\">Bolesław V, książę warszawski</a> (XV w.).", "Béla": "<b>Béla</b> – węgierskie imię utożsamiane z <a href=\"https://pl.wikipedia.org/wiki/Adalbert\" target=\"_blank\" rel=\"noopener noreferrer\">Adalbertem</a>, poza Węgrami pisane czasem jako Bela. Imieniny obchodzi na Węgrzech w dniu <a href=\"https://pl.wikipedia.org/wiki/23_kwietnia\" target=\"_blank\" rel=\"noopener noreferrer\">23 kwietnia</a>, poza – <a href=\"https://pl.wikipedia.org/wiki/3_maja\" target=\"_blank\" rel=\"noopener noreferrer\">3 maja</a>.", "Bibin": "<p>Bibin to męskie imię indyjskiego pochodzenia. Jest to również formą posiadania Biba, maleńką formą Biljana.</p>", "Bahram": "<b>Bahram</b> (również: Wahram, Warhran <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pahlawi\" target=\"_blank\" rel=\"noopener noreferrer\">pahl.</a> Whrmzd <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_awestyjski\" target=\"_blank\" rel=\"noopener noreferrer\">awest</a>. <a href=\"https://pl.wikipedia.org/wiki/Weretragna\" target=\"_blank\" rel=\"noopener noreferrer\">Weretragna</a>, <a href=\"https://pl.wikipedia.org/wiki/Wedy\" target=\"_blank\" rel=\"noopener noreferrer\">wedyjski</a> Wrtrahan) – <a href=\"https://pl.wikipedia.org/wiki/Epitet\" target=\"_blank\" rel=\"noopener noreferrer\">epitet</a> <a href=\"https://pl.wikipedia.org/wiki/Indra\" target=\"_blank\" rel=\"noopener noreferrer\">Indry</a>, oznaczający zabójcę smoka Wrtry, jazata zwycięstwa, niszczyciel zła, boża broń, pomocnik jednego z <a href=\"https://pl.wikipedia.org/wiki/Amszaspandowie\" target=\"_blank\" rel=\"noopener noreferrer\">Amszaspandów</a> – <a href=\"https://pl.wikipedia.org/wiki/Ardibeheszt\" target=\"_blank\" rel=\"noopener noreferrer\">Arta Wahiszta</a>, strażnik prawdy na usługach <a href=\"https://pl.wikipedia.org/wiki/Mitra_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mitry</a> i strażnik ognia.", "Beno": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ben</b>.</p><p>Ben (rucko ⁇ Ben ⁇) - drugi solowy album studiowy amerykańskiego piosenkarza Michaela Jacksona.</p>", "Baris": "<p>Baridy (lat. Baris) - rodzaj żółwi-długotwórców z podrodzin Baridinae.</p>", "Bob": "<p>Bob: Bob (Bob) - nazwisko, skrócenie od Roberta (ang. Robert), czasami używane jako Beb (rz.</p>", "Benyamin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Beniamin</b>.</p><b>Beniamin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia biblijnego, oznaczające dosłownie „syn południa” lub „syn prawicy” (w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języku hebrajskim</a> północ jest utożsamiana z lewą, a południe z prawą stroną). Beniamin <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/31_marca\" target=\"_blank\" rel=\"noopener noreferrer\">31 marca</a> i <a href=\"https://pl.wikipedia.org/wiki/19_grudnia\" target=\"_blank\" rel=\"noopener noreferrer\">19 grudnia</a>.", "Binu": "<p>Binu to powszechne imię dla chłopców w stanie Kerala w południowo-zachodniej Indiach. Nazwa była popularna w latach 70.</p>", "Bernardus": "<p>Bernard (lat. Bernardus; IX w.) - biskup Genewy pod koniec IX w.</p>", "Bagrat": "<p>Bagrat to męskie imię popularne w Armenii. Pochodzi z staro perskiego Bagadāta, \"dar Boga\".</p>", "Bao": "<p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Boran": "<p>Trihydridoboron, znany również jako boran lub borin, jest niestabilnym i bardzo reagownym związkiem nierozstabilnym z formułą chemiczną BH3. Zestawienie mieszanki boranu carbonylu BH3 (CO) odgrywało ważną rolę w odkryciu chemicznych właściwości boranu, ponieważ wskazywało na możliwość istnienia cząsteczek boranu.</p>", "Bashar": "<p>Bashar (arabsko: بشار) to imię, nazwisko i imię miejsca. Bashar może odnosić się do:</p>", "Brent": "<p>Brent (ang. Brent Crude, Brent Blend, London Brent) - etalonna marka (sortowy marker) ropy naftowej wydobywana w Morzu Północnym.</p>", "Behruz": "<p>Behrouz, Behrooz, Behrus lub bihuroz (persk. بهروز) to perskie imię, zazwyczaj męskie, co oznacza dobrobyt lub szczęście. Oznacza to \"Uspadek\" i gdy tłumaczono słowo po słowie, oznacza to \"człowiek, który ma dobre życie\" (beh: dobre, rooz: dzień (i odnosi się do roozegar: życie)).</p>", "Barnim": "<b>Barnim</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię pochodzenia słowiańskiego</a>. Było spotykane wśród <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%85%C5%BC%C4%99ta_pomorscy\" target=\"_blank\" rel=\"noopener noreferrer\">książąt pomorskich</a>.", "Boguchwał": "<b>Boguchwał</b>, <b>Bogchwał</b>, <b>Bochwał</b>, <b>Boguchał</b>, <b>Bogufał</b>, <b>Bogofał</b>, <b>Bogfał</b>, <b>Bofał</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członu <i>Bogu-</i> (\"Bóg\", ale pierwotnie \"los, dola, szczęście\") i <i>-chwał</i> (\"chwalić, sławić, dziękować\"). Prawdopodobnie oznaczało \"tego, który sławi szczęście\", późn. \"tego, który sławi Boga\". Zob. też <a href=\"https://pl.wikipedia.org/wiki/Chwalibog\" target=\"_blank\" rel=\"noopener noreferrer\">Chwalibog</a>, <a href=\"https://pl.wikipedia.org/wiki/Chwalibog\" target=\"_blank\" rel=\"noopener noreferrer\">Chwaliboż</a>, <a href=\"https://pl.wikipedia.org/wiki/Chwalibog\" target=\"_blank\" rel=\"noopener noreferrer\">Falibog</a>, <a href=\"https://pl.wikipedia.org/wiki/Chwalibog\" target=\"_blank\" rel=\"noopener noreferrer\">Faliboż</a>.", "Bert": "<p>Albert Gordon Duncanson (ang. Albert Gordon Dunsanson; 2 października 1911 r., Winnipeg - 24 marca 2000 r., Cowansville) - kanadyjski hokejista, mistrz zimowych igrzysk olimpijskich 1932 r. (i wraz z nią mistrz świata) w składzie zbiornej reprezentacji Kanady.</p>", "Babatunde": "<p>Babatunde (varianty: Babatunji, Babajide, Babawande, Babaside, Babatide, Bababode) to męskie imię. W języku joruba oznacza to \"ojciec wraca\" lub \"ojciec wrócił\".</p>", "Borja": "<p>Borja jest miastem w Zaragozie, Aragonia, Hiszpania. Według badania przeprowadzonego w 2004 roku przez Instytut Statystyczny Hiszpanii (INE), miasto to było ludności.</p>", "Basel": "<p>Bazel (/ˈbɑːzəl/, niemiecki: Basel /ˈbaːzəl /, francuski: Bâle /bal/ lub /bɑl/, włoski: Basilea /bazi'lɛːa/, rzymski: Basilea/bazi'lɛˈa/) jest trzecim najbardziej zaludnionym miastem Szwajcarii (180.976 ludności w 2022 roku). Jeśli wziąć pod uwagę cały obszar metropolitalny, miasto ma populację 731 000 osób (w 2004 roku), Basel jest trzecim co do wielkości obszarem metropolitalnym Szwajcarii.</p>", "Borisi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Boris</b>.</p><p>Boris (japońska ボリス) - japońska eksperymentalna grupa utworzona w 1992 roku w Tokio.</p>", "Besnik": "<p>Besnik to albanianskie imię męskie, co oznacza lojalny lub wierny. Osoby z imieniem Besnik to: Besnik Bekteshi (ur. 1941), albański polityk Besnik Bisha (ur. 1958), albański reżyser filmowy i aktor Besnik Bislimi (ur. 1971), kosowski ekonomista, akademik i polityk albanian Besnik Dushaj (ur. 19??), albański politik Besnik Ferati (ur. 2000), makedyński piłkarz Besnik Hasi (ur. 1971), kosowski-albanański piłkarze i...</p>", "Bing": "<p>Bing (z rosyjskiego Bing) - wyszukiwarka opracowana przez międzynarodową korporację Microsoft.</p>", "Bahrom": "<p>Bahrom lub Bakhrom to wariant perskiego męskiego nazwiska Bahram, w języku uzbekskim (Баҳром) i tajgijskim (Баҳрам). To również małajskie imię.</p>", "Bulat": "<p>Bulat jest zarówno męskim nazwiskiem i nazwiskiem z różnym pochodzeniem. Jako męskie imię pochodzi z rosyjskiego słowa oznaczającego \"stół\", ostatecznie z perskiego پولاد (pulâd).</p>", "Bennett": "<p>Edward Turner Bennett (ang. Edward Turner Bennett; 1797 - 1836) - brytyjski lekarz, zoolog i pisarz.</p>", "Baurzhan": "<p>Bauyrzhan (kazachski: Бауыржан) to kazachskie imię. Nazwa ma dwie części: pierwsza, Bauyr, tradycyjne słowo kazackie oznaczające brata lub krewnego; druga, jan/jaan, perskie i urdu słowo oznaczające duszę lub drogą.</p>", "Bekim": "<p>Bekim to albanskie imię męskie, co oznacza błogosławieństwo. Bekim Babić (ur. 1975), biegacz na targach w Bośni i Hercegowinie Bekim Balaj (ur. 1991), piłkarz albanian Bekim Bejta (ur. 1970), kosowski językoznawczy, poet i tłumacz Bekim Berisha (1966-1998), kosowski żołnierz albanian Bekem Christensen (ur. 1973), duński rowerz na rowerze drogowym Bekim Çollaku, były minister europejskich...</p>", "Babar": "<p>Babar (urdu: بابر), złożony również jako Baber, Babur i Babor, to męskie imię pochodzenia perskiego. Zazwyczaj jest używany w odniesieniu do perskiego babr (perskiego ببر), co oznacza \"tygrys\".</p>", "Bharath": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bharat</b>.</p>Nazwa „Indie”, której odpowiedniki używane są w wielu językach, pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">języka perskiego</a>. <a href=\"https://pl.wikipedia.org/wiki/Persowie\" target=\"_blank\" rel=\"noopener noreferrer\">Persowie</a>, którzy panowali nad zachodnimi rejonami Indii (dolina Indusu, ob. głównie <a href=\"https://pl.wikipedia.org/wiki/Pakistan\" target=\"_blank\" rel=\"noopener noreferrer\">Pakistan</a>), nazywali je <i>Hindu</i>, od nazwy rzeki <a href=\"https://pl.wikipedia.org/wiki/Indus\" target=\"_blank\" rel=\"noopener noreferrer\">Indus</a> (w sanskrycie <i>Sindhu</i>, po persku <i>Hindu</i>). Nazwy Indii w językach europejskich wywodzą się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka greckiego</a>, w którym inicjalne h słowa perskiego zanikło: stąd Grecy nazywali mieszkańców Indii <i>Indoi</i>, sam zaś kraj <i>India</i>. W islamskim kręgu kulturowym upowszechniła się natomiast nazwa <i>Hindostan</i>.", "Benedetto": "<p>Benedetto - katolicki czowiek XI - XII wieku. Na konsystorii 1077 roku został ogłoszony kardynalem-kapłanem kościoła Santa-Pudenciana.</p>", "Basilio": "<p>Basillio - własne imię, analog nazwa Waszyliusa; rozpowszechnione w postaci nazwisk.</p>", "Besarioni": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Besarion</b>.</p><b>Besarion</b> (<a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">grec.</a> <i>Βησσαρίων</i> – leśny) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego oznaczające pochodzący z miasta Besaro. W niektórych krajach, m.in. w <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosji</a> występuje w <a href=\"https://pl.wikipedia.org/wiki/Greka_bizantyjska\" target=\"_blank\" rel=\"noopener noreferrer\">bizantyjskiej</a> formie <b>Wissarion</b>.", "Billal": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bilal</b>.</p><p>Bilal Said Oliver (ang. Bilal Sayeed Oliver, rodzaj.</p>", "Buddha": "<p>Buddha oznacza \"Buddha\" lub \"oświecenie\".</p>", "Bình": "<p>Waso jest przedmiotem otwartym w ustach, który może być używany do przechowywania lub ornitoryki. Pięki są wykonane z różnych materiałów, takich jak glisa, gliny, aluminium, miedź, cygar, stal, drewno, metal.</p>", "Breno": "<p>Breno to miasto w włoskiej prowincji Brescia w regionie Lombardy. Miasto to ma powierzchnię około 4 km2, mieszkańców.</p>", "Bill": "<p>Bill (ang. Bill) - imię męskie.</p>", "Bryce": "<p>Bryce (Brice) - program do modelowania 3D, renderingu i animacji specjalizujący się w generowaniu krajobrazów fractalnych. Nazwa została podana w cześć Brysa-Kanonu, którego geometria została zmodyfikowana algorytmem programu.</p>", "Benson": "<p>Konstantyn Walter Benson - angielski ornitolog.</p>", "Bobi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bob</b>.</p><p>Bob: Bob (Bob) - nazwisko, skrócenie od Roberta (ang. Robert), czasami używane jako Beb (rz.</p>", "Blerim": "<p>Blerim jest gminą w hrabstwie Pukë w hrabstwa Shkodër, Albania. W 2005 roku liczba ludności wynosiła 1858.</p>", "Bakir": "<p>Bakir (arabski: بَكِير, oznaczający \"przedstawienie\") lub Bakır (tyrkski, oznaczający\" miedź\") może odnosić się do:</p>", "Bagrati": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bagrat</b>.</p><p>Bagrat to męskie imię popularne w Armenii. Pochodzi z staro perskiego Bagadāta, \"dar Boga\".</p>", "Brooklyn": "<p>Brooklyn - najludniejsza borka (oddział administracyjny) w Nowym Jorku - 2,73 mln mieszkańców (2020). Położony jest na zachodniej części wyspy Long Island.</p>", "Bambang": "<p>Bambang to miasto II klasy w prowincji Nueva Vizcaya w Filipinach. Według danych z 2007 roku, mieście miało 45,440 mieszkańców w 8,742 domach.</p>", "Benjie": "<p>Benjie to imię. Znani ludzie z nazwiskiem to: Benjie Paras (urodzony w 1968 roku), filipiński aktor, komiks, piłkarz koszykówki i trener Benjie E.</p>", "Bledar": "<p>Bledar to albanskie imię męskie. Mieszkańcy tej nazwy to: Bledar Borova (ur. 1983), albanianki trener Bledar Çuçi (ur. 1970), albanianski polityk Bledar Devolli (ur. 1978), albaniansky piłkarz Bledar Gjeçaj (ur. 1970), albanianki piłkarze koszykówki i trener Bledard Hajdini (ur. 1995), kosowski albanianki profesjonalny piłkarzem Bledar Hodo (ur. 1985) albanianki futbolist Bledar Kola (ur. 1972), albanian footballist ...</p>", "Bhupinder": "<p>Bhupinder to indyjskie imię męskie i może odnosić się do: Bhupinder Singh Hooda, indyjski polityk Bhupinder Nath Kirpal, indyjskiego sędziego Bhupinder Singha (muzyk), indyjskiej piosenkarki i muzyka Bhupinder singha z Patiala (1891-1938), Maharaja z Patiala Bhupinder singa, Sr. (ur. 1965), indyjski kryker Zobacz również Bhupinder سنگha (zróżnicowanie)</p>", "Brighton": "<p>Brighton - miasto na południowym wybrzeżu Anglii w hrabstwie Wschodni Sussex, na brzegu prądu La-Manch. Od Londynu jest 50 mil (80 km) po drodze kolejowej.</p>", "Bolebor": "<b>Bolebor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Składa się z członu <i>Bole-</i> (\"więcej\") i <i>-bor</i> (\"walka\", \"walczyć, zmagać się\"). Imię to mogło oznaczać \"tego, kto więcej walczy\".", "Bartholomäus": "<p>Bartolomie Strobel (młodszy) (niem. Bartholomäus, pod.</p>", "Boy": "<p>Boy (rosyjski ⁇ Maleczk ⁇) - debiutancki album irlandzkiej grupy rockowej U2, wydany 20 października 1980 roku i produkowany przez Steve'a Lilliwhita.</p>", "Bacho": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bach</b>.</p><p>Bach (niemiecki Bach) - niemiecka nazwisko, również toponim:</p>", "Balthazar": "<p>Balthazar - belgijski indy-pop i indy-rock. Zespół składa się z Martena Devolder, Jinta Depre, Taisa Delbek, Simona Kasie i Michelle Balken.</p>", "Ba": "<p>Bari (chymiczny symbol - Ba, od łacińskiego Barium) - element chemiczny 2 grupy (po przestarzałej klasyfikacji - głównej podgrupy drugiej grupy, IIA) szóstego okresu okresowego systemu elementów chemicznych D.</p>", "Bao Nam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Bjarne": "<p>Bjarne jest nordiczne męskie imię, wariant Bjorn, i może odnosić się do następujących osób: Bjarne Andersson, biegacz na nartach Bjarne Berg-Sæther, norweski polityk Bjarne Berntsen, norweska trener piłki nożnej i były gracz Bjarne Brøndbo, piosenkarz rockowy Bjarne brustad, skrzypiec B. S.</p>", "Brad": "<p>Brad to amerykański zespół rockowy z Seattle.</p>", "Blazej": "<p>Blažej to czeskie i słowackie imię. Błażej to polskie imię.</p>", "Barnabás": "<p>Barnabás to węgierska męska nazwa. Jest to imię Nowego Testamentu, które oznacza \"syn pociechy\" i było nazwiskiem św.</p>", "Bas": "<p>Cornelis Bas (w 1928 - 2013) - holenderski botanik i mikolog.</p>", "Baldur": "<p>Baldur's Gate to gra komputerowa, opracowana przez kanadyjską studio BioWare i wydana przez Interplay na PC w 1998 roku. Gra ta była pierwszą w serii Baldur's Gate, a następnie pojawiła się Baldur'S Gate: Tales of the Sword Coast oraz Baldur' s Gate II: Shadows of Amn.</p>", "Boby": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bobi</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bob</b>.</p><p>Bob: Bob (Bob) - nazwisko, skrócenie od Roberta (ang. Robert), czasami używane jako Beb (rz.</p>", "Bhushan": "<p>Bhushan to indyjska rodzina. Może odnosić się do:</p>", "Bala": "<p>Bala jest dzielnicą w prowincji Ankara w Turcji. Ogromnie obszarzyła 2563 km2 i liczba ludności w 2007 roku wynosiła 23505 osób, a jego gęstość wynosi 9 osób/km2.</p>", "Bartosh": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bartosz</b>.</p><b>Bartosz</b> – staropolska skrócona forma imienia <a href=\"https://pl.wikipedia.org/wiki/Bart%C5%82omiej\" target=\"_blank\" rel=\"noopener noreferrer\">Bartłomiej</a> (jedna z wielu wówczas istniejących, inne to np. Bartek, Bartko, Bartusz czy Bartysz). W Polsce używane w średniowieczu (pierwszy zapis w 1216 r.). Imię popularne w tej formie stało się ponownie w ostatnich dziesięcioleciach XX w.", "Barnaby": "<p>Barnaby to staroanglowska nazwisko składające się z elementy saksońskiego beorn oznaczającego młodego wojownika, a duńskiego sufiksu oznaczającego \"osadę\". Jako imię, oznacza \"syn pocieszenia\" i jest etymologicznie związane z nowotestamentowym nazwiskiem Barnaba.</p>", "Bach": "<p>Bach (niemiecki Bach) - niemiecka nazwisko, również toponim:</p>", "Bryant": "<p>Bryant (ang. Bryant, rzadko Briant) - angielskie nazwisko i toponim USA.</p>", "Bujar": "<p>Bujar to albanska męska nazwa, co oznacza hojność. Bujar Asqeriu (ur. 1956), albanski aktor Bujar Bukoshi (1947-2025), kosowski polityk Bujar Çani (1946-2012), albanski piłkarz Bujar Dida (ur. 1961), albaniański chemik i dyplomat Bujar Hoxha, albaniacki szachowca Bujar Idrizi (ur. 1991), kosowczy piłkarzem Bujar Lako (1947-2016), albaniackiego gracza Bujar Lika (ur. 1992), szwajcarsko-albaniacki piłkarze...</p>", "Branimir": "<p>Branimir (cyrylicki: Бранимир) jest słowiańskie męskie imię. Jest to połączenie słowiańskich elementów borna (\"chronić, bronić\") i miru (\"świat\" lub \"pokój\" w staroświatowym słowiańskim), a zatem oznacza \"ten, kto broni świata/pokój\".</p>", "Beat": "<b>Beat</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>beatus</i> – <a href=\"https://pl.wikipedia.org/wiki/B%C5%82ogos%C5%82awiony\" target=\"_blank\" rel=\"noopener noreferrer\">błogosławiony</a>. Zbliżone w znaczeniu do imion <a href=\"https://pl.wikipedia.org/wiki/Feliks\" target=\"_blank\" rel=\"noopener noreferrer\">Feliks</a> i <a href=\"https://pl.wikipedia.org/wiki/Fortunat\" target=\"_blank\" rel=\"noopener noreferrer\">Fortunat</a>.", "Bailey": "<p>Jacob Whitman Bailey (ang. Jacob Whitman, 1811 - 1857) - amerykański botanik, kolekcjoner wodorostów, profesor chemii, profesor mineralogii, profesor geologii i pedagog.</p>", "Bhavesh": "<p>Bhavesh lub Bhavish lub Bhawesh (भावेश, ભાવેશ) to indyjskie imię męskie. Pochodzą z sanskrytu bhāva, co oznacza \"istnienie\", i eesh, co oznacza Ishvara, \"Pan, Władca\".</p>", "Brain": "<p>Brain: Brain to jeden z pierwszych wirusów komputerowych. Brain to album kompozytora jazzu i pianisty Hiromi Uehary.</p>", "Bang": "<p>Państwo lub stan (ang. federated state, ale częściej używane jako state) to społeczność terytorialna, która ma własną konstytucję i stanowi część federacji. Stany te różnią się od państw suwerennych tym, że przekazują część swej władzy rządowi federalnemu.</p>", "Bratumił": "<b>Bratumił</b>, <b>Bratomił</b>, <b>Bratmił</b>, (zniem.) <b>Bretomił</b>, <b>Bretmił</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Bratu-</i> (\"bratu\", \"członkowi wspólnoty rodowej\", \"człowiekowi bliskiemu\") i <i>-mił</i> (\"miły\"). Znaczenie imienia: \"miły swoim bliskim\".", "Bahman": "<p>Bahman (persk. bahman, persk. [bæhˈmæn]) jest 11 miesiącem w irańskim kalendarzu. Iran ma 12 miesięcy.</p>", "Behzod": "<p>Behzad lub Behzaad (z klasycznego perskiego: بهزاد Bihzād, lit. 'dobrze urodzony', z به bih 'dobry' + زاد zād 'urodzony'; irańskiego perskiego: بہزاد Behzâd; hindi: बेहज़ाद, romanized: Bēhzād; urdu: بہزad, romanize: Bihzād; tajczyńskiego: Беҳзод; tureckiego: Behzat; uzbekskiego: Behzod) jest męskim nazwiskiem i nazwiskiem pochodzenia perskiego.</p>", "Bello": "<p>Bello (Bellon; zmarł nie później niż 812) - pierwszy francuski graf Karkassona (790 (?) - nie później niż 812), o którym zachowały się informacje w źródłach historycznych.</p>", "Bowen": "<p>Bowen to wieloznaczny termin pochodzący z nazwiska.</p>", "Briones": "<p>Briones prowincja i autonomiczna społeczność La Rioja, północna Hiszpania. Miasto to ma powierzchnię 37,72 km2, liczba ludności w 2009 roku wynosi 867 osób z gęstością 22,99 osób/km2.</p>", "Beau": "<b>Beau</b> (właściwie Christopher John Trevor Midgley), ur. maj <a href=\"https://pl.wikipedia.org/wiki/1946\" target=\"_blank\" rel=\"noopener noreferrer\">1946</a> w <a href=\"https://pl.wikipedia.org/wiki/Leeds\" target=\"_blank\" rel=\"noopener noreferrer\">Leeds</a>, <a href=\"https://pl.wikipedia.org/wiki/Wielka_Brytania\" target=\"_blank\" rel=\"noopener noreferrer\">Wielka Brytania</a> – brytyjski muzyk <a href=\"https://pl.wikipedia.org/wiki/Muzyka_folkowa\" target=\"_blank\" rel=\"noopener noreferrer\">folkowy</a> specjalizujący się w grze na <a href=\"https://pl.wikipedia.org/wiki/Gitara_dwunastostrunowa\" target=\"_blank\" rel=\"noopener noreferrer\">dwunastostrunowej gitarze</a>. Pseudonim Beau <a href=\"https://pl.wikipedia.org/wiki/Wymowa\" target=\"_blank\" rel=\"noopener noreferrer\">wym.</a> <i>bou</i>) w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">jęz. pol.</a> oznacza „eleganta”.", "Boromeusz": "<b>Boromeusz</b> – imię męskie, pochodzące od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Karol_Boromeusz\" target=\"_blank\" rel=\"noopener noreferrer\">św. Karola Boromeusza</a>. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Boromea\" target=\"_blank\" rel=\"noopener noreferrer\">Boromea</a>.", "Boguslav": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bogusław</b>.</p><b>Bogusław</b>, <b>Bogosław</b>, <b>Bohusław</b>, <b>Bogsław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Imię <i>Bogusław</i> jest przykładem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego</a>, złożonego, osobowego imienia dwuczłonowego, które jest <a href=\"https://pl.wikipedia.org/wiki/Relikt\" target=\"_blank\" rel=\"noopener noreferrer\">reliktem</a> <a href=\"https://pl.wikipedia.org/wiki/Poga%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">pogańskich</a> imion używanych we wczesnym średniowieczu przez <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">Słowian</a>. Składa się z członu <i>Bogu-</i> („Bóg”, „Boga”, ale pierwotnie „los, dola, szczęście”) oraz <i>-sław</i> („sława”). Być może znaczyło pierwotnie „ten, który sławi los”, a później „sławiący Boga”. <a href=\"https://pl.wikipedia.org/wiki/Witold_Taszycki\" target=\"_blank\" rel=\"noopener noreferrer\">Witold Taszycki</a> zaliczył je do grupy najstarszych polskich imion osobowych&#8201;.", "Benicjusz": "<b>Benicjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od włoskiego <a href=\"https://pl.wikipedia.org/wiki/Serwici\" target=\"_blank\" rel=\"noopener noreferrer\">serwity</a>, św. <a href=\"https://pl.wikipedia.org/wiki/Filip_Benicjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Filipa Benicjusza</a> (wł. <i>Benizi</i>). <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">Imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/23_sierpnia\" target=\"_blank\" rel=\"noopener noreferrer\">23 sierpnia</a>.", "Basri": "<p>Basri (arabski: بصري) to arabskie męskie imię i nazwisko, a także nazwisko znajdujące się w południowoindyjskim stanie Karnataka, w którym należą do społeczności hinduistycznej Kota Brahmin. Basri może odnosić się do:</p>", "Berry": "<p>Berry - własne imię, które występuje w postaci nazwisk (głównie angielskiego i francuskiego Berry lub Berri), nazwisk i toponimów.</p>", "Bonifacio": "<p>Bonifacio jest gminą w regionie administracyjnym Korsyki, należącą do prowincji Korsy-du-Sud, w okręgu Sartène (poziom), general Bonifacio. Bonifacio znajduje się na średniej wysokości 70 metrów nad morzem, z najniższym punktem 0 metrów i najwyższym punktem 340 metrów.</p>", "Bożymir": "<b>Borzymir</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Borzy-</i> (\"walczyć\", \"walka\") oraz <i>-mir</i> (\"pokój\"). Mogło oznaczać \"ten, który walczy o pokój\".", "Bijan": "<p>Bijan (zwany również Bizhan, Bijhan lub Bejan; perskie: بیژن) to perskie imię, które oznacza \"Hero\". Mieszkańcy nazwanych Bijan to: Bijan (projektant) (1940-2011), nazwisko Pakzad, modny i perfumista Bijan Abdolkarimi (ur. 1963), irański filozof Bijan Allipour (1949-2023), irański biznesmen Bijan Beg Saakadze, szafawijski szlachetny i urzędnik Bijan Beg (syn Rostam Khana), szafawiński urzędniczy Bijan Daneshmand (ur. 1958), irański aktor Bijan...</p>", "Barthélémy": "<p>Barthélemy, czyli Barthélémy, to francuskie imię, krewny Bartolomeusza. Do wybitnych osób z tym nazwiskiem należą:</p>", "Bończa": "<b>Bonifacy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>bonum</em> „dobro” i <em>facere</em> „czynić”, czyli oznacza czyniącego dobro.", "Badreddine": "<p>Badr al-Din (arabski: بدر الدين, lit. 'pełny księżyc wiary') jest muzułmańska nazwisko rodzinnego składające się z elementów Badr i ad-Din.</p>", "Bent": "<p>Bent (rosyjski Izb) - duet z Nottingham w Anglii, składający się z Simona Mills i Nilla Tollida.</p>", "Bronimir": "<b>Bronimir</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Broni-</i> (\"bronić, strzec\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Zapisy takiego imienia nie przechowały się w dokumentach staropolskich, jednak o jego istnieniu może świadczyć przechowanie się w nazwach miejscowych – takich jak <a href=\"https://pl.wikipedia.org/wiki/Bromierz\" target=\"_blank\" rel=\"noopener noreferrer\">Bromierz</a>, <a href=\"https://pl.wikipedia.org/wiki/Bromierzyk\" target=\"_blank\" rel=\"noopener noreferrer\">Bromierzyk</a> – formy <b>Bromir</b>, która mogła stanowić jego formę skróconą.", "Buddhika": "<p>Buddhika to syngalski nazwa. Może odnosić się do: Buddhika Pathirana, sri Lankańskiej polityk Budhika Mendis, sri lankańskiej krykerki Buddhika Kurukularatne, sri lanki polityk Charitha Buddhika, sri lankowa krykerka</p>", "Baldwin": "<b>Baldwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone z członów <i>Bald-</i> – „śmiałość, odwaga” i <i>wini</i> – „przyjaciel, miłośnik”. Mogło ono zatem oznaczać „miłośnika odwagi”, czy też po prostu „śmiałego, odważnego”. Baldwin był jednym z imion rodowych hrabiów z <a href=\"https://pl.wikipedia.org/wiki/Bouillon_(Belgia)\" target=\"_blank\" rel=\"noopener noreferrer\">Bouillon</a> i <a href=\"https://pl.wikipedia.org/wiki/W%C5%82adcy_Flandrii#Dynastia_flandryjska\" target=\"_blank\" rel=\"noopener noreferrer\">hrabiów flandryjskich</a>. W Polsce spotykane po raz pierwszy na przełomie <a href=\"https://pl.wikipedia.org/wiki/XI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XI</a> i <a href=\"https://pl.wikipedia.org/wiki/XII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XII wieku</a> jako imię <a href=\"https://pl.wikipedia.org/wiki/Baldwin_(biskup_krakowski)\" target=\"_blank\" rel=\"noopener noreferrer\">Baldwina, biskupa krakowskiego</a>. Pojawiało się także w formach Baldewin, Beldwin, Balwin, oraz <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">lat.</a> Baldwinus, Baldewinus, Balduwinus, Balwinus i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">fr.</a>-lat. Bauduinus. Niektóre możliwe staropolskie zdrobnienia to: Bal, Bala (masc.), Balich.", "Bono": "<p>Paul David Hewson (ang. Paul David Hewson; rod.</p>", "Badis": "<p>Badis jest naukowym nazwiskiem rodzinnego ryb słodkowodnych w rodzinnym Badidae. Zespół ten występuje w Azji Południowo-Wschodniej.</p>", "Bashkim": "<p>Bashkim to męskie albanskie imię, co oznacza \"jedność\" w języku albańskim.</p>", "Boualem": "<p>Boualem jest miastem w prowincji El Bayadh w Algierii. W 2002 roku liczba ludności wynosiła 5.386.</p>", "Billel": "<p>Bilal (arabski: بلال Bilāl), czyli warianty, jest zarówno nazwiskiem i nazwiskiem pochodzenia arabskiego/afrykańskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Baki̇": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Baky</b>.</p><p>Baku jest stolicą i największym miastem Azerbejdżanu, a także największym mieście leżącym nad wybrzeżą Kaspijską i regionem Kawkaz. Baku znajduje się na wysokości 28 metrów (92 ft) pod poziomem morza, co czyni go najniższym stolicą na świecie i największym miastem pod poziomami morza.</p>", "Bertin": "<p>Berton (francuski: Berton)  - Bertin, ok.</p>", "Barzan": "<p>Barzan - klasa szybkich uderzających łodzi zaprojektowana w Wielkiej Brytanii dla statków wojennych Kataru; znana również jako Super Vita.</p>", "Bulent": "<p>Bülent to tureckie imię męskie i nazwisko rodzinnie oznaczające \"wysoki\" i \"wysoki\", z perskiego boland lub buland (بلند) co oznacza wysoki, wysoki, wywyższony lub wyższy. Równoważna forma w azerbaińskim jest Bülənd.</p>", "Brady": "<p>Brady (ang. Brady) - angielskie i irlandzkie nazwisko.</p>", "Bentley": "<p>Bentley to wielostronny pojęcie.</p>", "Batir": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Batyr</b>.</p><p>Batyr (24 maja 1970 - 26 sierpnia 1993) był azjatyckim słoniem, który został uznany za zdolny do używania niektórych ludzkich wyrażeń. Żyjąc w zoo w sowieckim Kazachstanie, Batyr miał w swojej pamięci ponad 20 słów.</p>", "Bradford": "<p>Bradford, miasto w miejskim okręgu West Yorkshire, w północnej Anglii. Miasto zostało założone w 1974 roku i połączyło gmin Keighley i Shipley, z rzeką Aire.</p>", "Balwinder Singh": "<p>Balwinder Singh Shammi (ang. Balwinder Singh Shammi; rodzaj.</p>", "Bronisz": "<b>Bronisław</b>, <b>Bronsław</b>, <b>Barnisław</b>, (zniem.) <b>Brunisław</b>, <b>Brosław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Biraj": "<p>Biraj to indyjskie i nepalski męskie imię indyjskiego. Wśród znanych osób z tym nazwiskiem są: Biraj Bhatta, nepalejski aktor Biraj Maharjan, nepalewski piłkarz Andrew Biraj, bangladeski fotoreporter</p>", "Boyd": "<p>Boyd (ang. Boyd) - szkocka nazwisko i imię, zwróć uwagę na nazwisko Boyd.</p>", "Batikan": "<p>Batıkan jest powszechną męską turską nazwą. Składa się z dwóch słów: \"Batı\" i \"Kan\".</p>", "Baky": "<p>Baku jest stolicą i największym miastem Azerbejdżanu, a także największym mieście leżącym nad wybrzeżą Kaspijską i regionem Kawkaz. Baku znajduje się na wysokości 28 metrów (92 ft) pod poziomem morza, co czyni go najniższym stolicą na świecie i największym miastem pod poziomami morza.</p>", "Bernie": "<p>Philippe Bernat-Salles (ur. 17 lutego 1970 w Po) - francuski rugbyści, występujący w pozycji winga.</p>", "Borna": "<p>Borna - książę Morskiej Chorwacji w latach 810-821 i vassal Francji. Prawa Dalmatia z miasta Nin.</p>", "Biniyam": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Biniam</b>.</p><p>Benjamin jest powszechnym nazwiskiem męskich, pochodzącym z hebrajskiego בִּנְיָמִין , Binyāmīn, tłumacząc jako 'syn prawej [ręki]' w językach hebrajskim i arabskim, chociaż w Samarytanskim Pentateuch nazwisko pojawia się jako Binyaamem: 'syn moich dni'. Benjamin jest często skrócony na Ben, a czasami Benny, Benito, Benjy, Benji itp.</p>", "Brock": "<p>Brock - seria rosyjskich średnio- i dużych tonnych samochodów ciężarowych, produkowanych od 2023 roku przez kaliningradzką firmę Autor wraz z Foton.</p>", "Baadur": "<p>Baadur (georgijski: ბაადურ) to imię. Znanymi osobami z nazwiska są: Baadur Jobava (ur. 1983), gruziński mistrz szachów Baadur Tsuladze (1935-2018), gruziński aktor, reżyser filmowy, pisarz i nadawca</p>", "Balthasar": "<p>Balthasar (niem. Balthasar; 21 grudnia 1336, Weisenfels - 18 maja 1406, zamek Wartburg) - margraf Meisena, syn Frydryka II Szczerego i Mehtildy (Matyldy) Wschodniej Bawarskiej.</p>", "Bachi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bach</b>.</p><p>Bach (niemiecki Bach) - niemiecka nazwisko, również toponim:</p>", "Bikal": "<p>Bikal jest miastem w hongijskim okręgu Baranya. Miasto ma powierzchnię 17,03 km2, liczba ludności w 2010 roku wynosi 759 osób, a jego gęstość wynosi 45 osób/km2.</p>", "Bay": "<p>Podczas lotu obiekt przechodzi przez atmosferę (zwłaszcza powietrze) lub dalej (przelety do kosmosu), tworząc siłę podnoszącą aerodynamiczną, siłę napędową, używając innego, lżejszego gazu niż powietrze, lub taktyki wystrzelania. Bez bezpośredniego wsparcia z żadnej powierzchni.</p>", "Balasubramanian": "<p>Balasubramaniam lub Balasubramanian (teluga: బాలసుబ్రహ్మణ్యం; tamil: பாலசுப்ரமணியம்; kannada: ಬಾಲಸುಬ್ರಹ್ಮಣ್ಯಂ; malayalam: ബാലസുബ്രഹ്മണ്യം) to męskie imię w południowej Indiach i Sri Lance. Ze względu na tradycję używania nazwisk patronymowych w południowoindyjskich krajach może to być także nazwisko dla mężczyzn i kobiet.</p>", "Bassel": "<p>Bassel (arabsko: باسل) to arabskie imię. Nie należy go mylić z francuskim nazwiskiem Bassil.</p>", "Bogodar": "Imię to (wraz z <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCydar_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bożydarem</a>) uważa się za równoważnik znaczeniowy imienia <i><b>Adeodat</b></i>, a zatem Bogodar obchodzi imieniny w dniach wspomnienia św. Adeodatów.", "Blair": "<p>Blair jest szkocko-anglojęzycznym nazwiskiem pochodzącym z szkockiego języka gaelickiego. Nazwa pochodzi od jednego z licznych miejsc w Szkocji zwanego Blair, pochodzącego od szkockiego gagelickiego blàr, co oznacza \"płano\", \"włódź\" lub \"pole\", często pole bitwy.</p>", "Beltran": "<p>Beltrán to hiszpańsko-italijskie nazwisko (lub nazwisko męskie) początkowo włoskiego pochodzenia (Beltrami), z pierwszą dokumentacją nazwiska znalezioną na Uniwersytecie w Bolonii. Wieki później nazwisko to zaczęło się głównie znajdować w regionie wschodniej Hiszpanii i południowej Francji, gdzie mówi się na języku katalńskim.</p>", "Bento": "Pierwsze wzmianki o bentō pochodzą z V wieku n.e., kiedy to Japończycy wyruszali polować lub łowić ryby z dala od swoich domostw. Zabierali wtedy ze sobą podsuszany <a href=\"https://pl.wikipedia.org/wiki/Ry%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">ryż</a>, który po wymieszaniu z wodą rolowano w małe porcje.", "Baraka": "<i>Baraka</i> to starodawne słowo <a href=\"https://pl.wikipedia.org/wiki/Sufizm\" target=\"_blank\" rel=\"noopener noreferrer\">sufich</a>. Oznacza błogosławieństwo, esencję życia, od której rozpoczyna się ewolucja.", "B": "<b>B</b> (wymowa: <i>be</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>b</b>) – druga litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>, trzecia litera alfabetu polskiego. Oznacza w danym języku zwykle <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dwuwargowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoskę zwartą dwuwargową dźwięczną</a>, np. [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dwuwargowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">b</a>].", "Benone": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Benon</b>.</p><b>Benon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, powstałe jako zdrobnienie <i>Bennon</i> od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> <i>Bernhard </i> (<a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard</a>). W Polsce jest to prawdopodobnie skrót <i>Bień</i> od <a href=\"https://pl.wikipedia.org/wiki/Benedykt\" target=\"_blank\" rel=\"noopener noreferrer\">imienia Benedykt</a>.", "Borzysław": "<b>Borzysław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Wywodzi się od słów oznaczających „ten, który zdobywa sławę w boju”. Rosyjskim odpowiednikiem tego imienia jest <i>Borisław (Борислав)</i>.", "Bhupinder Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bhupinder</b>.</p><p>Bhupinder to indyjskie imię męskie i może odnosić się do: Bhupinder Singh Hooda, indyjski polityk Bhupinder Nath Kirpal, indyjskiego sędziego Bhupinder Singha (muzyk), indyjskiej piosenkarki i muzyka Bhupinder singha z Patiala (1891-1938), Maharaja z Patiala Bhupinder singa, Sr. (ur. 1965), indyjski kryker Zobacz również Bhupinder سنگha (zróżnicowanie)</p>", "Berko": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Berk</b>.</p><p>Burk, często błędnie przekazywany na język rosyjski jako Burk (ang. Burk, Burke, Bourke, Birk, wycieczka.</p>", "Borisovich": "<p>Boris, Borys lub Barys (bułgarski, rosyjski, serbski, ukraiński: Борис; białoruski: Барыс) to męskie imię pochodzenia bułgarskiego. Najczęściej stosowana jest w krajach Europy Wschodniej.</p>", "Bogudar": "Imię to (wraz z <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCydar_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bożydarem</a>) uważa się za równoważnik znaczeniowy imienia <i><b>Adeodat</b></i>, a zatem Bogodar obchodzi imieniny w dniach wspomnienia św. Adeodatów.", "Byju": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Biju</b>.</p><p>Biju (malayalam: ബിജു) to męskie imię i nazwisko w Indiach, zwłaszcza w Bengali, Orissa i Kerali. Znajduje się również w Bangladeszu, gdzie nazwa oznacza \"drugiego syna\".</p>", "Bohusz": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bogusław</b>.</p><b>Bogusław</b>, <b>Bogosław</b>, <b>Bohusław</b>, <b>Bogsław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Imię <i>Bogusław</i> jest przykładem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego</a>, złożonego, osobowego imienia dwuczłonowego, które jest <a href=\"https://pl.wikipedia.org/wiki/Relikt\" target=\"_blank\" rel=\"noopener noreferrer\">reliktem</a> <a href=\"https://pl.wikipedia.org/wiki/Poga%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">pogańskich</a> imion używanych we wczesnym średniowieczu przez <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">Słowian</a>. Składa się z członu <i>Bogu-</i> („Bóg”, „Boga”, ale pierwotnie „los, dola, szczęście”) oraz <i>-sław</i> („sława”). Być może znaczyło pierwotnie „ten, który sławi los”, a później „sławiący Boga”. <a href=\"https://pl.wikipedia.org/wiki/Witold_Taszycki\" target=\"_blank\" rel=\"noopener noreferrer\">Witold Taszycki</a> zaliczył je do grupy najstarszych polskich imion osobowych&#8201;.", "Brooke": "<p>Victor Alexander Brooke, 3rd Baronet; 5 stycznia 1843 - 27 listopada 1891) - angielski-irlandzki baronet, naturalista.</p>", "Behrouz": "<p>Behrouz, Behrooz, Behrus lub bihuroz (persk. بهروز) to perskie imię, zazwyczaj męskie, co oznacza dobrobyt lub szczęście. Oznacza to \"Uspadek\" i gdy tłumaczono słowo po słowie, oznacza to \"człowiek, który ma dobre życie\" (beh: dobre, rooz: dzień (i odnosi się do roozegar: życie)).</p>", "Burt": "<p>Burt to imię i nazwisko, a także skrócona forma innych nazw, takich jak Burton i Herbert, lub nazwisko miejsca. Burt może odnosić się do:</p>", "Bablu": "<p>Bablu (Bengali: বাবলু) jest bengalska męska nazwa daak. Może odnosić się do: Ziauddin Ahmed Bablu (1954-2021), były sekretarz generalny Partii Jatiya Hasanuzzaman Khan Bablu (ur. 1955), piłkarz i trener Rezaul Karim Bablu (ura. 1962), polityk Mohammad Asaduzzaman Bablu (urwa. 1986), polityk Mohammed AssaduzzamanBablu (urał 1996), piłkacz Abu Hena Bablu, kinematograf Nurul Islam Bablu, aktor</p>", "Baudouin": "<p>Baudouin to francuskie męskie imię i nazwisko, związane z Baldwinem. Do wybitnych osób z tym nazwiskiem należą:</p>", "Bảo Nam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Blendi": "<p>Blendi jest głównie językiem albańskim męskie nazwisko. Znanymi osobami, noszącymi nazwisko Blendi, są: Blendi Baftiu (ur. 1998), kosowski piłkarz Blendi Fevziu (ur. 1969), albanianny dziennikarz, pisarz i gospodarz telewizji Blendi Idrizi (ur. 1998, kosowski futbolista Blendi Klosi (ur. 1971), albanianki polityk Blendi Nallbani (ur. 1971, albanian football player),</p>", "Balint": "<p>Bálint lub Balint to węgierska nazwisko pochodzące od Valentina.</p>", "Borivoje": "<p>Borivoje (Serbski cyrylski: Боривоје) to serbskie męskie imię pochodzenia słowiańskiego. Może odnosić się do: Borivoje Đorđević (ur. 1948), serbski piłkarz Borivoje Filipović (ur., 1982), serbski Piłkarz Boorivoje Grbić (ur.1972), artysta komiksów Borivoje Kostić (1930-2011), piłkarza Borivoje Mirković (1884-1969), generała Borivoje Todorović (r. 1930), serbskiego aktora Borivoje Ristić (ur.).</p>", "Baboucarr": "<p>Baboucarr to męskie imię z Gambii. Wśród znanych osób z nazwiskiem są: Baboucarr Gaye (ur. 1998), gambijski bramkarz Baboucarm Njie (ur. 1995), gambijska piłkarz Babucarm-Blaise Jagne (ur. 1955), minister spraw zagranicznych Gambii</p>", "Balazs": "<p>Balázs to węgierska nazwisko i męskie nazwisko, równoważne francuskiej nazwy Blaise.</p>", "Bernard Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bernard</b>.</p><b>Bernard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „silny niedźwiedź”. (staroniemieckie: bero, bern – niedźwiedź i hart – silny). Wśród patronów – św. <a href=\"https://pl.wikipedia.org/wiki/Bernard_z_Clairvaux\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard z Clairvaux</a>. Formą oboczna tego imienia jest imię <i>Berard</i> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>Berardus</i>), zapisywane czasami jako: Berald(us), Gerard(us).", "Bogdan-Alexandru": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bogdan</b>.</p><b>Bogdan</b>, <b>Bogudan</b>, <b>Bogodan</b>, <b>Bohdan</b>, <b>Bodan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Bogumir": "<b>Bogumił</b>, <b>Bogomił</b>, <b>Bogmił</b>, <b>Bogomieł</b>, <b>Bogmieł</b>, <b>Bogumieł</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Wywodzi się ze złożenia członów: <i>Bog-</i> („Bóg”, ale pierwotnie w znaczeniu „los, dola, szczęście”) oraz <i>-mił</i> („miły”). Oznacza więc: „miły Bogu” (lecz uprzednio mogło znaczyć „ten, któremu los sprzyja”). <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Imiona słowiańskie</a> ze składnikami <i>Bog-</i> (np. Bogumił czy Bogusław) mogą być także słowiańskim naśladownictwem irańskich imion używanych w czasach od <a href=\"https://pl.wikipedia.org/wiki/VI_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">VI</a> do <a href=\"https://pl.wikipedia.org/wiki/IV_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">IV wieku p.n.e.</a>, takich jak Bagafarna („mający sławę od Boga”).", "Bazar": "Targowiska mogą mieć charakter spontaniczny lub zorganizowany. W tym drugim przypadku teren przeznaczony do handlu może mieć wyznaczone płatne stanowiska dla osób oferujących swoje towary. Targowiska umożliwiają swobodny, bezpośredni kontakt handlowca z klientem i bezpośrednie negocjowanie <a href=\"https://pl.wikipedia.org/wiki/Cena_(ekonomia)\" target=\"_blank\" rel=\"noopener noreferrer\">ceny</a>. W pewnym sensie rozwinięciem idei targowiska są <a href=\"https://pl.wikipedia.org/wiki/Gie%C5%82da\" target=\"_blank\" rel=\"noopener noreferrer\">giełdy</a>, które od targowisk różnią się w zasadzie tylko bardziej sformalizowanym stylem negocjowania cen.", "Bjarke": "<p>Bjarke to duńskie imię męskie. Mieszkańcy nazwy Bjarke to: Bjarke Ingels (ur. 1974), duński architekt Bjarke ingels Group (BIG), grupa architektów, projektantów i budowniczych z Kopenhadze i Nowego Jorku Bjarke Mogensen (ur. 1985), duński akordeonista Bjarke Møller (ur. 1985), duński hokejista na lodzie Bjarke Refslund (ur. 1981), duński rower górski</p>", "Borisav": "<p>Borisav (cyrylicki: Борисав) to serbskie męskie imię. Wśród znanych osób z nazwiskiem są: Borisav Burmaz (ur. 2001), serbski piłkarz Borisav Đorđević (1952-2024), serbski śpiewacz-poeta i poeta Borisav Jović (1928-2021), serbski ekonomista, dyplomaty i polityk Borisav Kovačević (ur. 1943), serbski polityk Borissav Pisić (1949-2015), bosnijski obstajer Borisav Ristić (1883-1967), serbski oficer wojskowy Borisav Stanković...</p>", "Bat": "<p>BAT - skróta z użyciem liter łacińskiej, która może oznaczać: BAT - British Antarctic Territory (ang. British Antarctic territory).</p>", "Bratislav": "<p>Bratislav (cyrylicki: Братислав) jest pochodzenia słowiańskiego, co oznacza nazwę: \"brat\" - krewny, brat i \"slava\" - chwała, sławę. Kobieta jest Bratislawą (cyrylicki: Братислава).</p>", "Brodie": "<p>Brodie może być nazwiskiem lub nazwiskiem pochodzenia szkockiego, a lokalizacja w Moray, Szkocja, jego znaczenie jest niepewne; nie jest jasne, czy Brodie, jako słowo, ma swoje pochodzenie w językach gaelickim lub piktyjskim. W 2012 roku to imię stało się 53. najpopularniejszym imieniem dla chłopców w Szkocji.</p>", "Beda": "<b>Beda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie łączone z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskim</a> <i>beadu</i>, <i>beado</i> — \"wojna, walka\". Istnieje trzech świętych o tym imieniu, wśród nich najbardziej znanym jest <a href=\"https://pl.wikipedia.org/wiki/Beda_Czcigodny\" target=\"_blank\" rel=\"noopener noreferrer\">Beda Czcigodny</a>, angielski historyk, uczony i <a href=\"https://pl.wikipedia.org/wiki/Doktor_Ko%C5%9Bcio%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">doktor Kościoła</a> z <a href=\"https://pl.wikipedia.org/wiki/VIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VIII wieku</a>.", "Binyam": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Biniam</b>.</p><p>Benjamin jest powszechnym nazwiskiem męskich, pochodzącym z hebrajskiego בִּנְיָמִין , Binyāmīn, tłumacząc jako 'syn prawej [ręki]' w językach hebrajskim i arabskim, chociaż w Samarytanskim Pentateuch nazwisko pojawia się jako Binyaamem: 'syn moich dni'. Benjamin jest często skrócony na Ben, a czasami Benny, Benito, Benjy, Benji itp.</p>", "Bogdan Kazimierz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bogdan</b>.</p><b>Bogdan</b>, <b>Bogudan</b>, <b>Bogodan</b>, <b>Bohdan</b>, <b>Bodan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Bahar": "<p>Mądry kot to rosyjska legenda.</p>", "Biniam": "<p>Benjamin jest powszechnym nazwiskiem męskich, pochodzącym z hebrajskiego בִּנְיָמִין , Binyāmīn, tłumacząc jako 'syn prawej [ręki]' w językach hebrajskim i arabskim, chociaż w Samarytanskim Pentateuch nazwisko pojawia się jako Binyaamem: 'syn moich dni'. Benjamin jest często skrócony na Ben, a czasami Benny, Benito, Benjy, Benji itp.</p>", "Bogdan-Mihai": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bogdan</b>.</p><b>Bogdan</b>, <b>Bogudan</b>, <b>Bogodan</b>, <b>Bohdan</b>, <b>Bodan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Božo": "<p>Božo (Serbski: Божо) to sławskie imię męskie, krewny angielskiego Theo, a podobnie popularne skrócie nazwiska - Božidar, angielski Theodore. Znani ludzie z nazwiska obejmują: Božo Bakota (1950-2015), chorwacki piłkarz Božo Biškupić (ur. 1938), chorwackie polityk i prawnik Božo Broketa (1922-1985), jugosławski piłkarze Božo Đumić (ur., 1992), serbski profesjonalny piłkarzem koszykówki Božo...</p>", "Bellamy": "<p>Bellamy lub odmiana może odnosić się do:</p>", "Ben Zion": "<p>Ben-Zion (Hebrajskie: בֵּן־צִיּוֹן, romanized: Ben-Tsiyyon, lit. 'Syn Syjon') jest hebrajskim imieniem.</p>", "Bogusław Kazimierz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bogusław</b>.</p><b>Bogusław</b>, <b>Bogosław</b>, <b>Bohusław</b>, <b>Bogsław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Imię <i>Bogusław</i> jest przykładem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego</a>, złożonego, osobowego imienia dwuczłonowego, które jest <a href=\"https://pl.wikipedia.org/wiki/Relikt\" target=\"_blank\" rel=\"noopener noreferrer\">reliktem</a> <a href=\"https://pl.wikipedia.org/wiki/Poga%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">pogańskich</a> imion używanych we wczesnym średniowieczu przez <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">Słowian</a>. Składa się z członu <i>Bogu-</i> („Bóg”, „Boga”, ale pierwotnie „los, dola, szczęście”) oraz <i>-sław</i> („sława”). Być może znaczyło pierwotnie „ten, który sławi los”, a później „sławiący Boga”. <a href=\"https://pl.wikipedia.org/wiki/Witold_Taszycki\" target=\"_blank\" rel=\"noopener noreferrer\">Witold Taszycki</a> zaliczył je do grupy najstarszych polskich imion osobowych&#8201;.", "Bahjat": "<p>Bahjat to męskie imię i nazwisko pochodzące z arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Baaduri": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Baadur</b>.</p><p>Baadur (georgijski: ბაადურ) to imię. Znanymi osobami z nazwiska są: Baadur Jobava (ur. 1983), gruziński mistrz szachów Baadur Tsuladze (1935-2018), gruziński aktor, reżyser filmowy, pisarz i nadawca</p>", "Bouchaib": "<p>Bouchaib lub Bouchaïb jest męskim imieniem i nazwiskiem pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Bunyamin": "<p>Bünyamin jest starszym wymową i turecką wariantą Benjamina i może odnosić się do: Bünyamin Sezer, turecki ciężarostac Bünyamin Sudaş, turecki ważostac Mohd Bunyamin Umar, malezyjski piłkarz</p>", "Bradly": "<p>Bradly to zarówno imię, jak i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Boye": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Boy</b>.</p><p>Boy (rosyjski ⁇ Maleczk ⁇) - debiutancki album irlandzkiej grupy rockowej U2, wydany 20 października 1980 roku i produkowany przez Steve'a Lilliwhita.</p>", "Blue": "<p>Blue może oznaczać: Windows Blue - wewnętrzna sygnał Windows 8.1. Blue (gra komputerowa) - erotyczna gra komputerowa opracowana przez firmę Caramel Box.</p>", "Bahadyr": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bahadir</b>.</p><p>Bahadır to powszechne męskie tureckie imię. W języku tureckim \"Bahadır\" oznacza \"odważny\", \"galahad\", \"bohater\", \"odważna\" i/lub \"galanta\".</p>", "Bueno": "Informacje o tej postaci pochodzą z późnego <i>Vitae</i> zachowanego w rękopisie w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_walijski\" target=\"_blank\" rel=\"noopener noreferrer\">języku walijskim</a> (datowanego na 1346 r.).", "Bogurad": "<b>Bogurad</b>, <b>Bogured</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie złożone z członów <i>Bog-</i> (\"Bóg\", ale pierwotnie \"los, dola, szczęście\") i <i>-rad</i> (\"być zadowolonym, chętnym, cieszyć się\"). Mogło zatem oznaczać \"ten, który jest pozytywnie nastawiony do Boga\" albo \"ten, który cieszy się szczęściem\".", "Bugra": "<p>Buğra jest turecką nazwą i może odnosić się do:</p>", "Bagdasar": "<p>Baghdasar (Բաղդասար) lub (Պաղտասար) to armenijska męska nazwa, forma Belshazara.</p>", "Brunno": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bruno</b>.</p><b>Bruno, Brunon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa <i>brün</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Nied%C5%BAwied%C5%BA_brunatny\" target=\"_blank\" rel=\"noopener noreferrer\">niedźwiedź</a>” lub „brunatny”. Forma <b>Brunon</b> powstała pod wpływem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim</a>. W Polsce imię Bruno po raz pierwszy zanotowano w <a href=\"https://pl.wikipedia.org/wiki/1236\" target=\"_blank\" rel=\"noopener noreferrer\">1236</a> roku.", "Beyazit": "<p>Bayezid (zwany również Beyazıt, Beyazid, Bayazid, Bajazet, Beyazit, Bejazid lub Bayazit), arabska, perskia, bengalska, pasztówka i turecka nazwa, z arabskiego baizid, co oznacza \"oddanego świętego\", może odnosić się do:</p>", "Budzisław": "<b>Budzisław</b>, Budzsław – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Budzi-</i> (\"budzić\") i <i>-sław</i> (\"sława\"). Mogło oznaczać \"ten, który zyskuje sławę\". Imię to notowane jest w Polsce od 1136 roku.", "Bharath Reddy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bharath</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bharat</b>.</p>Nazwa „Indie”, której odpowiedniki używane są w wielu językach, pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">języka perskiego</a>. <a href=\"https://pl.wikipedia.org/wiki/Persowie\" target=\"_blank\" rel=\"noopener noreferrer\">Persowie</a>, którzy panowali nad zachodnimi rejonami Indii (dolina Indusu, ob. głównie <a href=\"https://pl.wikipedia.org/wiki/Pakistan\" target=\"_blank\" rel=\"noopener noreferrer\">Pakistan</a>), nazywali je <i>Hindu</i>, od nazwy rzeki <a href=\"https://pl.wikipedia.org/wiki/Indus\" target=\"_blank\" rel=\"noopener noreferrer\">Indus</a> (w sanskrycie <i>Sindhu</i>, po persku <i>Hindu</i>). Nazwy Indii w językach europejskich wywodzą się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka greckiego</a>, w którym inicjalne h słowa perskiego zanikło: stąd Grecy nazywali mieszkańców Indii <i>Indoi</i>, sam zaś kraj <i>India</i>. W islamskim kręgu kulturowym upowszechniła się natomiast nazwa <i>Hindostan</i>.", "Bao Long": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Bada": "<b>bada OS</b> – <a href=\"https://pl.wikipedia.org/wiki/System_operacyjny\" target=\"_blank\" rel=\"noopener noreferrer\">system operacyjny</a> dla <a href=\"https://pl.wikipedia.org/wiki/Telefon_kom%C3%B3rkowy\" target=\"_blank\" rel=\"noopener noreferrer\">telefonów komórkowych</a>. Został stworzony przez firmę <a href=\"https://pl.wikipedia.org/wiki/Samsung\" target=\"_blank\" rel=\"noopener noreferrer\">Samsung</a>, a zaprezentowany w listopadzie 2009. Nazwa <i>bada</i> w tłumaczeniu z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_korea%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">języka koreańskiego</a> oznacza ocean lub morze.", "Ben Mohamed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ben</b>.</p><p>Ben (rucko ⁇ Ben ⁇) - drugi solowy album studiowy amerykańskiego piosenkarza Michaela Jacksona.</p>", "Borromeo": "<b>Boromeusze</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">wł.</a> Borromeo) – <a href=\"https://pl.wikipedia.org/wiki/Lombardia\" target=\"_blank\" rel=\"noopener noreferrer\">lombardzko</a>-<a href=\"https://pl.wikipedia.org/wiki/Piemont\" target=\"_blank\" rel=\"noopener noreferrer\">piemoncki</a> <a href=\"https://pl.wikipedia.org/wiki/R%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">ród</a> kupiecki, bankierski i arystokratyczny, z którego wywodziło się wielu <a href=\"https://pl.wikipedia.org/wiki/Kardyna%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">kardynałów</a>, m.in. św. <a href=\"https://pl.wikipedia.org/wiki/Karol_Boromeusz\" target=\"_blank\" rel=\"noopener noreferrer\">Karol Boromeusz</a> czy <a href=\"https://pl.wikipedia.org/wiki/Federico_Borromeo_(1564%E2%80%931631)\" target=\"_blank\" rel=\"noopener noreferrer\">Fryderyk</a>, uwieczniony w <a href=\"https://pl.wikipedia.org/wiki/Powie%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">powieści</a> <a href=\"https://pl.wikipedia.org/wiki/Alessandro_Manzoni\" target=\"_blank\" rel=\"noopener noreferrer\">Alessandra Manzoniego</a> pt. <i><a href=\"https://pl.wikipedia.org/wiki/Narzeczeni_(powie%C5%9B%C4%87)\" target=\"_blank\" rel=\"noopener noreferrer\">Narzeczeni</a></i>.", "Bolesław Kazimierz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bolesław</b>.</p><b>Bolesław</b> (<i>bole(j)</i> + <i>sław</i> – „bardziej sławny”) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Dawniej zapisywane również w formie skróconej Bosław lub Bolko. Imię dynastyczne w polskiej dynastii <a href=\"https://pl.wikipedia.org/wiki/Piastowie\" target=\"_blank\" rel=\"noopener noreferrer\">Piastów</a> oraz czeskiej <a href=\"https://pl.wikipedia.org/wiki/Przemy%C5%9Blidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Przemyślidów</a>. Do dynastii piastowskiej zostało zapożyczone od <a href=\"https://pl.wikipedia.org/wiki/Przemy%C5%9Blidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Przemyślidów</a> poprzez dziedziczenie po linii żeńskiej (imię kognacyjne). Ostatnim jego piastowskim przedstawicielem był Piast mazowiecki <a href=\"https://pl.wikipedia.org/wiki/Boles%C5%82aw_V_warszawski\" target=\"_blank\" rel=\"noopener noreferrer\">Bolesław V, książę warszawski</a> (XV w.).", "Bogdan-Gabriel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bogdan</b>.</p><b>Bogdan</b>, <b>Bogudan</b>, <b>Bogodan</b>, <b>Bohdan</b>, <b>Bodan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Bảo Khang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Behrooz": "<p>Behrouz, Behrooz, Behrus lub bihuroz (persk. بهروز) to perskie imię, zazwyczaj męskie, co oznacza dobrobyt lub szczęście. Oznacza to \"Uspadek\" i gdy tłumaczono słowo po słowie, oznacza to \"człowiek, który ma dobre życie\" (beh: dobre, rooz: dzień (i odnosi się do roozegar: życie)).</p>", "Barnard": "<p>Barnard jest nazwiskiem z staroangelskiego pochodzenia, pochodzącym z angielsko-saksyjskiej nazwy \"Beornheard\". Składa się z dwóch elementów: \"Beorn\", co oznacza \"młody wojownik\" lub \"miedźwiec\", oraz \"słyszał\", co oznacza\" twardy\", \"odważny\" lub \"silny\". W niektórych przypadkach Barnard jest wersją nazwiska Bernard, które jest francuskim i niemieckim męskim nazwiskiem i nazwiskiem.</p>", "Bai": "Lud Bai ceni wysoko kolor biały, od którego zresztą wywodzi się jego nazwa. Jego przedstawiciele mówią o sobie <i>Baizi</i>, <i>Baini</i> lub <i>Baihuo</i>, co oznacza „Biały Lud”. Oficjalna chińska nazwa została nadana w 1956 roku.", "Boyet": "<p>Boyet to zarówno imię, jak i nazwisko. Wśród znanych osób z nazwiskiem są: Boyet Fernandez (w XXI wieku), filipiński mistrz koszykówki trener Christopher de Leon (ur. 1953), filipiński aktor znany również jako Boyet Boyet Sison (1963-2022), filipińskiego dziennikarza i komentatora sportu Benjamin Boyet (ur. 1979), francuski piłkarz rugby unijny Boyet Bautista (ur. 1981), filipińczyk piłkarza koszykówka</p>", "Beşir": "<p>Beşir to męskie imię, które jest używane w Turcji. Pochodzi od arabskiego korzenia - beşr, co oznacza \"głosnik\".</p>", "Ben-Zion": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ben</b>.</p><p>Ben (rucko ⁇ Ben ⁇) - drugi solowy album studiowy amerykańskiego piosenkarza Michaela Jacksona.</p>", "Barthelemy": "<p>Barthélemy, czyli Barthélémy, to francuskie imię, krewny Bartolomeusza. Do wybitnych osób z tym nazwiskiem należą:</p>", "Barsbold": "<p>Barsbold to mongolskie imię. Wśród znanych osób z nazwą: Rinchen Barsbold (1935-2025), mongolski paleontolog i geolog Ulambayaryn Barsbold, minister środowiska w Mongolii Barsbold Denzen (ur. 1958), mongolska rzeźbiarz i artysta, syn Rinchen Bardsbold</p>", "Beto": "<p>Beto jest nazwiskiem i pseudonimem nazwisk Alberto, Albertino, Adalberto, Berthony, Heriberto, Norberto, Roberto, Humberto i Benito. W większości przypadków występuje w krajach i społecznościch portugalskojęzycznych i hiszpańskich.</p>", "Badriddin": "<p>Badr al-Din (arabski: بدر الدين, lit. 'pełny księżyc wiary') jest muzułmańska nazwisko rodzinnego składające się z elementów Badr i ad-Din.</p>", "Bibian": "<b>Bibian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie utworzone od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiej</a> nazwy rodu <i>Vivius</i> i oznaczające \"należący do rodu <i>Vivii</i>\". Patronem tego imienia jest św. Bibian, biskup <a href=\"https://pl.wikipedia.org/wiki/Saintes\" target=\"_blank\" rel=\"noopener noreferrer\">Saintes</a> (<a href=\"https://pl.wikipedia.org/wiki/V_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">V wiek</a>).", "Bevan": "<p>Bevan jest nazwą pochodzenia welskiego, pochodzącą z ab Ifan oznacza \"syn Evan\" (Ifan jest wariantem Ieuan, welski odpowiednik Jana). Do wybitnych osób z tym nazwiskiem należą:</p>", "Bharat Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bharat</b>.</p>Nazwa „Indie”, której odpowiedniki używane są w wielu językach, pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">języka perskiego</a>. <a href=\"https://pl.wikipedia.org/wiki/Persowie\" target=\"_blank\" rel=\"noopener noreferrer\">Persowie</a>, którzy panowali nad zachodnimi rejonami Indii (dolina Indusu, ob. głównie <a href=\"https://pl.wikipedia.org/wiki/Pakistan\" target=\"_blank\" rel=\"noopener noreferrer\">Pakistan</a>), nazywali je <i>Hindu</i>, od nazwy rzeki <a href=\"https://pl.wikipedia.org/wiki/Indus\" target=\"_blank\" rel=\"noopener noreferrer\">Indus</a> (w sanskrycie <i>Sindhu</i>, po persku <i>Hindu</i>). Nazwy Indii w językach europejskich wywodzą się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka greckiego</a>, w którym inicjalne h słowa perskiego zanikło: stąd Grecy nazywali mieszkańców Indii <i>Indoi</i>, sam zaś kraj <i>India</i>. W islamskim kręgu kulturowym upowszechniła się natomiast nazwa <i>Hindostan</i>.", "Babajide": "<p>Bàbájídé jest męskim imieniem pochodzenia joruba; główna grupa etniczna w południowo-zachodniej Nigerii. Nazwa pochodzi od jorubańskich słów, bàbá - \"ojciec \" jí -\"budzisz się\",\" i dé -\"przybyć\".</p>", "Bao Minh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Bizhan": "<p>Bijan (zwany również Bizhan, Bijhan lub Bejan; perskie: بیژن) to perskie imię, które oznacza \"Hero\". Mieszkańcy nazwanych Bijan to: Bijan (projektant) (1940-2011), nazwisko Pakzad, modny i perfumista Bijan Abdolkarimi (ur. 1963), irański filozof Bijan Allipour (1949-2023), irański biznesmen Bijan Beg Saakadze, szafawijski szlachetny i urzędnik Bijan Beg (syn Rostam Khana), szafawiński urzędniczy Bijan Daneshmand (ur. 1958), irański aktor Bijan...</p>", "Bao Trung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Bhaskaran": "<p>Bhaskaran to męskie nazwisko tamilowe i malayali lub nazwisko patronymiczne z pochodzenia w sanskrcie oznaczające \"słońce\".</p>", "Benzion": "<p>Ben-Zion (Hebrajskie: בֵּן־צִיּוֹן, romanized: Ben-Tsiyyon, lit. 'Syn Syjon') jest hebrajskim imieniem.</p>", "Bibi": "<p>Kim Hyosho (kor. Kim형서, 金亨瑞, rodzaj.</p>", "Baja": "<b>Baja</b> lub <b>bay'a</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab</a>. بَيْعَة = „sprzedaż”, „transakcja handlowa”) – <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamska</a> przysięga wierności składana <a href=\"https://pl.wikipedia.org/wiki/Kalif\" target=\"_blank\" rel=\"noopener noreferrer\">kalifowi</a> przez muzułmanów. Odbierający przysięgę kalif zobowiązywał się do przestrzegania przepisów prawa muzułmańskiego, natomiast muzułmanin składający ją uznawał autorytet kalifa i przysięgał mu posłuszeństwo. Muzułmanin składający przysięgę symbolicznie dotykał otwartej dłoni kalifa. Jej złożeniu często towarzyszyła wielka uroczystość. Baję złożyło <a href=\"https://pl.wikipedia.org/wiki/Mahomet\" target=\"_blank\" rel=\"noopener noreferrer\">Mahometowi</a> 1400 muzułmanów w Al-Hudajbiji. <a href=\"https://pl.wikipedia.org/wiki/Mirza_Gulam_Ahmad\" target=\"_blank\" rel=\"noopener noreferrer\">Mirza Gulam Ahmad</a>, założyciel islamskiego ruchu reformatorskiego <a href=\"https://pl.wikipedia.org/wiki/Ahmadijja\" target=\"_blank\" rel=\"noopener noreferrer\">ahmadijja</a>, formalnie rozpoczął swoje panowanie nad islamską gminą od odebrania baji. W czasach przedislamskich pojęcie to oznaczało zakończenie transakcji handlowej wyrażone przez potrząśnięcie dłonią.", "Berenger": "<p>Berengar to męskie imię pochodzące z korzeni germańskich, które oznaczają \"źwiedzie\" i \"piedź\". Nazwa ta pojawia się często wśród niektórych szlachetnych rodzin w średniowieczu, zwłaszcza wśród Unruochings i pokrewnych.</p>", "Bảo Long": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Bharat Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bharat</b>.</p>Nazwa „Indie”, której odpowiedniki używane są w wielu językach, pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">języka perskiego</a>. <a href=\"https://pl.wikipedia.org/wiki/Persowie\" target=\"_blank\" rel=\"noopener noreferrer\">Persowie</a>, którzy panowali nad zachodnimi rejonami Indii (dolina Indusu, ob. głównie <a href=\"https://pl.wikipedia.org/wiki/Pakistan\" target=\"_blank\" rel=\"noopener noreferrer\">Pakistan</a>), nazywali je <i>Hindu</i>, od nazwy rzeki <a href=\"https://pl.wikipedia.org/wiki/Indus\" target=\"_blank\" rel=\"noopener noreferrer\">Indus</a> (w sanskrycie <i>Sindhu</i>, po persku <i>Hindu</i>). Nazwy Indii w językach europejskich wywodzą się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka greckiego</a>, w którym inicjalne h słowa perskiego zanikło: stąd Grecy nazywali mieszkańców Indii <i>Indoi</i>, sam zaś kraj <i>India</i>. W islamskim kręgu kulturowym upowszechniła się natomiast nazwa <i>Hindostan</i>.", "Blagoy": "<p>Blagoy (Bolgarski: Благой) to bułgarskie imię męskie i może odnosić się do: Blagoy Blagoev (ur. 1956), olympijski ciężarostach dla Bułgarii Blagoy Georgiev (ur. 1981), bułgarski piłkarz Blagoy Makendzhiev (ur. 1988), bułgarski piłkarze Blagoy Nakov (ur. 1985), bułgara piłkarza Blagoy Popov (1902-1968), współodpowiedziany wraz z Georgiem Dimitrovem i Wasil Tanewem w procesie w Lipsku Blagoym Shklifovem, bułgarskim dialektykiem i...</p>", "Bogdan-Ioan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bogdan</b>.</p><b>Bogdan</b>, <b>Bogudan</b>, <b>Bogodan</b>, <b>Bohdan</b>, <b>Bodan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Bruno Miguel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bruno</b>.</p><b>Bruno, Brunon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa <i>brün</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Nied%C5%BAwied%C5%BA_brunatny\" target=\"_blank\" rel=\"noopener noreferrer\">niedźwiedź</a>” lub „brunatny”. Forma <b>Brunon</b> powstała pod wpływem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim</a>. W Polsce imię Bruno po raz pierwszy zanotowano w <a href=\"https://pl.wikipedia.org/wiki/1236\" target=\"_blank\" rel=\"noopener noreferrer\">1236</a> roku.", "Bożidar": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bożydar</b>.</p><b>Bożydar</b>, <b>Bożdar</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie złożone z członów <i>Boż(y)-</i> („Boga”, ale pierwotnie „losu, doli, szczęścia”) i <i>-dar</i> („upominek, dar, ofiara”). Być może oznaczało „tego, kto jest darem losu”. Imię to (wraz z <a href=\"https://pl.wikipedia.org/wiki/Bogodar\" target=\"_blank\" rel=\"noopener noreferrer\">Bogodarem</a>) uważa się za równoważnik znaczeniowy imienia <i>Adeodat</i> (łacińskiego <i>Adeodatus</i>), czy greckiego <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a> lub <a href=\"https://pl.wikipedia.org/wiki/Bogdan\" target=\"_blank\" rel=\"noopener noreferrer\">Bogdan</a>, a zatem Bożydar obchodzi imieniny w dniach wspomnienia św. Adeodatów, których jest kilku.", "Bhavish": "<p>Bhavesh lub Bhavish lub Bhawesh (भावेश, ભાવેશ) to indyjskie imię męskie. Pochodzą z sanskrytu bhāva, co oznacza \"istnienie\", i eesh, co oznacza Ishvara, \"Pan, Władca\".</p>", "Borisław": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Borysław</b>.</p><b>Borzysław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Wywodzi się od słów oznaczających „ten, który zdobywa sławę w boju”. Rosyjskim odpowiednikiem tego imienia jest <i>Borisław (Борислав)</i>.", "Braad": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Brad</b>.</p><p>Brad to amerykański zespół rockowy z Seattle.</p>", "Beñat": "<p>Beñat jest baskijską męską wariantą nazwy Bernard, która pochodzi z pochodzenia germańskiego. Istnieją warianty w innych językach, w tym hiszpańskim i włoskim Bernardo.</p>", "Benjamin Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Benjamin</b>.</p><p>Benjamin może odnosić się do: Benjamin Netanyahu Benjamin Franklin Benjamin Harrison</p>", "Belaid": "<p>Belaid lub typowo Belaïd (arabski: بلعيد) jest zarówno arabskim nazwiskiem, jak i męskim nazwisku. Do wybitnych osób z tym nazwiskiem należą:</p>", "Bernadyn": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bernadin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bernadine</b>.</p><p>Bernadine to żeńskie imię, wariant pisowni Bernardine. Znanymi osobami z nazwiska są: Bernadine Bezuidenhout (ur. 1993), nowozelandzkie krykerka Bernadine Craft, amerykański polityk z Wyomingu Bernadine Custer (1900-1991), amerykańska artystka Bernadina Hayes (1912-1987), amerykańska piosenkarka i aktorka Bernadines Healy (1944-2011), amerykański kardiolog Bernadine Jayasinghe, osobowość telewizyjna, zwycięzca prezydenckich nagród i...</p>", "Boryslaw": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Boryslav</b>.</p><p>Boryslav (ukrainsky: Борислав) to miasto w Ukrainie. Miasto należy do prowincji Lwowa.</p>", "Bhawani": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bhavani</b>.</p><p>Bhavani to miasto i dzielnica w hrabstwie Erode w stanie Tamil Nadu, India.</p>", "Beniamini": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Beniamin</b>.</p><b>Beniamin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia biblijnego, oznaczające dosłownie „syn południa” lub „syn prawicy” (w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języku hebrajskim</a> północ jest utożsamiana z lewą, a południe z prawą stroną). Beniamin <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/31_marca\" target=\"_blank\" rel=\"noopener noreferrer\">31 marca</a> i <a href=\"https://pl.wikipedia.org/wiki/19_grudnia\" target=\"_blank\" rel=\"noopener noreferrer\">19 grudnia</a>.", "Bronisław Jan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bronisław</b>.</p><b>Bronisław</b>, <b>Bronsław</b>, <b>Barnisław</b>, (zniem.) <b>Brunisław</b>, <b>Brosław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Blažej": "<p>Blažej to czeskie i słowackie imię. Błażej to polskie imię.</p>", "Beraat": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Berat</b>.</p><p>Berat to miasto w hrabstwie Berat w Albanii. To dziewiąte największe miasto w Albanii pod względem ludności.</p>", "Berel": "<p>Berel (jiddish: בערעל, hebrajsky: ברל) to męskie imię, które może odnosić się do: Berel Lang (ur. 1933), amerykańskiego historyków i autora Berel Lazar (ur. 1964), rabin prawosławny, jednego z dwóch ubiegających się o tytuł \"Główny rabin Rosji\" Baruch Dov Povarsky (ur. 1931), często określany jako rabin Berel Povarsky, rosh yeshiva Dov Schwartzman (1921-2011), również zwany Berel Schwartzmann, rosyjski urodzony amerykański rabin żydowski Haredi, wychowawca i...</p>", "Blagoja": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Blagoj</b>.</p><p>Blagoj (makedońska: Благој) to makedońskie męskie imię. Może odnosić się do: Blagoj Jankov Mučeto, makedonii partizan, który został ogłoszony ludowym bohaterem Jugosławii Blagoj Nacoski (ur. 1979), makedonii tenorowy piosenkarz operowy Blagoj Stračkovski (1920-1943), makedonian komunista</p>", "Bohdan-Mykhailo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bohdan</b>.</p><b>Bohdan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Blagoje": "<p>Blagoje (serski cyrylski: Благоје) to męskie słowiańskie imię pochodzące od korzeni blag (\"miękkie, łagodne\") i -oje. Jest zarejestrowana w Serbii od średniowiecza.</p>", "Botros": "<p>Boutros, Botros lub Butrus (arabski: بطرس) jest arabską formą nazwy Piotr, pochodzącą bezpośrednio z greckiego Πέτρος (Petros) i uzupełniona również przez koptyjski: ⁇ i syryjski: ?? . Jest to zwykle używane jako imię męskie, ale może być również używane jako nazwisko.</p>", "Bronisław Kazimierz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bronisław</b>.</p><b>Bronisław</b>, <b>Bronsław</b>, <b>Barnisław</b>, (zniem.) <b>Brunisław</b>, <b>Brosław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Bedrich": "<p>Bedřich jest czeskim męskim nazwiskiem, czeskim wariantem niemieckiego nazwiska Friedrich i angielskiego Frederick. Zdaje się również jako nazwisko (oblubieńki: Bedřichová).</p>", "Brahma": "<b>Brahma</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a> ब्रह्मा, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_tamilski\" target=\"_blank\" rel=\"noopener noreferrer\">tamil.</a>&#160;பிரம்மா) – w <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduizmie</a> wraz z <a href=\"https://pl.wikipedia.org/wiki/Wisznu\" target=\"_blank\" rel=\"noopener noreferrer\">Wisznu</a> i <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aiwa\" target=\"_blank\" rel=\"noopener noreferrer\">Śiwą</a> tworzy <a href=\"https://pl.wikipedia.org/wiki/Trimurti\" target=\"_blank\" rel=\"noopener noreferrer\">Trimurti</a>. W każdym z niezliczonej ilości <a href=\"https://pl.wikipedia.org/wiki/Wszech%C5%9Bwiat\" target=\"_blank\" rel=\"noopener noreferrer\">wszechświatów</a>, stwarzanych przez <a href=\"https://pl.wikipedia.org/wiki/Mahawisznu\" target=\"_blank\" rel=\"noopener noreferrer\">Mahawisznu</a> Brahma jest pierwszą, śmiertelną, żywą istotą, zrodzoną z formy <i>virat</i> – kwiatu lotosu wyrastającego z jeziora umiejscowionego w pępku <a href=\"https://pl.wikipedia.org/wiki/Garbhodaka%C5%9Baji\" target=\"_blank\" rel=\"noopener noreferrer\">Garbhodakaśaji Wisznu</a>, stąd bierze się jego inne imię <i>Aja</i>.", "Benyamine": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Benyamin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Beniamin</b>.</p><b>Beniamin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia biblijnego, oznaczające dosłownie „syn południa” lub „syn prawicy” (w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języku hebrajskim</a> północ jest utożsamiana z lewą, a południe z prawą stroną). Beniamin <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/31_marca\" target=\"_blank\" rel=\"noopener noreferrer\">31 marca</a> i <a href=\"https://pl.wikipedia.org/wiki/19_grudnia\" target=\"_blank\" rel=\"noopener noreferrer\">19 grudnia</a>.", "Berislav": "<p>Berislav (zwany również Berisav) jest słowiańskim męskim imieniem pochodzącym od beri \"noszą\" i slawy \"głosię, sławę\". Kobieta to Berislava.</p>", "Bael": "<b>Bael</b> – w tradycji <a href=\"https://pl.wikipedia.org/wiki/Okultyzm\" target=\"_blank\" rel=\"noopener noreferrer\">okultystycznej</a>, <a href=\"https://pl.wikipedia.org/wiki/Demon\" target=\"_blank\" rel=\"noopener noreferrer\">demon</a>, król <a href=\"https://pl.wikipedia.org/wiki/Piek%C5%82o\" target=\"_blank\" rel=\"noopener noreferrer\">piekła</a> (wschodniej części), znany również pod imieniem <b>Baal</b>. Włada 66 legionami duchów piekielnych. W <i><a href=\"https://pl.wikipedia.org/wiki/Lemegeton\" target=\"_blank\" rel=\"noopener noreferrer\">Lemegetonie</a></i> i <i><a href=\"https://pl.wikipedia.org/wiki/Pseudomonarchia_Daemonum\" target=\"_blank\" rel=\"noopener noreferrer\">Pseudomonarchii Daemonum</a></i> jest pierwszym <a href=\"https://pl.wikipedia.org/wiki/Duch_(spirytyzm)\" target=\"_blank\" rel=\"noopener noreferrer\">duchem</a>.", "Bharath Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bharath</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bharat</b>.</p>Nazwa „Indie”, której odpowiedniki używane są w wielu językach, pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">języka perskiego</a>. <a href=\"https://pl.wikipedia.org/wiki/Persowie\" target=\"_blank\" rel=\"noopener noreferrer\">Persowie</a>, którzy panowali nad zachodnimi rejonami Indii (dolina Indusu, ob. głównie <a href=\"https://pl.wikipedia.org/wiki/Pakistan\" target=\"_blank\" rel=\"noopener noreferrer\">Pakistan</a>), nazywali je <i>Hindu</i>, od nazwy rzeki <a href=\"https://pl.wikipedia.org/wiki/Indus\" target=\"_blank\" rel=\"noopener noreferrer\">Indus</a> (w sanskrycie <i>Sindhu</i>, po persku <i>Hindu</i>). Nazwy Indii w językach europejskich wywodzą się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka greckiego</a>, w którym inicjalne h słowa perskiego zanikło: stąd Grecy nazywali mieszkańców Indii <i>Indoi</i>, sam zaś kraj <i>India</i>. W islamskim kręgu kulturowym upowszechniła się natomiast nazwa <i>Hindostan</i>.", "Bernard Jan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bernard</b>.</p><b>Bernard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „silny niedźwiedź”. (staroniemieckie: bero, bern – niedźwiedź i hart – silny). Wśród patronów – św. <a href=\"https://pl.wikipedia.org/wiki/Bernard_z_Clairvaux\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard z Clairvaux</a>. Formą oboczna tego imienia jest imię <i>Berard</i> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>Berardus</i>), zapisywane czasami jako: Berald(us), Gerard(us).", "Bunta": "<b>Bunta</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ぶんた, ブンタ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Biron": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Byron</b>.</p><p>George Gordon Noel Byron, VI Earl Byron (1788-1824) był angielskim poetykiem romantycznym, często zwanym Lordem Byronem. Jest uważany za jednego z największych poety XIX wieku.</p>", "Bala Ram": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bala</b>.</p><p>Bala jest dzielnicą w prowincji Ankara w Turcji. Ogromnie obszarzyła 2563 km2 i liczba ludności w 2007 roku wynosiła 23505 osób, a jego gęstość wynosi 9 osób/km2.</p>", "Bogdan-Constantin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bogdan</b>.</p><b>Bogdan</b>, <b>Bogudan</b>, <b>Bogodan</b>, <b>Bohdan</b>, <b>Bodan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Bedgost": "<b>Bdzigost</b> [bˈd͡ʑigɔst﻿&#65279;<a href=\"https://www.wikidata.org/wiki/Q8615234#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>], <b>Bedgost</b> [ˈbɛdgɔst&#65279;<a href=\"https://www.wikidata.org/wiki/Q8615234#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>] – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Składa się z członu <i>Bdzi-</i> (\"powoduje, że czuwa\", por. <i>budzić</i>) i <i>gost-</i> (\"gościć\", \"gość\"). Mogło zatem oznaczać \"budzący gości\".", "Barnett": "<p>Barnett to zarówno nazwisko, jak i męskie imię.</p>", "Bernadin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bernadine</b>.</p><p>Bernadine to żeńskie imię, wariant pisowni Bernardine. Znanymi osobami z nazwiska są: Bernadine Bezuidenhout (ur. 1993), nowozelandzkie krykerka Bernadine Craft, amerykański polityk z Wyomingu Bernadine Custer (1900-1991), amerykańska artystka Bernadina Hayes (1912-1987), amerykańska piosenkarka i aktorka Bernadines Healy (1944-2011), amerykański kardiolog Bernadine Jayasinghe, osobowość telewizyjna, zwycięzca prezydenckich nagród i...</p>", "Bhumi": "<b>Bhūmi</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">skt.</a> <i>bhūmi</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_tybeta%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">tyb.</a> <i>byang chub sems dpa'i sa</i>, poziomy oświeconej istoty) – w tradycji <a href=\"https://pl.wikipedia.org/wiki/Mahajana\" target=\"_blank\" rel=\"noopener noreferrer\">mahajany</a> oznacza dziesięć poziomów <a href=\"https://pl.wikipedia.org/wiki/Bodhisattwa\" target=\"_blank\" rel=\"noopener noreferrer\">Bodhisattwy</a> na ścieżce przebudzenia. Sanskrycki termin bhūmi oznacza dosłownie \"podstawę\". Każdy poziom oznacza etap urzeczywistnienia i służy jako podstawa dla następnego poziomu. Każdy poziom oznacza określony postęp w treningu i towarzyszy mu konsekwentny wzrost mocy i mądrości.", "Bảo Trung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Bhagwant": "<p>Bhagwant może odnosić się do Bhagwant Das, władcy Amber Bhagwant Mann, indyjskiego polityka i aktora Bhagwant Nagar, miasteczka w okręgu Unnao w stanie Uttar Pradesh Bhagwant Singh, władca Jat stanu Dholpur Bhagwant Sing z Mewar, tytułowego władcy indyjskiej książęckiej stanu Udaipur lub Mewar Bhagwant University, znajdującej się w Ajmer, Rajasthan, India</p>", "Bechara": "<p>Bishara, Beshero, Bechara lub Beshara (بشارة) jest powszechną nazwą arabską i koptyjską na Bliskim Wschodzie. Najczęściej występuje w Libanie, Egipcie, Iraku i Syrii.</p>", "Bolesław Józef": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bolesław</b>.</p><b>Bolesław</b> (<i>bole(j)</i> + <i>sław</i> – „bardziej sławny”) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Dawniej zapisywane również w formie skróconej Bosław lub Bolko. Imię dynastyczne w polskiej dynastii <a href=\"https://pl.wikipedia.org/wiki/Piastowie\" target=\"_blank\" rel=\"noopener noreferrer\">Piastów</a> oraz czeskiej <a href=\"https://pl.wikipedia.org/wiki/Przemy%C5%9Blidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Przemyślidów</a>. Do dynastii piastowskiej zostało zapożyczone od <a href=\"https://pl.wikipedia.org/wiki/Przemy%C5%9Blidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Przemyślidów</a> poprzez dziedziczenie po linii żeńskiej (imię kognacyjne). Ostatnim jego piastowskim przedstawicielem był Piast mazowiecki <a href=\"https://pl.wikipedia.org/wiki/Boles%C5%82aw_V_warszawski\" target=\"_blank\" rel=\"noopener noreferrer\">Bolesław V, książę warszawski</a> (XV w.).", "Bhavani": "<p>Bhavani to miasto i dzielnica w hrabstwie Erode w stanie Tamil Nadu, India.</p>", "Bogdan-George": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bogdan</b>.</p><b>Bogdan</b>, <b>Bogudan</b>, <b>Bogodan</b>, <b>Bohdan</b>, <b>Bodan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Benignus": "<b>Benigny</b>, <b>Benignus</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa „uprzejmy”, „przyjazny”. Patronem imienia jest m.in. <a href=\"https://pl.wikipedia.org/wiki/Benigny_z_Dijon\" target=\"_blank\" rel=\"noopener noreferrer\">św. Benigny z Dijon</a>, męczennik z II wieku.", "Bariş Can": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bariş</b>.</p><p>Barış to tureckie słowo oznaczające \"pokój\" i unisex. Nazwa ta rzadko nadaje się kobiecom, przy czym przeważająca większość osób mających tę nazwę to mężczyźni.</p>", "Balasubramaniam": "<p>Balasubramaniam lub Balasubramanian (teluga: బాలసుబ్రహ్మణ్యం; tamil: பாலசுப்ரமணியம்; kannada: ಬಾಲಸುಬ್ರಹ್ಮಣ್ಯಂ; malayalam: ബാലസുബ്രഹ്മണ്യം) to męskie imię w południowej Indiach i Sri Lance. Ze względu na tradycję używania nazwisk patronymowych w południowoindyjskich krajach może to być także nazwisko dla mężczyzn i kobiet.</p>", "Bhawan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bhawani</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bhavani</b>.</p><p>Bhavani to miasto i dzielnica w hrabstwie Erode w stanie Tamil Nadu, India.</p>", "Buddha Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Buddha</b>.</p><p>Buddha oznacza \"Buddha\" lub \"oświecenie\".</p>", "Baris Can": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bariş</b>.</p><p>Barış to tureckie słowo oznaczające \"pokój\" i unisex. Nazwa ta rzadko nadaje się kobiecom, przy czym przeważająca większość osób mających tę nazwę to mężczyźni.</p>", "Bo Hyun": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bo</b>.</p><p>Bo lub BO może odnosić się do:</p>", "Bharathi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bharath</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bharat</b>.</p>Nazwa „Indie”, której odpowiedniki używane są w wielu językach, pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">języka perskiego</a>. <a href=\"https://pl.wikipedia.org/wiki/Persowie\" target=\"_blank\" rel=\"noopener noreferrer\">Persowie</a>, którzy panowali nad zachodnimi rejonami Indii (dolina Indusu, ob. głównie <a href=\"https://pl.wikipedia.org/wiki/Pakistan\" target=\"_blank\" rel=\"noopener noreferrer\">Pakistan</a>), nazywali je <i>Hindu</i>, od nazwy rzeki <a href=\"https://pl.wikipedia.org/wiki/Indus\" target=\"_blank\" rel=\"noopener noreferrer\">Indus</a> (w sanskrycie <i>Sindhu</i>, po persku <i>Hindu</i>). Nazwy Indii w językach europejskich wywodzą się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka greckiego</a>, w którym inicjalne h słowa perskiego zanikło: stąd Grecy nazywali mieszkańców Indii <i>Indoi</i>, sam zaś kraj <i>India</i>. W islamskim kręgu kulturowym upowszechniła się natomiast nazwa <i>Hindostan</i>.", "Bernard Henryk": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bernard</b>.</p><b>Bernard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „silny niedźwiedź”. (staroniemieckie: bero, bern – niedźwiedź i hart – silny). Wśród patronów – św. <a href=\"https://pl.wikipedia.org/wiki/Bernard_z_Clairvaux\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard z Clairvaux</a>. Formą oboczna tego imienia jest imię <i>Berard</i> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>Berardus</i>), zapisywane czasami jako: Berald(us), Gerard(us).", "Bandile": "<p>Bandile to męskie imię, pochodzące od słowa Nguni ukwanda/kwandile, co oznacza \"zwiększyć/powiększyć/rozszerzyć/rozwijać\". Do wybitnych osób z tym nazwiskiem należą: Bandile Masuku (fl.</p>", "Bogdan-Nicolae": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bogdan</b>.</p><b>Bogdan</b>, <b>Bogudan</b>, <b>Bogodan</b>, <b>Bohdan</b>, <b>Bodan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Bardhyl": "<p>Bardhyl, Bardhyll lub Bardhul jest albaniackim męskim imieniem, co oznacza \"biały/świetły\", odzwierciedlającym się również z iliryjskiego imienia Bardylis i Messapic Barzidihi i Barduli. Ten sam korzeń znajduje się w albanii Bardh-i (męski) i Bardh-a (męski), a także w albanii nazwisko Bardhi, co oznacza \"biały\".</p>", "Bonifacio Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bonifacio</b>.</p><p>Bonifacio jest gminą w regionie administracyjnym Korsyki, należącą do prowincji Korsy-du-Sud, w okręgu Sartène (poziom), general Bonifacio. Bonifacio znajduje się na średniej wysokości 70 metrów nad morzem, z najniższym punktem 0 metrów i najwyższym punktem 340 metrów.</p>", "Bogdan-Vasile": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bogdan</b>.</p><b>Bogdan</b>, <b>Bogudan</b>, <b>Bogodan</b>, <b>Bohdan</b>, <b>Bodan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Basti": "<p>Basti jest miastem i miejscem położenia gmin Basti w stanie Uttar Pradesh w Indiach.</p>", "Budziwoj": "<b>Budziwoj</b>, <b>Budźwoj</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Budzi-</i>, <i>Budź-</i> (\"budzić\") i <i>-woj</i> (\"wojownik\"). Oznacza \"tego, który budzi wojowników, wzywa do walki\".", "Bogoljub": "<p>Bogoljub (serski cyrylski: Богољуб) to serbskie imię męskie, co oznacza \"miłość do Boga\". Może odnosić się do: Bogoljub Jevtić (1886-1960), serbskiego polityka Bogoljub Karić (ur. 1954), serbskiego biznesmena i polityka Boguljub Kočović (1920-2013), serbskiego prawnika i statystyka Bogoljuba Marković (ur., 2005), serbskiego koszykarza Bogoljupa Mitić (1969-2017), serbskiego aktora i komika Bogoljubu Nedeljković (191920-1986), serbskiego...</p>", "Badir": "<p>Badir (arabski: بدير) to arabskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Bibek Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bibek</b>.</p><p>Bibek jest popularną nazwą wśród mieszkańców Nepali, Bengali i Assam w ogóle, a także wśród Indian w większej skali. Jest to regionalizowana forma Viveka, co oznacza coś w efekcie współczucia, serdecznego uczucia w sanskrcie.</p>", "Bromir": "<b>Bronimir</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Broni-</i> (\"bronić, strzec\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Zapisy takiego imienia nie przechowały się w dokumentach staropolskich, jednak o jego istnieniu może świadczyć przechowanie się w nazwach miejscowych – takich jak <a href=\"https://pl.wikipedia.org/wiki/Bromierz\" target=\"_blank\" rel=\"noopener noreferrer\">Bromierz</a>, <a href=\"https://pl.wikipedia.org/wiki/Bromierzyk\" target=\"_blank\" rel=\"noopener noreferrer\">Bromierzyk</a> – formy <b>Bromir</b>, która mogła stanowić jego formę skróconą.", "Bella": "<p>Bella to marka kosmetyki dla kobiet. Bella - piosenka Kenji Zyraka (2013).</p>", "Bao Ngoc": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Bolesław Tadeusz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bolesław</b>.</p><b>Bolesław</b> (<i>bole(j)</i> + <i>sław</i> – „bardziej sławny”) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Dawniej zapisywane również w formie skróconej Bosław lub Bolko. Imię dynastyczne w polskiej dynastii <a href=\"https://pl.wikipedia.org/wiki/Piastowie\" target=\"_blank\" rel=\"noopener noreferrer\">Piastów</a> oraz czeskiej <a href=\"https://pl.wikipedia.org/wiki/Przemy%C5%9Blidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Przemyślidów</a>. Do dynastii piastowskiej zostało zapożyczone od <a href=\"https://pl.wikipedia.org/wiki/Przemy%C5%9Blidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Przemyślidów</a> poprzez dziedziczenie po linii żeńskiej (imię kognacyjne). Ostatnim jego piastowskim przedstawicielem był Piast mazowiecki <a href=\"https://pl.wikipedia.org/wiki/Boles%C5%82aw_V_warszawski\" target=\"_blank\" rel=\"noopener noreferrer\">Bolesław V, książę warszawski</a> (XV w.).", "Bogdan-Marian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bogdan</b>.</p><b>Bogdan</b>, <b>Bogudan</b>, <b>Bogodan</b>, <b>Bohdan</b>, <b>Bodan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Ben Nabil": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ben</b>.</p><p>Ben (rucko ⁇ Ben ⁇) - drugi solowy album studiowy amerykańskiego piosenkarza Michaela Jacksona.</p>", "Bang Giang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bang</b>.</p><p>Państwo lub stan (ang. federated state, ale częściej używane jako state) to społeczność terytorialna, która ma własną konstytucję i stanowi część federacji. Stany te różnią się od państw suwerennych tym, że przekazują część swej władzy rządowi federalnemu.</p>", "Bao Duy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Bruno Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bruno</b>.</p><b>Bruno, Brunon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa <i>brün</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Nied%C5%BAwied%C5%BA_brunatny\" target=\"_blank\" rel=\"noopener noreferrer\">niedźwiedź</a>” lub „brunatny”. Forma <b>Brunon</b> powstała pod wpływem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim</a>. W Polsce imię Bruno po raz pierwszy zanotowano w <a href=\"https://pl.wikipedia.org/wiki/1236\" target=\"_blank\" rel=\"noopener noreferrer\">1236</a> roku.", "Bảo Hưng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Bohdan-Volodymyr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bohdan</b>.</p><b>Bohdan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Bayezid": "<p>Bayezid (zwany również Beyazıt, Beyazid, Bayazid, Bajazet, Beyazit, Bejazid lub Bayazit), arabska, perskia, bengalska, pasztówka i turecka nazwa, z arabskiego baizid, co oznacza \"oddanego świętego\", może odnosić się do:</p>", "Barnabi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Barnaby</b>.</p><p>Barnaby to staroanglowska nazwisko składające się z elementy saksońskiego beorn oznaczającego młodego wojownika, a duńskiego sufiksu oznaczającego \"osadę\". Jako imię, oznacza \"syn pocieszenia\" i jest etymologicznie związane z nowotestamentowym nazwiskiem Barnaba.</p>", "Bernard Paul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bernard</b>.</p><b>Bernard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „silny niedźwiedź”. (staroniemieckie: bero, bern – niedźwiedź i hart – silny). Wśród patronów – św. <a href=\"https://pl.wikipedia.org/wiki/Bernard_z_Clairvaux\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard z Clairvaux</a>. Formą oboczna tego imienia jest imię <i>Berard</i> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>Berardus</i>), zapisywane czasami jako: Berald(us), Gerard(us).", "Benito Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Benito</b>.</p><b>Benedykt</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>benedictus</i>, oznaczającego „tego, o którym się dobrze mówi”; „tego, któremu się dobrze życzy”. Znanym imiennikiem był <a href=\"https://pl.wikipedia.org/wiki/Benedykt_z_Nursji\" target=\"_blank\" rel=\"noopener noreferrer\">Benedykt z Nursji</a>, założyciel <a href=\"https://pl.wikipedia.org/wiki/Benedyktyni\" target=\"_blank\" rel=\"noopener noreferrer\">opactwa benedyktyńskiego</a> na <a href=\"https://pl.wikipedia.org/wiki/Monte_Cassino\" target=\"_blank\" rel=\"noopener noreferrer\">Monte Cassino</a>, i <a href=\"https://pl.wikipedia.org/wiki/Baruch_Spinoza\" target=\"_blank\" rel=\"noopener noreferrer\">Spinoza</a>.", "Behram": "<b>Behram</b> (ok. 1765–1840) – przywódca (<i>dżemadar</i>) <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduistycznej</a> <a href=\"https://pl.wikipedia.org/wiki/Sekta\" target=\"_blank\" rel=\"noopener noreferrer\">sekty</a> <a href=\"https://pl.wikipedia.org/wiki/Thugowie\" target=\"_blank\" rel=\"noopener noreferrer\">thugów</a> – dusicieli zabijających ofiary na cześć bogini <a href=\"https://pl.wikipedia.org/wiki/Kali\" target=\"_blank\" rel=\"noopener noreferrer\">Kali</a>. Funkcję tę sprawował przez blisko 40 lat, póki w 1837 nie został zdradzony przez brytyjskiego informatora i aresztowany. Krótko po zatrzymaniu przyznał się do własnoręcznego uduszenia przy pomocy rytualnego sukna (lub rumāl) 125 osób i nadzorowania uduszenia kolejnych 150, jednak rok później przyznał się do „bycia obecnym” przy 931 morderstwach. Ze względu na tak dużą liczbę <a href=\"https://pl.wikipedia.org/wiki/Zab%C3%B3jstwo\" target=\"_blank\" rel=\"noopener noreferrer\">morderstw</a>, Behram uważany jest za najbardziej wydajnego indywidualnego <a href=\"https://pl.wikipedia.org/wiki/Seryjny_morderca\" target=\"_blank\" rel=\"noopener noreferrer\">seryjnego mordercę</a> w historii. Został skazany na śmierć i powieszony przez Brytyjczyków.", "Behruzi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Behruz</b>.</p><p>Behrouz, Behrooz, Behrus lub bihuroz (persk. بهروز) to perskie imię, zazwyczaj męskie, co oznacza dobrobyt lub szczęście. Oznacza to \"Uspadek\" i gdy tłumaczono słowo po słowie, oznacza to \"człowiek, który ma dobre życie\" (beh: dobre, rooz: dzień (i odnosi się do roozegar: życie)).</p>", "Balasubramanyam": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Balasubramaniam</b>.</p><p>Balasubramaniam lub Balasubramanian (teluga: బాలసుబ్రహ్మణ్యం; tamil: பாலசுப்ரமணியம்; kannada: ಬಾಲಸುಬ್ರಹ್ಮಣ್ಯಂ; malayalam: ബാലസുബ്രഹ്മണ്യം) to męskie imię w południowej Indiach i Sri Lance. Ze względu na tradycję używania nazwisk patronymowych w południowoindyjskich krajach może to być także nazwisko dla mężczyzn i kobiet.</p>", "Bayezit": "<p>Bayezid (zwany również Beyazıt, Beyazid, Bayazid, Bajazet, Beyazit, Bejazid lub Bayazit), arabska, perskia, bengalska, pasztówka i turecka nazwa, z arabskiego baizid, co oznacza \"oddanego świętego\", może odnosić się do:</p>", "Bijal": "<p>Bijal to zarówno kobiece imię, jak i nazwisko. Wśród znanych osób z imieniem: Bijal P.</p>", "Bhavan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bhavani</b>.</p><p>Bhavani to miasto i dzielnica w hrabstwie Erode w stanie Tamil Nadu, India.</p>", "Bell": "<p>Bell, Bell (ang. bell - ⁇ колокол ⁇ , ⁇ колокольчик ⁇) - nazwisko i toponim.</p>", "Boureima": "<p>Boureima to imię. Oto lista znanych osób, z tym nazwiskiem: Boureima Badini (ur. 1956), burkinabski polityk Boureima Hassane Bandé (ur. 1998), burkinabski piłkarz Boureima Maïga (ur. 1983), burkinabecki piłkarze Boureima Ouattara (ur. 1984), burkinabekin piłkarza Boureima Zongo (ur. 16 marca 1972), burkinabé były piłkarzem</p>", "Bolesław Stefan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bolesław</b>.</p><b>Bolesław</b> (<i>bole(j)</i> + <i>sław</i> – „bardziej sławny”) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Dawniej zapisywane również w formie skróconej Bosław lub Bolko. Imię dynastyczne w polskiej dynastii <a href=\"https://pl.wikipedia.org/wiki/Piastowie\" target=\"_blank\" rel=\"noopener noreferrer\">Piastów</a> oraz czeskiej <a href=\"https://pl.wikipedia.org/wiki/Przemy%C5%9Blidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Przemyślidów</a>. Do dynastii piastowskiej zostało zapożyczone od <a href=\"https://pl.wikipedia.org/wiki/Przemy%C5%9Blidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Przemyślidów</a> poprzez dziedziczenie po linii żeńskiej (imię kognacyjne). Ostatnim jego piastowskim przedstawicielem był Piast mazowiecki <a href=\"https://pl.wikipedia.org/wiki/Boles%C5%82aw_V_warszawski\" target=\"_blank\" rel=\"noopener noreferrer\">Bolesław V, książę warszawski</a> (XV w.).", "Bảo Ngọc": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Babatunji": "<p>Babatunde (varianty: Babatunji, Babajide, Babawande, Babaside, Babatide, Bababode) to męskie imię. W języku joruba oznacza to \"ojciec wraca\" lub \"ojciec wrócił\".</p>", "Bobo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bob</b>.</p><p>Bob: Bob (Bob) - nazwisko, skrócenie od Roberta (ang. Robert), czasami używane jako Beb (rz.</p>", "Bohdan-Vladyslav": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bohdan</b>.</p><b>Bohdan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Bohdan-Vasyl": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bohdan</b>.</p><b>Bohdan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Bhawani Prasad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bhawani</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bhavani</b>.</p><p>Bhavani to miasto i dzielnica w hrabstwie Erode w stanie Tamil Nadu, India.</p>", "Bhakti": "<b>Bhakti</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskr.</a> <i>bhakti</i> – przywiązanie, miłość; termin zwykle oddawany jako <b>pobożność</b>) – forma religijności w <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduizmie</a> przejawiająca się głębokim emocjonalnym i intelektualnym oddaniem <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">bogu</a>, której <a href=\"https://pl.wikipedia.org/wiki/Metafora\" target=\"_blank\" rel=\"noopener noreferrer\">metaforą</a> może być miłosny związek z bóstwem, a zarazem niezwykle silny, żywiołowy ruch religijno-społeczny. Osoba praktykująca bhakti nazywana jest <a href=\"https://pl.wikipedia.org/wiki/Bhakta\" target=\"_blank\" rel=\"noopener noreferrer\">bhaktą</a>.", "Bảo Việt": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Buddha Bir": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Buddha</b>.</p><p>Buddha oznacza \"Buddha\" lub \"oświecenie\".</p>", "Bohdan-Ivan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bohdan</b>.</p><b>Bohdan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Badrudin": "<p>Badr al-Din (arabski: بدر الدين, lit. 'pełny księżyc wiary') jest muzułmańska nazwisko rodzinnego składające się z elementów Badr i ad-Din.</p>", "Benild": "<b>Benild</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>, którego patronem jest św. <a href=\"https://pl.wikipedia.org/wiki/Benild_Roman%C3%A7on\" target=\"_blank\" rel=\"noopener noreferrer\">Benild</a>, brat zakonny (zm. <a href=\"https://pl.wikipedia.org/wiki/1862\" target=\"_blank\" rel=\"noopener noreferrer\">1862</a>).", "Bảo Khánh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Bogomir": "<b>Bogumił</b>, <b>Bogomił</b>, <b>Bogmił</b>, <b>Bogomieł</b>, <b>Bogmieł</b>, <b>Bogumieł</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Wywodzi się ze złożenia członów: <i>Bog-</i> („Bóg”, ale pierwotnie w znaczeniu „los, dola, szczęście”) oraz <i>-mił</i> („miły”). Oznacza więc: „miły Bogu” (lecz uprzednio mogło znaczyć „ten, któremu los sprzyja”). <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Imiona słowiańskie</a> ze składnikami <i>Bog-</i> (np. Bogumił czy Bogusław) mogą być także słowiańskim naśladownictwem irańskich imion używanych w czasach od <a href=\"https://pl.wikipedia.org/wiki/VI_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">VI</a> do <a href=\"https://pl.wikipedia.org/wiki/IV_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">IV wieku p.n.e.</a>, takich jak Bagafarna („mający sławę od Boga”).", "Benu": "Imię jego prawdopodobnie wywodziło się od słowa „weben” (wbn), co oznaczało „wznoszący się w blasku” lub „świecący, błyszczący”.", "Bohdan-Arsen": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bohdan</b>.</p><b>Bohdan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Bhawesh": "<p>Bhavesh lub Bhavish lub Bhawesh (भावेश, ભાવેશ) to indyjskie imię męskie. Pochodzą z sanskrytu bhāva, co oznacza \"istnienie\", i eesh, co oznacza Ishvara, \"Pan, Władca\".</p>", "Barbara": "<b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Bułat": "<b>Bułat</b> – imię pochodzenia gruzińskiego.", "Barzani": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Barzan</b>.</p><p>Barzan - klasa szybkich uderzających łodzi zaprojektowana w Wielkiej Brytanii dla statków wojennych Kataru; znana również jako Super Vita.</p>", "Bahaddin": "<p>Baha al-Din lub Bahaa ad-Din (arabski: بهاء الدين, romanized: Bahāʾ al-Dīn, lit. 'sławność wiary'), lub różne warianty, takie jak Bahauddin, Baha eddine lub (w tureckim) Bahattin, mogą odnosić się do:</p>", "Bjoern": "<p>Bjorn, Bjorne (ang. Bjorn), Björn (szwedzki, islandzki, holenderski i niemiecki), Bjørn (danowski, farerski i norweski), Beorn (starożytny angielski) lub, rzadko, Bjôrn, Biorn lub latynistyczny Biornus, Brum (portugalski), jest skandynawskie męskie imię lub rzadziej nazwisko. Nazwa oznacza \"źwiedzie\" (zwierzę).</p>", "Ben Chokri": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ben</b>.</p><p>Ben (rucko ⁇ Ben ⁇) - drugi solowy album studiowy amerykańskiego piosenkarza Michaela Jacksona.</p>", "Blagoj": "<p>Blagoj (makedońska: Благој) to makedońskie męskie imię. Może odnosić się do: Blagoj Jankov Mučeto, makedonii partizan, który został ogłoszony ludowym bohaterem Jugosławii Blagoj Nacoski (ur. 1979), makedonii tenorowy piosenkarz operowy Blagoj Stračkovski (1920-1943), makedonian komunista</p>", "Berengar": "<b>Berengar</b>, Berengariusz – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, którego patronami jest dwóch św. Berengarów – z <a href=\"https://pl.wikipedia.org/wiki/VII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VII</a> i <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a> – wspominanych jednego dnia. Imię to było – również w formie żeńskiej – często spotykane w szlachetnych rodach zachodniej Europy we wczesnych wiekach.", "Bawo": "<b>Bawon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, pochodzi od francuskiego <i>bave</i> - ślina lub <i>bavard</i> - gadatliwy, gaduła. Być może powstało jako stopniowe zniekształcanie imiona: Baudo, Baldo, <a href=\"https://pl.wikipedia.org/wiki/Baldwin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Baldwin</a>.", "Benijamin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Beniamin</b>.</p><b>Beniamin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia biblijnego, oznaczające dosłownie „syn południa” lub „syn prawicy” (w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języku hebrajskim</a> północ jest utożsamiana z lewą, a południe z prawą stroną). Beniamin <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/31_marca\" target=\"_blank\" rel=\"noopener noreferrer\">31 marca</a> i <a href=\"https://pl.wikipedia.org/wiki/19_grudnia\" target=\"_blank\" rel=\"noopener noreferrer\">19 grudnia</a>.", "Bao An": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Bohdan-": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bohdan</b>.</p><b>Bohdan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Bravo": "<b>Bravo</b> – dwutygodnik dla młodzieży, pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Niemcy\" target=\"_blank\" rel=\"noopener noreferrer\">Niemiec</a>, ukazujący się też w wielu innych krajach Europy. W Polsce pojawił się po raz pierwszy w <a href=\"https://pl.wikipedia.org/wiki/1991\" target=\"_blank\" rel=\"noopener noreferrer\">1991</a> roku i wydawany był przez <a href=\"https://pl.wikipedia.org/wiki/Wydawnictwo_Bauer\" target=\"_blank\" rel=\"noopener noreferrer\">Wydawnictwo Bauer</a>. Redaktorem naczelnym polskiej wersji czasopisma był Michał Wiśnicki. Ostatni numer polskiego wydania <i>Bravo</i> ukazał się w grudniu 2017.", "Bernard Raymond": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bernard</b>.</p><b>Bernard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „silny niedźwiedź”. (staroniemieckie: bero, bern – niedźwiedź i hart – silny). Wśród patronów – św. <a href=\"https://pl.wikipedia.org/wiki/Bernard_z_Clairvaux\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard z Clairvaux</a>. Formą oboczna tego imienia jest imię <i>Berard</i> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>Berardus</i>), zapisywane czasami jako: Berald(us), Gerard(us).", "Bartymeusz": "Syn Tymeusza (Timaiosa), niewidomy, który pod <a href=\"https://pl.wikipedia.org/wiki/Jerycho\" target=\"_blank\" rel=\"noopener noreferrer\">Jerychem</a> wołał <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa</a>: <i>Synu Dawida, ulituj się nade mną!</i>, a którego Jezus uzdrowił. Patrz <a href=\"https://pl.wikipedia.org/wiki/Ewangelia_Marka\" target=\"_blank\" rel=\"noopener noreferrer\">Mk</a> 10,46 - 52. Ponieważ oba określenia „Bartymeusz” i „syn Tymeusza” znaczą to samo, jego prawdziwe imię nie jest znane. Imię Timaios oznacza po grecku kogoś szanowanego (<i>τιμή</i> 'cześć, szacunek').", "Berno": "<p>Berno to męskie imię i nazwisko. Może odnosić się do: Bjørn (fl.</p>", "Bohdan-Marian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bohdan</b>.</p><b>Bohdan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Boel": "<p>Böel to gmina w niemieckim Schleswig-Holstein. Böel lub Boel mogą również odnosić się do:</p>", "Bina": "<b>Bina</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <b>בינה</b>) – określenie oznaczające zrozumienie, inteligencję.", "Bertolt": "<p>Bertolt to niemiecka męska nazwa, wariant Berthold, co oznacza \"świetny przywódca\". Wśród znanych osób z nazwiskiem: Morten Bertolt (ur. 1984), duński piłkarz Bertolt Brecht (1898-1956), niemiecki teatralny praktyk, dramatyk i poeta Bertolt Flick (ur. 1964), niemiecka biznesmen</p>", "Beata": "<b>Beata</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Beat_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Beat</a>, pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>beatus</em> oznaczającego <i>błogosławiona, przynosząca szczęście, szczęśliwa</i>.", "Bożena": "<b>Bożena</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, utworzone poprzez dodanie do rdzenia <i>boż-</i> (od „Bóg”) przyrostka zdrabniającego <i>-ana</i> lub <i>-ena</i>. Imię to zanotowano w dawnych dokumentach w formach <i><b>Bożana</b></i> i <i><b>Bożechna</b></i>, natomiast forma <b>Bożena</b> była znana w języku czeskim, a w Polsce zaczęła się pojawiać regularnie dopiero w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>.", "Bogumiła": "<b>Bogumiła</b>, <b>Bogmiła</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie złożone z członów <i>Bog-</i> („Bóg”, ale pierwotnie „los, dola, szczęście”) i <i>-miła</i> („miła”). Znaczenie imienia „miła Bogu”, lecz pierwotnie mogło ono oznaczać „ta, której los sprzyja”. Odpowiedniki męskie to <a href=\"https://pl.wikipedia.org/wiki/Bogumi%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Bogumił</a>, <a href=\"https://pl.wikipedia.org/wiki/Bogumi%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Bogomił</a>, <a href=\"https://pl.wikipedia.org/wiki/Bogumi%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Bogmił</a>, <a href=\"https://pl.wikipedia.org/wiki/Bogumi%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Bogomieł</a> i <a href=\"https://pl.wikipedia.org/wiki/Bogumi%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Bogmieł</a>. W źródłach poświadczone od XIII wieku. Występuje w „Sielankach” <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_Bart%C5%82omiej_Zimorowic\" target=\"_blank\" rel=\"noopener noreferrer\">J. B. Zimorowicza</a> i w wierszach Andrzeja Morsztyna.", "Bogusława": "<b>Bogusława</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Bogus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Bogusław</a> znany od <a href=\"https://pl.wikipedia.org/wiki/1265\" target=\"_blank\" rel=\"noopener noreferrer\">1265</a> roku. Używane były m.in. zdrobnienia <i>Bogusza</i>, <i>Boguszka</i> i <i>Boguchna</i>. W polskim imiennictwie imię to żywe jest do dziś, ze zdrobnieniami: <i>Bogusia</i> czy <i>Boguśka</i>.", "Bronisława": "<b>Bronisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Broni-</i> („bronić, strzec”) i <i>-sława</i> („sława”). Być może znaczyło „ta, która broni sławy”. W źródłach polskich poświadczone od XIII wieku.", "Bernadeta": "<b>Bernadeta</b>, <b>Bernadetta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, polski odpowiednik francuskiego imienia <i>Bernadette</i>, które jest zdrobnieniem imienia <i>Bernadet</i> utworzonego od imienia <a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard</a>.", "Blanka": "<b>Blanka</b> – imię żeńskie wywodzące się od hiszpańskiej wersji francuskiego imienia <i>Blanche</i> lub z <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> <i>blankus, blanchus</i> „biała”. W niektórych językach występuje również w formie <i><b>Bianka</b></i>.", "Brygida": "<b>Brygida</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>. Pochodzi od imienia bogini celtyckiej <a href=\"https://pl.wikipedia.org/wiki/Brigid\" target=\"_blank\" rel=\"noopener noreferrer\">Brigid</a> lub od słów <i>brigh</i> „siła”, „męstwo”, „cnota”, <i>briganti</i> „wysoki”. Jego pierwotne znaczenie można objaśnić jako „wysoka”, „dostojna”, „potężna”. Imię to pojawiło się w Polsce już w średniowieczu, zapisywano je jako Brygida, Bryjida, Bryda, Bryta, Brytnia. Najstarszy zapis pochodzi z 1265 roku. W 2001 roku miało tak na imię 17456 Polek (255. miejsce wśród wszystkich imion nadanych w Polsce). Były one najczęściej urodzone w latach 50. i 60. XX wieku.", "Bożenna": "<b>Bożena</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, utworzone poprzez dodanie do rdzenia <i>boż-</i> (od „Bóg”) przyrostka zdrabniającego <i>-ana</i> lub <i>-ena</i>. Imię to zanotowano w dawnych dokumentach w formach <i><b>Bożana</b></i> i <i><b>Bożechna</b></i>, natomiast forma <b>Bożena</b> była znana w języku czeskim, a w Polsce zaczęła się pojawiać regularnie dopiero w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>.", "Bernadetta": "<b>Bernadeta</b>, <b>Bernadetta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, polski odpowiednik francuskiego imienia <i>Bernadette</i>, które jest zdrobnieniem imienia <i>Bernadet</i> utworzonego od imienia <a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard</a>.", "Bianka": "<b>Blanka</b> – imię żeńskie wywodzące się od hiszpańskiej wersji francuskiego imienia <i>Blanche</i> lub z <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> <i>blankus, blanchus</i> „biała”. W niektórych językach występuje również w formie <i><b>Bianka</b></i>.", "Bernarda": "<b>Bernarda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard</a>", "Bogna": "<b>Bogna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie stanowiące formę pochodną (zdrobniałą) od imion rozpoczynających się na <i>Bog-</i>, początkowo zarówno męską, jak i żeńską. Istnieją również hipotezy, że imię to mogło być wymyślone przez kronikarza <a href=\"https://pl.wikipedia.org/wiki/Jan_D%C5%82ugosz\" target=\"_blank\" rel=\"noopener noreferrer\">Jana Długosza</a>, w którego pismach pojawia się po raz pierwszy, lub służyć jako zdrobnienie od imienia <a href=\"https://pl.wikipedia.org/wiki/Benigna\" target=\"_blank\" rel=\"noopener noreferrer\">Benigna</a>. W źródłach polskich poświadczone w XV wieku.", "Bolesława": "<b>Bolesława</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Boles%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bolesław</a>. Forma ta jest notowana w Polsce od <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a>.", "Balbina": "<b>Balbina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Balbin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Balbin</a> o pochodzeniu łacińskim.", "Bernardyna": "<b>Bernardyna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Bernardyn_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernardyn</a>. Patronką tego imienia jest św. Bernardyna z <a href=\"https://pl.wikipedia.org/wiki/Foligno\" target=\"_blank\" rel=\"noopener noreferrer\">Foligno</a>.", "Berenika": "W Polsce między 1901 a 1994 rokiem imię to nadano&#160;<b>414</b>&#160;razy: w latach 20. odnotowano&#160;je <b>1</b>&#160;raz, w latach 30., 40. i 50. nie odnotowano&#160;ani jednej&#160;Bereniki. W latach 60. XX wieku było ich <b>34</b> a 104 w latach 70. Najwięcej, bo aż <b>221</b>&#160; nadań tego imienia odnotowano w latach 80. Pomiędzy 1991 a kwietniem 1994 roku zarejestrowano&#160;<b>54</b>&#160;Bereniki.", "Benedykta": "<b>Benedykta</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Benedykt\" target=\"_blank\" rel=\"noopener noreferrer\">Benedykt</a>. Może też występować w formie <b>Benita</b>.", "Bogdana": "<b>Bogdana</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członu <i>Bog-</i> („Bóg”, „Boga”, ale pierwotnie „los, dola, szczęście”) i <i>-dana</i> („dana”). Imię to mogło oznaczać „dana przez los”, później „dana przez Boga”. W źródłach polskich poświadczone od XIII wieku.", "Bianca": "<p>Giuseppe Bianca (włoski: Giuseppe Bianca; 1801 - 1883) - włoski botanik.</p>", "Berta": "<b>Berta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, wywodzące się od przymiotnika <i>beraht</i> – „lśniący, błyszczący”; pierwotnie <a href=\"https://pl.wikipedia.org/wiki/Zdrobnienie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnienie</a> od imion z takim pierwszym lub drugim członem, np. Bertylda, Amalberta, <a href=\"https://pl.wikipedia.org/wiki/Bertrada\" target=\"_blank\" rel=\"noopener noreferrer\">Bertrada</a>, <a href=\"https://pl.wikipedia.org/wiki/Adalberta\" target=\"_blank\" rel=\"noopener noreferrer\">Adalberta</a>. W <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> zapisywane co najmniej od <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>, w formach Berta (poświadczona w <a href=\"https://pl.wikipedia.org/wiki/1252\" target=\"_blank\" rel=\"noopener noreferrer\">1252</a> roku), <i>Berchta</i>, Breta i ze zdrobnieniem Bretka.", "Blandyna": "<b>Blandyna</b> – żeńska forma imienia <a href=\"https://pl.wikipedia.org/wiki/Blandyn\" target=\"_blank\" rel=\"noopener noreferrer\">Blandyn</a>, utworzona od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> przymiotnika <i>blandinus</i> (ż. <i>blandina</i>), w znaczeniu „powabny, wdzięczny, czarujący, ew. uprzejmy, przyjacielski”.", "Bernardeta": "<b>Bernadeta</b>, <b>Bernadetta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, polski odpowiednik francuskiego imienia <i>Bernadette</i>, które jest zdrobnieniem imienia <i>Bernadet</i> utworzonego od imienia <a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard</a>.", "Benita": "<b>Benedykta</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Benedykt\" target=\"_blank\" rel=\"noopener noreferrer\">Benedykt</a>. Może też występować w formie <b>Benita</b>.", "Bozhena": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bożena</b>.</p><b>Bożena</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, utworzone poprzez dodanie do rdzenia <i>boż-</i> (od „Bóg”) przyrostka zdrabniającego <i>-ana</i> lub <i>-ena</i>. Imię to zanotowano w dawnych dokumentach w formach <i><b>Bożana</b></i> i <i><b>Bożechna</b></i>, natomiast forma <b>Bożena</b> była znana w języku czeskim, a w Polsce zaczęła się pojawiać regularnie dopiero w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>.", "Benigna": "<b>Benigna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Benigny\" target=\"_blank\" rel=\"noopener noreferrer\">Benignus</a>, <a href=\"https://pl.wikipedia.org/wiki/Benigny\" target=\"_blank\" rel=\"noopener noreferrer\">Benigny</a>. Pochodzi od przymiotnika <i>benigna</i>, oznaczającego „dobroduszna, uprzejma, przyjazna, życzliwa”, który następnie stał się <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomkiem</a>, a później imieniem. W Polsce po raz pierwszy zanotowane w XIV wieku, jednak w odniesieniu do osoby żyjącej w wieku XI. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Benigna_z_Wroc%C5%82awia\" target=\"_blank\" rel=\"noopener noreferrer\">bł. Benigna z Wrocławia</a> (lub <a href=\"https://pl.wikipedia.org/wiki/Trzebnica\" target=\"_blank\" rel=\"noopener noreferrer\">Trzebnicy</a>).", "Bibianna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bibiana</b>.</p><b>Bibiana</b>, <b>Bibianna</b>, <b>Wiwiana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie utworzone od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiej</a> nazwy rodu <i>Vivius</i> i oznaczające „należąca do rodu <i>Vivii</i>”. Z kolei owa łacińska nazwa rodowa wywodzi się od łac. przymiotnika <i>vivus</i>, oznaczającego „żywy, żwawy”. Wymiana <i>W</i> na <i>B</i> odzwierciedla ludową włoską i hiszpańską wymowę tego imienia. W Polsce nadawane co najmniej od 1755 roku.", "Betina": "Pierwsza wzmianka o Betinie pochodzi z 1423 roku. W 1573 roku, w Betinie osiedlili się uchodźcy z miejscowości Vrana, którzy szukali schronienia przed tureckimi wojskami.", "Blanca": "<p>Gabriel Blanca (szp. Gabriel Blanca, czy hiszpański.</p>", "Bogda": "<p>Bogda jest gminą w prowincji Timiș, Rumunii. W 2002 roku liczba ludności wynosiła 470 osób.</p>", "Beatrice": "<p>Beatrice - znana grupa muzyczna, zakazana przez komunistyczny reżim węgier w 1981 roku.</p>", "Brigitte": "<p>Brigitte (ur. 2010) to francuska aktorka, znana z roli Stella w serialu telewizyjnym ABC Modern Family. W 2012 roku wygrał nagrodę \"Najpiękniejszy Pies w Filmie Telewizyjnym\" w ceremonii Golden Collar.</p>", "Beatrycze": "<b>Beatrycze</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Wywodzi się od słowa oznaczającego „przynosząca szczęście”. Użyte w <i><a href=\"https://pl.wikipedia.org/wiki/Boska_komedia\" target=\"_blank\" rel=\"noopener noreferrer\">Boskiej komedii</a></i> <a href=\"https://pl.wikipedia.org/wiki/Dante_Alighieri\" target=\"_blank\" rel=\"noopener noreferrer\">Dantego</a>.", "Brenda": "<b>Brenda</b> – żeńskie imię, które jest odpowiednikiem męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Brendan\" target=\"_blank\" rel=\"noopener noreferrer\">Brendan</a>. Imię popularne w kulturze amerykańskiej i angielskiej.", "Biruta": "<b>Biruta</b> (<i>Birutė</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewskiego</a>. Wywodzi się od słowa <i>birti</i> oznaczającego: „rozpraszać”, „wylewać”.", "Bernadyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bernadyn</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bernadin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bernadine</b>.</p><p>Bernadine to żeńskie imię, wariant pisowni Bernardine. Znanymi osobami z nazwiska są: Bernadine Bezuidenhout (ur. 1993), nowozelandzkie krykerka Bernadine Craft, amerykański polityk z Wyomingu Bernadine Custer (1900-1991), amerykańska artystka Bernadina Hayes (1912-1987), amerykańska piosenkarka i aktorka Bernadines Healy (1944-2011), amerykański kardiolog Bernadine Jayasinghe, osobowość telewizyjna, zwycięzca prezydenckich nagród i...</p>", "Bibiana": "<b>Bibiana</b>, <b>Bibianna</b>, <b>Wiwiana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie utworzone od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiej</a> nazwy rodu <i>Vivius</i> i oznaczające „należąca do rodu <i>Vivii</i>”. Z kolei owa łacińska nazwa rodowa wywodzi się od łac. przymiotnika <i>vivus</i>, oznaczającego „żywy, żwawy”. Wymiana <i>W</i> na <i>B</i> odzwierciedla ludową włoską i hiszpańską wymowę tego imienia. W Polsce nadawane co najmniej od 1755 roku.", "Bernardetta": "<b>Bernadeta</b>, <b>Bernadetta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, polski odpowiednik francuskiego imienia <i>Bernadette</i>, które jest zdrobnieniem imienia <i>Bernadet</i> utworzonego od imienia <a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard</a>.", "Bozena": "<p>Bożena (polskie wymowa: [bɔˈ ⁇ ɛna]) to polskie imię żeńskie, pierwotnie pojawiające się jako Bożana i Bożechna. Pochodzi od słowa \"Bóg\" (Bóg).</p>", "Belen": "<p>Belen jest okręg w tureckiej prowincji Hatay. Ogromnie obszarzyła 130 km2 i liczba ludności w 2007 roku wynosiła 26256 osób, a jego gęstość wynosi 202 osoby/km2.</p>", "Bronislava": "<p>Bronislava (cyrylicki: Бронислава) jest słowiańskim imieniem żeńskim, pochodzącym od słowiańskich elementów borna (chronić, bronić) i slava (sława, sławę) i oznacza \"wojownik\", \"obrony chwały\". To kobieca forma Bronisława.</p>", "Betty": "<b>Betty</b> – <a href=\"https://pl.wikipedia.org/wiki/Anglia\" target=\"_blank\" rel=\"noopener noreferrer\">angielskie</a> imię. Jest to zdrobnienie od imienia Elizabeth (<a href=\"https://pl.wikipedia.org/wiki/El%C5%BCbieta\" target=\"_blank\" rel=\"noopener noreferrer\">Elżbieta</a>).", "Belén": "<p>Belén jest samodzielnym terenem w prowincji Rivas w Nikaragui. Obecnie Belén ma powierzchnię 246 kilometrów kwadratowych.</p>", "Brunhilda": "<p>Brunhilda (lat. Brunhilda) - gatunek ptaków z rodziny węzłowych tkanczyków (Estrildidae). Rozmieszczone w Afryce.</p>", "Belinda": "Belinda – imię żeńskie o niejasnym pochodzeniu, być może angielskim lub niemieckim.", "Bożysława": "<b>Borzysława</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Borzys%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Borzysław</a>, nienotowany w czasach staropolskich.", "Beth": "<p>Beth - piosenka amerykańskiego zespołu hard-rock Kiss, z ich albu Destroyer, nagranej w 1976 roku. Jest to najwyższa pozycja w całej historii grupy (#7), jeden z dwóch złotych singli (drugiego - ⁇ I Was Made For Lovin' You ⁇ 1979), a także jeden z dwóch piosenek Kiss, który trafił w top-10 w Billboardie (poza Forever, która zajmowała tam miejsce #8).</p>", "Bogdanna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bogdana</b>.</p><b>Bogdana</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członu <i>Bog-</i> („Bóg”, „Boga”, ale pierwotnie „los, dola, szczęście”) i <i>-dana</i> („dana”). Imię to mogło oznaczać „dana przez los”, później „dana przez Boga”. W źródłach polskich poświadczone od XIII wieku.", "Beatrix": "<p>Beatrisza Bawarska (Beatrix; szwedzka Beatrix, 1344 - 25 grudnia 1359, Szwecja) - królowa-konsort Szwecji, żona Erika XII, która rządziła razem ze swoim ojcem Magnusem II.</p>", "Belle": "<p>Belle (francuski belle - piękna) może odnosić się do: ⁇ Belle ⁇ - piosenka z muzyka ⁇ Notr-Dam de Paris ⁇ (1998) kompozytora Riccardo Kochchanté.</p>", "Bona": "<b>Bona</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie oznaczające \"dobra\". Łacińskie słowo, od którego imię to pochodzi (<i>bonus</i> — \"dobry\"; <i>bona</i> — \"dobra\") nie ma pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_indoeuropejskie\" target=\"_blank\" rel=\"noopener noreferrer\">indoeuropejskiego</a>.", "Bronislawa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bronisław</b>.</p><b>Bronisław</b>, <b>Bronsław</b>, <b>Barnisław</b>, (zniem.) <b>Brunisław</b>, <b>Brosław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>.", "Brittany": "<p>Bretagne może odnosić się do: Bretagne, francuskiego regionu administracyjnego Bretagne, wojennej francuskiej wojny II SS Bretagne (1952) statku przydomnie nazwanego Brittany w 1962 roku; spalony w 1963 roku Bretagne jest również nazwą lub częścią nazwy wielu francuskich komun: Bretagne , Indre , Bretagne , Territoire de Belfort , w departamencie Territoire De Belfort Bain-de-Bretagne , w prowincji Ille-et-Vilaine Bretagne-d'Armagnac,...</p>", "Boguchwała": "<b>Boguchwała</b>, <b>Bogufała</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członu <i>Bogu-</i> (\"Bóg\", ale pierwotnie \"los, dola, szczęście\") i <i>-chwała</i> (\"chwalić, sławić, dziękować\"). Prawdopodobnie oznaczało \"tę, która sławi szczęście\", późn. \"tę, która sławi Boga\". W źródłach polskich poświadczone od XIII wieku.", "Bonifacja": "<b>Bonifacja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słów <i>bonum fatum</i> oznaczających „dobry los”. Patronką tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Bonifacja_Rodr%C3%ADguez_Castro\" target=\"_blank\" rel=\"noopener noreferrer\">Bonifacja Rodríguez Castro</a>.", "Borysława": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Borysław</b>.</p><b>Borzysław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Wywodzi się od słów oznaczających „ten, który zdobywa sławę w boju”. Rosyjskim odpowiednikiem tego imienia jest <i>Borisław (Борислав)</i>.", "Brianna": "<p>Brianna, Breanna, Briana i Bryanna to imiona żeńskie. Brianna jest kobiecową angielską formą męskiego imienia irlandzkiego Brian, a \"Briana\" jest oryginalnym pisownią.</p>", "Beáta": "<p>Beata lub Beate to imiona lub nazwisko portugalskie kobiet, które występuje w kilku kulturach i językach, w tym włoskim, niemieckim, polskim i szwedzkim, a które pochodzi z łacińskiego beatus, co oznacza \"błogosławiony\". Warianty obejmują Bea, Beade i Beáta.</p>", "Bermet": "<b>Bermet</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbski\" target=\"_blank\" rel=\"noopener noreferrer\">serb.</a>&#160;<a href=\"https://pl.wikipedia.org/wiki/Cyrylica_serbska\" target=\"_blank\" rel=\"noopener noreferrer\">cyr.</a> Бермет) – <a href=\"https://pl.wikipedia.org/wiki/Wino_deserowe\" target=\"_blank\" rel=\"noopener noreferrer\">wino deserowe</a> pochodzące z regionu <a href=\"https://pl.wikipedia.org/wiki/Fru%C5%A1ka_gora\" target=\"_blank\" rel=\"noopener noreferrer\">Fruška gora</a> w <a href=\"https://pl.wikipedia.org/wiki/Wojwodina\" target=\"_blank\" rel=\"noopener noreferrer\">Wojwodinie</a>. Początkowo przeznaczony był do zastosowań medycznych (trawienie), następnie produkowany do powszechnej konsumpcji. Bermet zawiera od 16 do 18 procent alkoholu, zazwyczaj podawany jest jako wino deserowe, ale może również być podany jako <a href=\"https://pl.wikipedia.org/wiki/Aperitif\" target=\"_blank\" rel=\"noopener noreferrer\">aperitif</a>. Zaleca się podawanie wina w temperaturze 18-20 °C. Nazwa wina pochodzi od zniekształconego słowa <a href=\"https://pl.wikipedia.org/wiki/Wermut\" target=\"_blank\" rel=\"noopener noreferrer\">wermut</a>, wytwarzany jest jednak inaczej niż wermut, poprzez macerację minimum 20 ziół i przypraw. Wytwarzany jest zarówno z białych jak i czerwonych winogron. Dokładny przepis pozostaje tajny i obecnie jest w posiadaniu kilku rodzin z miasta <a href=\"https://pl.wikipedia.org/wiki/Sremski_Karlovci\" target=\"_blank\" rel=\"noopener noreferrer\">Sremski Karlovci</a>. Według niektórych relacji, Bermet był serwowany na <a href=\"https://pl.wikipedia.org/wiki/Titanic\" target=\"_blank\" rel=\"noopener noreferrer\">Titanicu</a>, jak również w Królewskim Pałacu w Wiedniu. Bermet jest zarejestrowanym chronionym oznaczeniem geograficznym w Urzędzie Własności Intelektualnej Republiki Serbii.", "Balladyna": "<b>Balladyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia literackiego, imię tytułowej bohaterki <a href=\"https://pl.wikipedia.org/wiki/Dramat\" target=\"_blank\" rel=\"noopener noreferrer\">dramatu</a> <a href=\"https://pl.wikipedia.org/wiki/Romantyzm\" target=\"_blank\" rel=\"noopener noreferrer\">romantycznego</a> <a href=\"https://pl.wikipedia.org/wiki/Juliusz_S%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">Juliusza Słowackiego</a> <i><a href=\"https://pl.wikipedia.org/wiki/Balladyna\" target=\"_blank\" rel=\"noopener noreferrer\">Balladyna</a></i>.", "Benona": "<b>Benona</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Benon_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Benon</a>, powstałego jako zdrobnienie od imienia <a href=\"https://pl.wikipedia.org/wiki/Bernard_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bernard</a>.", "Blanche": "<p>Blanche - skróczenie botaniczne oznaczające, że autorem taksyny jest Emmanuel-Louis Blanche Blanca Francuska</p>", "Bernadett": "<p>Bernadette to francuska nazwa, żeńska forma nazwiska Bernard, co oznacza \"odważny niedźwiedź\". Bernadett to węgierski pisowni.</p>", "Beniamina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Beniamin</b>.</p><b>Beniamin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia biblijnego, oznaczające dosłownie „syn południa” lub „syn prawicy” (w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języku hebrajskim</a> północ jest utożsamiana z lewą, a południe z prawą stroną). Beniamin <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/31_marca\" target=\"_blank\" rel=\"noopener noreferrer\">31 marca</a> i <a href=\"https://pl.wikipedia.org/wiki/19_grudnia\" target=\"_blank\" rel=\"noopener noreferrer\">19 grudnia</a>.", "Bertha": "<p>Bertha (lat. Bertha; około 863 - 8 marca 925, Lucka) - najpierw grafia Arla (885 - między 887 i 890) w związku z Teobaldem, następnie markgrafia Toskania (między 890 i 895 - 915) w związku z Adalbertem II Bogaty; regent Marka Toskńskiego (915 - 916) przy swoim synie Gvidzie.</p>", "Blandine": "<p>Święta Blandinę (francuski: Sainte Blandienne). Blandine, lat.</p>", "Bratumiła": "<b>Bratumiła</b>, <b>Bratomiła</b>, <b>Bratmiła</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Bratu-</i> (\"bratu\", \"członkowi wspólnoty rodowej\", \"człowiekowi bliskiemu\") i <i>-miła</i> (\"miła\"). Znaczenie imienia: \"miła swoim bliskim\". W źródłach polskich poświadczone w XIII wieku (1265 rok).", "Bonita": "<b>Bonita</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a>, oznaczające \"człowieka o dobrym sercu\", pierwotnie pochodzące od zdrobnienia od przymiotnika <i>bonus</i> — \"dobry\". Patronem tego imienia jest św. Bonet (Bonitus).", "Bao Anh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Björk": "<p>Björk Guðmundsdóttir (BYURK, islandzki: [pjœr ⁇ k ˈkvʏðmʏntsˌtouhtɪr ⁇ ]; urodzona 21 listopada 1965 roku) lub znana jako Björk, jest islandzką piosenkarką, muzyką, kompozytorką, producentem muzycznym i aktorką. Znana z wyjątkowego głosu, osma i wyjątkowej publicznej osobliwości, w ciągu pięciu dekad kariery, która łączyła elektronikę, pop, muzykę, muzykę i muzykę, rozwinęła się w różne style.</p>", "Bożena Kazimiera": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bożena</b>.</p><b>Bożena</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, utworzone poprzez dodanie do rdzenia <i>boż-</i> (od „Bóg”) przyrostka zdrabniającego <i>-ana</i> lub <i>-ena</i>. Imię to zanotowano w dawnych dokumentach w formach <i><b>Bożana</b></i> i <i><b>Bożechna</b></i>, natomiast forma <b>Bożena</b> była znana w języku czeskim, a w Polsce zaczęła się pojawiać regularnie dopiero w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>.", "Beatris": "<b>Beatrycze</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Wywodzi się od słowa oznaczającego „przynosząca szczęście”. Użyte w <i><a href=\"https://pl.wikipedia.org/wiki/Boska_komedia\" target=\"_blank\" rel=\"noopener noreferrer\">Boskiej komedii</a></i> <a href=\"https://pl.wikipedia.org/wiki/Dante_Alighieri\" target=\"_blank\" rel=\"noopener noreferrer\">Dantego</a>.", "Boguslawa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bogusław</b>.</p><b>Bogusław</b>, <b>Bogosław</b>, <b>Bohusław</b>, <b>Bogsław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Imię <i>Bogusław</i> jest przykładem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego</a>, złożonego, osobowego imienia dwuczłonowego, które jest <a href=\"https://pl.wikipedia.org/wiki/Relikt\" target=\"_blank\" rel=\"noopener noreferrer\">reliktem</a> <a href=\"https://pl.wikipedia.org/wiki/Poga%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">pogańskich</a> imion używanych we wczesnym średniowieczu przez <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">Słowian</a>. Składa się z członu <i>Bogu-</i> („Bóg”, „Boga”, ale pierwotnie „los, dola, szczęście”) oraz <i>-sław</i> („sława”). Być może znaczyło pierwotnie „ten, który sławi los”, a później „sławiący Boga”. <a href=\"https://pl.wikipedia.org/wiki/Witold_Taszycki\" target=\"_blank\" rel=\"noopener noreferrer\">Witold Taszycki</a> zaliczył je do grupy najstarszych polskich imion osobowych&#8201;.", "Bożydara": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bożydar</b>.</p><b>Bożydar</b>, <b>Bożdar</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie złożone z członów <i>Boż(y)-</i> („Boga”, ale pierwotnie „losu, doli, szczęścia”) i <i>-dar</i> („upominek, dar, ofiara”). Być może oznaczało „tego, kto jest darem losu”. Imię to (wraz z <a href=\"https://pl.wikipedia.org/wiki/Bogodar\" target=\"_blank\" rel=\"noopener noreferrer\">Bogodarem</a>) uważa się za równoważnik znaczeniowy imienia <i>Adeodat</i> (łacińskiego <i>Adeodatus</i>), czy greckiego <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a> lub <a href=\"https://pl.wikipedia.org/wiki/Bogdan\" target=\"_blank\" rel=\"noopener noreferrer\">Bogdan</a>, a zatem Bożydar obchodzi imieniny w dniach wspomnienia św. Adeodatów, których jest kilku.", "Barbara Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Barbara</b>.</p><b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Borzysława": "<b>Borzysława</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Borzys%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Borzysław</a>, nienotowany w czasach staropolskich.", "Branislava": "<p>Branislava (cyrylicki: Бранислава) jest słowiańskim imieniem żeńskim, pochodzącym z słowiańskich elementów borna (ochronić, bronić) i slava (sława, sławę) i oznacza \"wojownik\", \"obrony chwały\". To kobieca forma Branislawa.</p>", "Bazylia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bazyli</b>.</p><b>Bazyli</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">późnogreckiego</a>. Pochodzi ono od przymiotnika „królewski, cesarski” (<i>basíleios</i>, od <a href=\"https://pl.wikipedia.org/wiki/II_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">II wieku</a> wymawiane <i>basílios</i>), od rzeczownika <i>basileus</i> – „król, wódz, cesarz”. Jego formą oboczną jest Bazyliusz, a żeńskim odpowiednikiem – <a href=\"https://pl.wikipedia.org/wiki/Bazyla\" target=\"_blank\" rel=\"noopener noreferrer\">Bazyla</a>.", "Benedyktyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Benedykt</b>.</p><b>Benedykt</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>benedictus</i>, oznaczającego „tego, o którym się dobrze mówi”; „tego, któremu się dobrze życzy”. Znanym imiennikiem był <a href=\"https://pl.wikipedia.org/wiki/Benedykt_z_Nursji\" target=\"_blank\" rel=\"noopener noreferrer\">Benedykt z Nursji</a>, założyciel <a href=\"https://pl.wikipedia.org/wiki/Benedyktyni\" target=\"_blank\" rel=\"noopener noreferrer\">opactwa benedyktyńskiego</a> na <a href=\"https://pl.wikipedia.org/wiki/Monte_Cassino\" target=\"_blank\" rel=\"noopener noreferrer\">Monte Cassino</a>, i <a href=\"https://pl.wikipedia.org/wiki/Baruch_Spinoza\" target=\"_blank\" rel=\"noopener noreferrer\">Spinoza</a>.", "Betul": "<p>Betul to miasto i dzielnica gmin w hrabstwie Betul w stanie Madhya Pradesh, India.</p>", "Beatricze": "<b>Beatrycze</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Wywodzi się od słowa oznaczającego „przynosząca szczęście”. Użyte w <i><a href=\"https://pl.wikipedia.org/wiki/Boska_komedia\" target=\"_blank\" rel=\"noopener noreferrer\">Boskiej komedii</a></i> <a href=\"https://pl.wikipedia.org/wiki/Dante_Alighieri\" target=\"_blank\" rel=\"noopener noreferrer\">Dantego</a>.", "Bénédicte": "<p>Bénédicte może odnosić się do: Bénédictes Augst (ur. 1968), francuskiej gimnastki rytmicznej Bénédict Couvreur, francuskiego producenta filmowego Bénédicta Cronier (ur. 1961), francuskiego piłkarza bridżu Bénédichte Dorfman-Luzuy (ur. 1971), francuskiego remnika Bénédicke Duprez (ur. 1951), francuskiego pływacza Bénédique Kurzen (ur. 1980), francuskiego fotografa i fotoreporterka Bénédicie Liénard (ur. 1965), belgijskiego filmowca Bénédicten Paviot, francuskiego reporterka telewizyjnych wiadomości Bénédicle...</p>", "Britt": "<p>Britt jest przedstawicielem celtyckiego narodu Brittów.</p>", "Berra": "<p>Berra jest miastem w prowincji Ferrara, Emilia-Romagna w Italii, znajdującym się około 70 km północno-wschodnio od Bologny i około 30 km północnie od Ferrary. Na dzień 31 grudnia 2004 roku mieście miało ludności 5,696 osób i powierzchnię 68,6 km2.</p>", "Betsy": "<p>Betsy (prawdziwe imię - Svetlana Michajłowna Chertyczowa, urodzona 27 stycznia 2013, Sankt-Peterburg, Rosja), znana również jako Betsy Girl, - rosyjska piosenkarka i blogerka.</p>", "Boglárka": "<p>Boglárka to popularne węgierskie imię dla kobiet, które oznacza \"biżut\" lub \"buttercup\".</p>", "Binita": "<p>Binita (nepali: विनिता) to imię nadawane kobiecom w Indiach i Nepalu. Znani ludzie z nazwiskiem to: Binita Toppo (ur. 1980), indyjska hokejistka Binita Soren, indyjska alpinista Binita Desai, indyjski animator i wychowawca Binita Prabhu, fikcyjna postać z brytyjskiej opera mydłowej Doktorzy</p>", "Bilha": "<p>Bilha jest miastem i nagarem panchayatów w hrabstwie Bilaspur w stanie Chhattisgarh, India.</p>", "Baya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bay</b>.</p><p>Podczas lotu obiekt przechodzi przez atmosferę (zwłaszcza powietrze) lub dalej (przelety do kosmosu), tworząc siłę podnoszącą aerodynamiczną, siłę napędową, używając innego, lżejszego gazu niż powietrze, lub taktyki wystrzelania. Bez bezpośredniego wsparcia z żadnej powierzchni.</p>", "Belita": "<p>Belita (ang. Belita), imię przy urodzeniu Marii Gladys Olive Line Jepson-Turner (ang.</p>", "Bistra": "<p>Bistra może być: Bistra, Silistra, wioska w prowincji Silistra, Bułgaria Bistra, Targovishte, wiosko w Targovishta, Bułgara Bistra, Chorwacja, wioski w hrabstwie Zagreb, Chorwacji Góra Bistra w północnej Macedonii Bistra (górka góry) w Kosowie Bistra, Alba, gmina w Alba, Rumunii Bistra, Maramureș, gmina Maramureş, RumuniiBistra, Popeşti, wiosка w Popești, Bihor, Rumunii</p>", "Budzisława": "<b>Budzisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Budzi-</i> (\"budzić\") i <i>-sława</i> (\"sława\"). Mogło oznaczać \"ta, która zyskuje sławę\". Staropolskie zdrobnienie: Buchna. W źródłach polskich poświadczone w XIV wieku (1362 rok).", "Beatrysa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Beatrisa</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Beatris</b>.</p><b>Beatrycze</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Wywodzi się od słowa oznaczającego „przynosząca szczęście”. Użyte w <i><a href=\"https://pl.wikipedia.org/wiki/Boska_komedia\" target=\"_blank\" rel=\"noopener noreferrer\">Boskiej komedii</a></i> <a href=\"https://pl.wikipedia.org/wiki/Dante_Alighieri\" target=\"_blank\" rel=\"noopener noreferrer\">Dantego</a>.", "Benedicte": "<p>Bénédicte może odnosić się do: Bénédictes Augst (ur. 1968), francuskiej gimnastki rytmicznej Bénédict Couvreur, francuskiego producenta filmowego Bénédicta Cronier (ur. 1961), francuskiego piłkarza bridżu Bénédichte Dorfman-Luzuy (ur. 1971), francuskiego remnika Bénédicke Duprez (ur. 1951), francuskiego pływacza Bénédique Kurzen (ur. 1980), francuskiego fotografa i fotoreporterka Bénédicie Liénard (ur. 1965), belgijskiego filmowca Bénédicten Paviot, francuskiego reporterka telewizyjnych wiadomości Bénédicle...</p>", "Britney": "<p>Britney to trzeci album studio amerykańskiej piosenkarki Britney Spears. Wydał 31 października 2001 roku na wytwórni Jive Records.</p>", "Becky": "<p>Becky to kobiece imię, często skrócona forma (hypocorism) Rebecki. Może odnosić się do:</p>", "Brunona": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Brunon</b>.</p><b>Bruno, Brunon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa <i>brün</i> oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Nied%C5%BAwied%C5%BA_brunatny\" target=\"_blank\" rel=\"noopener noreferrer\">niedźwiedź</a>” lub „brunatny”. Forma <b>Brunon</b> powstała pod wpływem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim</a>. W Polsce imię Bruno po raz pierwszy zanotowano w <a href=\"https://pl.wikipedia.org/wiki/1236\" target=\"_blank\" rel=\"noopener noreferrer\">1236</a> roku.", "Bích": "<p>Bích może być: Innym słowem Elat. Wojsko w zachodniej karcie.</p>", "Bronisława Kazimiera": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bronisława</b>.</p><b>Bronisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Broni-</i> („bronić, strzec”) i <i>-sława</i> („sława”). Być może znaczyło „ta, która broni sławy”. W źródłach polskich poświadczone od XIII wieku.", "Bảo Anh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Belkis": "<p>Belkis, Belkıs i Belkız (a także inne warianty) to imiona żeńskie w Ameryce Łacińskiej i na Bliskim Wschodzie, pochodzące od Belqis, arabskiej nazwy królowej Szoby; i może odnosić się do: Belkis Ayón (1967-1999), kubański artysta Belkis Cuza Malé (ur. 1942), kubańsko-amerykański pisarz Belkis Leal (ur. 1940), wenezuelski wrównik Belkis Rodríguez (ur. 1965), kubański emerytowany tenisa Belkis Ulacio, wenezuelska polityk Belkis, Regina...</p>", "Borzyna": "<b>Borzymir</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Borzy-</i> (\"walczyć\", \"walka\") oraz <i>-mir</i> (\"pokój\"). Mogło oznaczać \"ten, który walczy o pokój\".", "Bao Chau": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Brielle": "<p>Brielle, znana również jako Den Briel (Brill in English) jest miasteczkiem w zachodniej części Holandii, w prowincji Zuid-Holland, na północnej stronie wyspy Voorne, na brzegu rzeki New Maas. Miasto to ma powierzchnię 31,12 km2 (12,02 mile2), z czego 3,63 km2 (1,40 mile2) to powierzchnia wodna.</p>", "Bao Han": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Bozenna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bożena</b>.</p><b>Bożena</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, utworzone poprzez dodanie do rdzenia <i>boż-</i> (od „Bóg”) przyrostka zdrabniającego <i>-ana</i> lub <i>-ena</i>. Imię to zanotowano w dawnych dokumentach w formach <i><b>Bożana</b></i> i <i><b>Bożechna</b></i>, natomiast forma <b>Bożena</b> była znana w języku czeskim, a w Polsce zaczęła się pojawiać regularnie dopiero w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>.", "Bibijanna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bibianna</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bibiana</b>.</p><b>Bibiana</b>, <b>Bibianna</b>, <b>Wiwiana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie utworzone od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiej</a> nazwy rodu <i>Vivius</i> i oznaczające „należąca do rodu <i>Vivii</i>”. Z kolei owa łacińska nazwa rodowa wywodzi się od łac. przymiotnika <i>vivus</i>, oznaczającego „żywy, żwawy”. Wymiana <i>W</i> na <i>B</i> odzwierciedla ludową włoską i hiszpańską wymowę tego imienia. W Polsce nadawane co najmniej od 1755 roku.", "Bazyla": "<b>Bazyla</b>, <b>Bazylia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia greckiego. Pochodzi ono od przymiotnika utworzonego od rzeczownika <i>basileus</i> – „król, wódz, cesarz”. Oznacza więc „królewska”.", "Bhavana": "<b>Bhavana</b> (<i><a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_palijski\" target=\"_blank\" rel=\"noopener noreferrer\">pali</a>: bhāvanā</i>) oznacza \"rozwój\" (dosłownie \"przywoływanie do istnienia, produkowanie\"). W naukach <a href=\"https://pl.wikipedia.org/wiki/Budda_Siakjamuni\" target=\"_blank\" rel=\"noopener noreferrer\">Buddy</a> termin ten jest często używany w połączeniu z innymi wyrazami w takich frazach, jak:", "Błażeja": "<b>Błażeja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego \"seplenić\". Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/B%C5%82a%C5%BCej\" target=\"_blank\" rel=\"noopener noreferrer\">Błażej</a>.", "Battsetseg": "<p>Battsetseg (w mongolskim cyrylce Батцэцэг) to kobiece mongolskie imię, które oznacza \"silny kwiat\". Znani ludzie z nazwy to: Altantsetsegiin Battsetseg (1994-), mongolski wrestler wolnego stylu Baatarzorigiin Battsetseg, mongolski zwalczyciel Battsetsega Batmunkh (1973-), minister spraw zagranicznych Mongolii Soronzonboldyn Battsetseeg (1990-), mongolska wrestlerka wolnego styla Tsagaan Battsetsegi (1972-), mongolsko-amerykański szachowiec</p>", "Benitha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Benita</b>.</p><b>Benedykta</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Benedykt\" target=\"_blank\" rel=\"noopener noreferrer\">Benedykt</a>. Może też występować w formie <b>Benita</b>.", "Bảo An": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Bao Nhi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Bogumiła Kazimiera": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bogumiła</b>.</p><b>Bogumiła</b>, <b>Bogmiła</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie złożone z członów <i>Bog-</i> („Bóg”, ale pierwotnie „los, dola, szczęście”) i <i>-miła</i> („miła”). Znaczenie imienia „miła Bogu”, lecz pierwotnie mogło ono oznaczać „ta, której los sprzyja”. Odpowiedniki męskie to <a href=\"https://pl.wikipedia.org/wiki/Bogumi%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Bogumił</a>, <a href=\"https://pl.wikipedia.org/wiki/Bogumi%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Bogomił</a>, <a href=\"https://pl.wikipedia.org/wiki/Bogumi%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Bogmił</a>, <a href=\"https://pl.wikipedia.org/wiki/Bogumi%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Bogomieł</a> i <a href=\"https://pl.wikipedia.org/wiki/Bogumi%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Bogmieł</a>. W źródłach poświadczone od XIII wieku. Występuje w „Sielankach” <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_Bart%C5%82omiej_Zimorowic\" target=\"_blank\" rel=\"noopener noreferrer\">J. B. Zimorowicza</a> i w wierszach Andrzeja Morsztyna.", "Beatrisa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Beatris</b>.</p><b>Beatrycze</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Wywodzi się od słowa oznaczającego „przynosząca szczęście”. Użyte w <i><a href=\"https://pl.wikipedia.org/wiki/Boska_komedia\" target=\"_blank\" rel=\"noopener noreferrer\">Boskiej komedii</a></i> <a href=\"https://pl.wikipedia.org/wiki/Dante_Alighieri\" target=\"_blank\" rel=\"noopener noreferrer\">Dantego</a>.", "Benilda": "<b>Benilda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, którego patronką jest św. Benilda, żyjąca w <a href=\"https://pl.wikipedia.org/wiki/Kordowa\" target=\"_blank\" rel=\"noopener noreferrer\">Kordowie</a> (<a href=\"https://pl.wikipedia.org/wiki/Hiszpania\" target=\"_blank\" rel=\"noopener noreferrer\">Hiszpania</a>), w <a href=\"https://pl.wikipedia.org/wiki/IX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IX wieku</a>.", "Birutė": "<b>Biruta</b> (<i>Birutė</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewskiego</a>. Wywodzi się od słowa <i>birti</i> oznaczającego: „rozpraszać”, „wylewać”.", "Brandy": "Nazwa pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Holandia\" target=\"_blank\" rel=\"noopener noreferrer\">holenderskiego</a> słowa <i>brandewijn</i> („destylowane wino”). Staropolska, do dziś poprawna i używana nazwa brandy to <i>wypalanka</i>. Tak określa się <a href=\"https://pl.wikipedia.org/wiki/W%C3%B3dka\" target=\"_blank\" rel=\"noopener noreferrer\">wódki</a> destylowane w tradycyjny sposób, „wypalane” w aparatach destylacyjnych, a już nie wódki <a href=\"https://pl.wikipedia.org/wiki/Rektyfikacja_(destylacja)\" target=\"_blank\" rel=\"noopener noreferrer\">rektyfikowane</a>. Niekiedy nazywana jest również błędnie <i>przepalanką</i>, mimo że termin odnosi się do destylatów produkowanych na bazie <a href=\"https://pl.wikipedia.org/wiki/Karmel\" target=\"_blank\" rel=\"noopener noreferrer\">karmelu</a>.", "Brianne": "<p>Brianne to wariant nazwiska Brianna. Wśród znanych osób z tej nazwy są: Brianne Berkson (ur. 1985), amerykańska aktorka Brianne Davis (ur. 1982), amerykajska aktorka Brianine Desa (ur. 2000), kanadyjsko-guyanską piłkarka Brianne Howey (ur. 1989), amerykańską aktorkę Brianne Jenner (ur. 1991), kanadyjską hokejistkę Brianne Leary (ur. 1957), amerykajską aktorkę Bryanne McLaughlin (ur. 1987), amerykański hokejistka Brianne Moncrief ...</p>", "Benata": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Beñat</b>.</p><p>Beñat jest baskijską męską wariantą nazwy Bernard, która pochodzi z pochodzenia germańskiego. Istnieją warianty w innych językach, w tym hiszpańskim i włoskim Bernardo.</p>", "Bao Tran": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Bilkis": "<b>Makeda</b> – pierwsza znana królowa <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Saba\" target=\"_blank\" rel=\"noopener noreferrer\">Saby</a>. Makeda to imię wywodzące się z tradycji <a href=\"https://pl.wikipedia.org/wiki/Etiopia\" target=\"_blank\" rel=\"noopener noreferrer\">etiopskiej</a>; w <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamskich</a> przekazach nazywana była Bilkis (<b>بلقيس</b> <i>Bilqīs</i>). Inne wersje jej imienia to Nikaule oraz Nicaula.", "Bukola": "<p>Bukola (Bùkọ́lá) to nigeryjska unisex nazwa pochodzenia joruba, co oznacza \"dodawane bogactwo\". Jest to diminutiwna wersja nazw takich jak \"Olúwabùkọ́la\" oznacza \"Bóg dodał bogactwu\" i \"Adébùkọ́ла\" oznacza \"Korona dodała bogactwu\".</p>", "Barbara Krystyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Barbara</b>.</p><b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Beatriks": "<b>Beatrycze</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Wywodzi się od słowa oznaczającego „przynosząca szczęście”. Użyte w <i><a href=\"https://pl.wikipedia.org/wiki/Boska_komedia\" target=\"_blank\" rel=\"noopener noreferrer\">Boskiej komedii</a></i> <a href=\"https://pl.wikipedia.org/wiki/Dante_Alighieri\" target=\"_blank\" rel=\"noopener noreferrer\">Dantego</a>.", "Barbara Elżbieta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Barbara</b>.</p><b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Bellinda": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Belinda</b>.</p>Belinda – imię żeńskie o niejasnym pochodzeniu, być może angielskim lub niemieckim.", "Beta": "<b>Beta</b> (<b>wita</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βῆτα, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_nowogrecki\" target=\"_blank\" rel=\"noopener noreferrer\">nw.gr.</a> <b>βήτα</b>, pisana <b>Ββ</b> lub <b>ϐ</b>) – druga <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">litera</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu greckiego</a>. W <a href=\"https://pl.wikipedia.org/wiki/Grecki_system_liczbowy\" target=\"_blank\" rel=\"noopener noreferrer\">greckim systemie liczbowym</a> oznaczała liczbę <a href=\"https://pl.wikipedia.org/wiki/2_(liczba)\" target=\"_blank\" rel=\"noopener noreferrer\">2</a>. Beta pochodzi od litery <a href=\"https://pl.wikipedia.org/wiki/Alfabet_fenicki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu fenickiego</a> bet <a href=\"https://pl.wikipedia.org/wiki/Plik:Phoenician_beth.svg\" target=\"_blank\" rel=\"noopener noreferrer\"></a>. Od bety pochodzą <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a> <a href=\"https://pl.wikipedia.org/wiki/B\" target=\"_blank\" rel=\"noopener noreferrer\">B</a> i <a href=\"https://pl.wikipedia.org/wiki/Cyrylica\" target=\"_blank\" rel=\"noopener noreferrer\">cyrylickie</a> <a href=\"https://pl.wikipedia.org/wiki/%D0%91\" target=\"_blank\" rel=\"noopener noreferrer\">Б</a> i <a href=\"https://pl.wikipedia.org/wiki/%D0%92\" target=\"_blank\" rel=\"noopener noreferrer\">В</a>.", "Bełła": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bell</b>.</p><p>Bell, Bell (ang. bell - ⁇ колокол ⁇ , ⁇ колокольчик ⁇) - nazwisko i toponim.</p>", "Bhawana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bhavana</b>.</p><b>Bhavana</b> (<i><a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_palijski\" target=\"_blank\" rel=\"noopener noreferrer\">pali</a>: bhāvanā</i>) oznacza \"rozwój\" (dosłownie \"przywoływanie do istnienia, produkowanie\"). W naukach <a href=\"https://pl.wikipedia.org/wiki/Budda_Siakjamuni\" target=\"_blank\" rel=\"noopener noreferrer\">Buddy</a> termin ten jest często używany w połączeniu z innymi wyrazami w takich frazach, jak:", "Bozhena-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bozhena</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bożena</b>.</p><b>Bożena</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, utworzone poprzez dodanie do rdzenia <i>boż-</i> (od „Bóg”) przyrostka zdrabniającego <i>-ana</i> lub <i>-ena</i>. Imię to zanotowano w dawnych dokumentach w formach <i><b>Bożana</b></i> i <i><b>Bożechna</b></i>, natomiast forma <b>Bożena</b> była znana w języku czeskim, a w Polsce zaczęła się pojawiać regularnie dopiero w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>.", "Benazir": "<p>Benazir lub Binazir (perskiego: بی نَظِیر, romanized: bēnazīr, lit. 'nie ma równych') może odnosić się do:</p>", "Bảo Hân": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Bianca-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bianca</b>.</p><p>Giuseppe Bianca (włoski: Giuseppe Bianca; 1801 - 1883) - włoski botanik.</p>", "Bao Vy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Bogusława Kazimiera": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bogusława</b>.</p><b>Bogusława</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Bogus%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Bogusław</a> znany od <a href=\"https://pl.wikipedia.org/wiki/1265\" target=\"_blank\" rel=\"noopener noreferrer\">1265</a> roku. Używane były m.in. zdrobnienia <i>Bogusza</i>, <i>Boguszka</i> i <i>Boguchna</i>. W polskim imiennictwie imię to żywe jest do dziś, ze zdrobnieniami: <i>Bogusia</i> czy <i>Boguśka</i>.", "Barbara Małgorzata": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Barbara</b>.</p><b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Bartłomieja": "<b>Bartłomieja</b> – forma żeńska <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Bart%C5%82omiej\" target=\"_blank\" rel=\"noopener noreferrer\">Bartłomiej</a>. W Polsce w tej formie imię nie jest używane. Zapisywana jako Bartolomea imieniny obchodzi <a href=\"https://pl.wikipedia.org/wiki/26_lipca\" target=\"_blank\" rel=\"noopener noreferrer\">26 lipca</a>.", "Breanna": "<p>Brianna, Breanna, Briana i Bryanna to imiona żeńskie. Brianna jest kobiecową angielską formą męskiego imienia irlandzkiego Brian, a \"Briana\" jest oryginalnym pisownią.</p>", "Bao Tram": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Boguslava": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Boguslav</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bogusław</b>.</p><b>Bogusław</b>, <b>Bogosław</b>, <b>Bohusław</b>, <b>Bogsław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Imię <i>Bogusław</i> jest przykładem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego</a>, złożonego, osobowego imienia dwuczłonowego, które jest <a href=\"https://pl.wikipedia.org/wiki/Relikt\" target=\"_blank\" rel=\"noopener noreferrer\">reliktem</a> <a href=\"https://pl.wikipedia.org/wiki/Poga%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">pogańskich</a> imion używanych we wczesnym średniowieczu przez <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">Słowian</a>. Składa się z członu <i>Bogu-</i> („Bóg”, „Boga”, ale pierwotnie „los, dola, szczęście”) oraz <i>-sław</i> („sława”). Być może znaczyło pierwotnie „ten, który sławi los”, a później „sławiący Boga”. <a href=\"https://pl.wikipedia.org/wiki/Witold_Taszycki\" target=\"_blank\" rel=\"noopener noreferrer\">Witold Taszycki</a> zaliczył je do grupy najstarszych polskich imion osobowych&#8201;.", "Birte": "<p>Birte to żeńskie imię, które może odnosić się do: Birte Bruhns (ur. 1970), niemiecka emeryturka biegaczka średniej odległości Birte Christoffersen (1924-2026), duńsko-szwedzka nurka Birte Glang (ur. 1980), niemiecki aktorka, ambasadorka marki, modelka mody i prawnik Birte Glißmann (ur. 1992), niemieckiej polityk Birte Høeg Brask (1918-1997), duńskiego walki z opórem i lekarza Birte Melsen (ur. 1939), duńskiej ortodontysty Birte Ove-Petersen (ur. 1938),...</p>", "Barbara Teresa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Barbara</b>.</p><b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Boya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Boy</b>.</p><p>Boy (rosyjski ⁇ Maleczk ⁇) - debiutancki album irlandzkiej grupy rockowej U2, wydany 20 października 1980 roku i produkowany przez Steve'a Lilliwhita.</p>", "Bree": "<b>Bree</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia celtycko-irlandzkiego spokrewnione z imionami <a href=\"https://pl.wikipedia.org/wiki/Brygida\" target=\"_blank\" rel=\"noopener noreferrer\">Brygida</a> (<i>Bridget</i>), Brianna i <a href=\"https://pl.wikipedia.org/wiki/Sabrina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Sabrina</a>. Występuje też w wariantach Breehan i Brighe.", "Bisola": "<p>Bísólá (wpisane jako Bísólà) to nigeryjska uniseksowa nazwisko pochodzenia joruba, co oznacza \"narodzony w bogactwie\". Bísólá, kiedyś wyłącznie kobiece, jest obecnie przyjmowana przez mężczyzn, odzwierciedlając zmieniające się normy społeczne i rosnący trend nazwisk unisex.</p>", "Bogudara": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bogudar</b>.</p>Imię to (wraz z <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCydar_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bożydarem</a>) uważa się za równoważnik znaczeniowy imienia <i><b>Adeodat</b></i>, a zatem Bogodar obchodzi imieniny w dniach wspomnienia św. Adeodatów.", "Baye": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bay</b>.</p><p>Podczas lotu obiekt przechodzi przez atmosferę (zwłaszcza powietrze) lub dalej (przelety do kosmosu), tworząc siłę podnoszącą aerodynamiczną, siłę napędową, używając innego, lżejszego gazu niż powietrze, lub taktyki wystrzelania. Bez bezpośredniego wsparcia z żadnej powierzchni.</p>", "Bianca-Elena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bianca</b>.</p><p>Giuseppe Bianca (włoski: Giuseppe Bianca; 1801 - 1883) - włoski botanik.</p>", "Busisiwe": "<p>Busisiwe to kobiece imię pochodzące od słowa Nguni busisa, co oznacza \"błogosławić\". Wśród znanych osób z nazwiskiem są: Busisiwe Mavuso (ur. 1977 lub 1978), południowoafrykańska biznesmena Busisiwe Mkhwebane (ur. 1970), połudnoafrykański adwokat i prokurator Busisiwe Mncube, południoafrykańczy polityk Busisiwe Ndimeni (ur. 1991), południeafrykańskiego piłkarza Busisiwe Nolubabalo Nqwiliso (ur. 1987), południaafrykacka piosenkarka znana jako Bucie Busisiwe...</p>", "Bảo Trâm": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Beata-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Beata</b>.</p><b>Beata</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Beat_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Beat</a>, pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>beatus</em> oznaczającego <i>błogosławiona, przynosząca szczęście, szczęśliwa</i>.", "Brygitte": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Brigitte</b>.</p><p>Brigitte (ur. 2010) to francuska aktorka, znana z roli Stella w serialu telewizyjnym ABC Modern Family. W 2012 roku wygrał nagrodę \"Najpiękniejszy Pies w Filmie Telewizyjnym\" w ceremonii Golden Collar.</p>", "Beatrys": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Beatrysa</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Beatrisa</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Beatris</b>.</p><b>Beatrycze</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Wywodzi się od słowa oznaczającego „przynosząca szczęście”. Użyte w <i><a href=\"https://pl.wikipedia.org/wiki/Boska_komedia\" target=\"_blank\" rel=\"noopener noreferrer\">Boskiej komedii</a></i> <a href=\"https://pl.wikipedia.org/wiki/Dante_Alighieri\" target=\"_blank\" rel=\"noopener noreferrer\">Dantego</a>.", "Bożena Jadwiga": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bożena</b>.</p><b>Bożena</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, utworzone poprzez dodanie do rdzenia <i>boż-</i> (od „Bóg”) przyrostka zdrabniającego <i>-ana</i> lub <i>-ena</i>. Imię to zanotowano w dawnych dokumentach w formach <i><b>Bożana</b></i> i <i><b>Bożechna</b></i>, natomiast forma <b>Bożena</b> była znana w języku czeskim, a w Polsce zaczęła się pojawiać regularnie dopiero w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>.", "Barbara Janina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Barbara</b>.</p><b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Bożenna Barbara": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bożenna</b>.</p><b>Bożena</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, utworzone poprzez dodanie do rdzenia <i>boż-</i> (od „Bóg”) przyrostka zdrabniającego <i>-ana</i> lub <i>-ena</i>. Imię to zanotowano w dawnych dokumentach w formach <i><b>Bożana</b></i> i <i><b>Bożechna</b></i>, natomiast forma <b>Bożena</b> była znana w języku czeskim, a w Polsce zaczęła się pojawiać regularnie dopiero w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>.", "Bolesława Kazimiera": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bolesława</b>.</p><b>Bolesława</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Boles%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bolesław</a>. Forma ta jest notowana w Polsce od <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a>.", "Bronisława Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bronisława</b>.</p><b>Bronisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Broni-</i> („bronić, strzec”) i <i>-sława</i> („sława”). Być może znaczyło „ta, która broni sławy”. W źródłach polskich poświadczone od XIII wieku.", "Bảo Nhi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Begonia": "<b>Begonia</b>, ukośnica (<i>Begonia</i> L.) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin z rodziny <a href=\"https://pl.wikipedia.org/wiki/Begoniowate\" target=\"_blank\" rel=\"noopener noreferrer\">begoniowatych</a> obejmujący według różnych autorów 1200–1500 <a href=\"https://pl.wikipedia.org/wiki/Gatunek_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">gatunków</a>. Występują na wszystkich, z wyjątkiem Australii obszarach tropikalnych i subtropikalnych kuli ziemskiej, najliczniejsza grupa gatunków występuje w Ameryce Południowej. Jest to jeden z najbardziej obfitujących w gatunki rodzajów roślin. Należą do niego popularne na całym świecie <a href=\"https://pl.wikipedia.org/wiki/Ro%C5%9Bliny_ozdobne\" target=\"_blank\" rel=\"noopener noreferrer\">rośliny ozdobne</a>. Nazwa rodzaju pochodzi od nazwiska francuskiego botanika M. Begona. <a href=\"https://pl.wikipedia.org/wiki/Gatunek_typowy\" target=\"_blank\" rel=\"noopener noreferrer\">Gatunkiem typowym</a> jest <i> Begonia obliqua</i> L.", "Bahara": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bahar</b>.</p><p>Mądry kot to rosyjska legenda.</p>", "Bao Quyen": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Barbara Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Barbara</b>.</p><b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Barbie": "Nazwa Barbie jest <a href=\"https://pl.wikipedia.org/wiki/Zdrobnienie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnieniem</a> od imienia córki Ruth Handler, Barbary, dla której Ruth kupiła egzemplarz Lilli podczas pobytu w <a href=\"https://pl.wikipedia.org/wiki/Szwajcaria\" target=\"_blank\" rel=\"noopener noreferrer\">Szwajcarii</a>. Pełne nazwisko lalki to <b>Barbara Millicent Roberts</b>. Stanowi ono tylko część wymyślonej biografii, w której występują między innymi chłopak Barbie – <a href=\"https://pl.wikipedia.org/wiki/Ken_Carson\" target=\"_blank\" rel=\"noopener noreferrer\">Ken</a> i jej przyjaciółki – <a href=\"https://pl.wikipedia.org/wiki/Midge\" target=\"_blank\" rel=\"noopener noreferrer\">Midge</a> i Teresa. Barbie ma również trzy młodsze siostry o imionach Skipper, Stacie i Chelsea.", "Bratomiła": "<b>Bratumiła</b>, <b>Bratomiła</b>, <b>Bratmiła</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Bratu-</i> (\"bratu\", \"członkowi wspólnoty rodowej\", \"człowiekowi bliskiemu\") i <i>-miła</i> (\"miła\"). Znaczenie imienia: \"miła swoim bliskim\". W źródłach polskich poświadczone w XIII wieku (1265 rok).", "Bianca-Andreea": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bianca</b>.</p><p>Giuseppe Bianca (włoski: Giuseppe Bianca; 1801 - 1883) - włoski botanik.</p>", "Benitta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Benita</b>.</p><b>Benedykta</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Benedykt\" target=\"_blank\" rel=\"noopener noreferrer\">Benedykt</a>. Może też występować w formie <b>Benita</b>.", "Borysława Kazimiera": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Borysława</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Borysław</b>.</p><b>Borzysław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Wywodzi się od słów oznaczających „ten, który zdobywa sławę w boju”. Rosyjskim odpowiednikiem tego imienia jest <i>Borisław (Борислав)</i>.", "Bożenna Jadwiga": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bożenna</b>.</p><b>Bożena</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, utworzone poprzez dodanie do rdzenia <i>boż-</i> (od „Bóg”) przyrostka zdrabniającego <i>-ana</i> lub <i>-ena</i>. Imię to zanotowano w dawnych dokumentach w formach <i><b>Bożana</b></i> i <i><b>Bożechna</b></i>, natomiast forma <b>Bożena</b> była znana w języku czeskim, a w Polsce zaczęła się pojawiać regularnie dopiero w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>.", "Bao Thu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Beatrice-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Beatrice</b>.</p><p>Beatrice - znana grupa muzyczna, zakazana przez komunistyczny reżim węgier w 1981 roku.</p>", "Barbara Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Barbara</b>.</p><b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Bożenna Małgorzata": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bożenna</b>.</p><b>Bożena</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, utworzone poprzez dodanie do rdzenia <i>boż-</i> (od „Bóg”) przyrostka zdrabniającego <i>-ana</i> lub <i>-ena</i>. Imię to zanotowano w dawnych dokumentach w formach <i><b>Bożana</b></i> i <i><b>Bożechna</b></i>, natomiast forma <b>Bożena</b> była znana w języku czeskim, a w Polsce zaczęła się pojawiać regularnie dopiero w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>.", "Bianca-Milena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bianca</b>.</p><p>Giuseppe Bianca (włoski: Giuseppe Bianca; 1801 - 1883) - włoski botanik.</p>", "Barbara Ewa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Barbara</b>.</p><b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Barbara Jolanta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Barbara</b>.</p><b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Bianca-Oana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bianca</b>.</p><p>Giuseppe Bianca (włoski: Giuseppe Bianca; 1801 - 1883) - włoski botanik.</p>", "Bertha Lucia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bertha</b>.</p><p>Bertha (lat. Bertha; około 863 - 8 marca 925, Lucka) - najpierw grafia Arla (885 - między 887 i 890) w związku z Teobaldem, następnie markgrafia Toskania (między 890 i 895 - 915) w związku z Adalbertem II Bogaty; regent Marka Toskńskiego (915 - 916) przy swoim synie Gvidzie.</p>", "Basa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bas</b>.</p><p>Cornelis Bas (w 1928 - 2013) - holenderski botanik i mikolog.</p>", "Bao Linh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Barbara Danuta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Barbara</b>.</p><b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Birthe": "<p>Birthe to kobiece imię. Do wybitnych osób z tym nazwiskiem należą: Birthe Hegstad (ur. 1966), norweska piłkarka, zdobyła decydujący cel w finale mistrzostw Europy w 1993 roku.</p>", "Bibijan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bibian</b>.</p><b>Bibian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie utworzone od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiej</a> nazwy rodu <i>Vivius</i> i oznaczające \"należący do rodu <i>Vivii</i>\". Patronem tego imienia jest św. Bibian, biskup <a href=\"https://pl.wikipedia.org/wiki/Saintes\" target=\"_blank\" rel=\"noopener noreferrer\">Saintes</a> (<a href=\"https://pl.wikipedia.org/wiki/V_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">V wiek</a>).", "Biata": "<p>Beata lub Beate to imiona lub nazwisko portugalskie kobiet, które występuje w kilku kulturach i językach, w tym włoskim, niemieckim, polskim i szwedzkim, a które pochodzi z łacińskiego beatus, co oznacza \"błogosławiony\". Warianty obejmują Bea, Beade i Beáta.</p>", "Barbara Kazimiera": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Barbara</b>.</p><b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Barbara Władysława": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Barbara</b>.</p><b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Beatha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Beata</b>.</p><b>Beata</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Beat_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Beat</a>, pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>beatus</em> oznaczającego <i>błogosławiona, przynosząca szczęście, szczęśliwa</i>.", "Blanda": "<b>Blanda</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"czarująca\". Od tego imienia wywodzi się imię <a href=\"https://pl.wikipedia.org/wiki/Blandyna\" target=\"_blank\" rel=\"noopener noreferrer\">Blandyna</a>. Jego patronką jest św. Blanda, wspominana razem ze św. Symplicjuszem i Feliksem.", "Bożena Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bożena</b>.</p><b>Bożena</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, utworzone poprzez dodanie do rdzenia <i>boż-</i> (od „Bóg”) przyrostka zdrabniającego <i>-ana</i> lub <i>-ena</i>. Imię to zanotowano w dawnych dokumentach w formach <i><b>Bożana</b></i> i <i><b>Bożechna</b></i>, natomiast forma <b>Bożena</b> była znana w języku czeskim, a w Polsce zaczęła się pojawiać regularnie dopiero w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>.", "Bianca-Valentina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bianca</b>.</p><p>Giuseppe Bianca (włoski: Giuseppe Bianca; 1801 - 1883) - włoski botanik.</p>", "Barbara Aleksandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Barbara</b>.</p><b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Bao Tien": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Bergit": "<p>Birgit to kobiece imię, krótka forma Birgitta i ostatecznie germańska forma gaelickiego imienia Bridget. Do wybitnych osób z tym nazwiskiem należą: Birgit Brüel, duńska piosenkarka i aktorka Birgit Collin-Langen, niemiecka polityka Birgit Cunningham, anglo-amerykańska aktywistka Birgit Doll, austriacka aktorka i reżyserka teatralna Birgit Finnilä, szwedzka piosenkarz operowa Birgit Fischer, niemiecki kanoper Birgit Fogh-Andersen (1922-2012), duńska polityka...</p>", "Bao Trang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Bo Young": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bo</b>.</p><p>Bo lub BO może odnosić się do:</p>", "Bogumira": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bogumir</b>.</p><b>Bogumił</b>, <b>Bogomił</b>, <b>Bogmił</b>, <b>Bogomieł</b>, <b>Bogmieł</b>, <b>Bogumieł</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Wywodzi się ze złożenia członów: <i>Bog-</i> („Bóg”, ale pierwotnie w znaczeniu „los, dola, szczęście”) oraz <i>-mił</i> („miły”). Oznacza więc: „miły Bogu” (lecz uprzednio mogło znaczyć „ten, któremu los sprzyja”). <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Imiona słowiańskie</a> ze składnikami <i>Bog-</i> (np. Bogumił czy Bogusław) mogą być także słowiańskim naśladownictwem irańskich imion używanych w czasach od <a href=\"https://pl.wikipedia.org/wiki/VI_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">VI</a> do <a href=\"https://pl.wikipedia.org/wiki/IV_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">IV wieku p.n.e.</a>, takich jak Bagafarna („mający sławę od Boga”).", "Barbara Antonina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Barbara</b>.</p><b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Beatrice-Andreea": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Beatrice</b>.</p><p>Beatrice - znana grupa muzyczna, zakazana przez komunistyczny reżim węgier w 1981 roku.</p>", "Boleslawa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bolesław</b>.</p><b>Bolesław</b> (<i>bole(j)</i> + <i>sław</i> – „bardziej sławny”) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Dawniej zapisywane również w formie skróconej Bosław lub Bolko. Imię dynastyczne w polskiej dynastii <a href=\"https://pl.wikipedia.org/wiki/Piastowie\" target=\"_blank\" rel=\"noopener noreferrer\">Piastów</a> oraz czeskiej <a href=\"https://pl.wikipedia.org/wiki/Przemy%C5%9Blidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Przemyślidów</a>. Do dynastii piastowskiej zostało zapożyczone od <a href=\"https://pl.wikipedia.org/wiki/Przemy%C5%9Blidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Przemyślidów</a> poprzez dziedziczenie po linii żeńskiej (imię kognacyjne). Ostatnim jego piastowskim przedstawicielem był Piast mazowiecki <a href=\"https://pl.wikipedia.org/wiki/Boles%C5%82aw_V_warszawski\" target=\"_blank\" rel=\"noopener noreferrer\">Bolesław V, książę warszawski</a> (XV w.).", "Barbara Helena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Barbara</b>.</p><b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Bao Uyen": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Bảo Châu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Barbara Julia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Barbara</b>.</p><b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Blanca Cecilia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Blanca</b>.</p><p>Gabriel Blanca (szp. Gabriel Blanca, czy hiszpański.</p>", "Beatryks": "<b>Beatrycze</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Wywodzi się od słowa oznaczającego „przynosząca szczęście”. Użyte w <i><a href=\"https://pl.wikipedia.org/wiki/Boska_komedia\" target=\"_blank\" rel=\"noopener noreferrer\">Boskiej komedii</a></i> <a href=\"https://pl.wikipedia.org/wiki/Dante_Alighieri\" target=\"_blank\" rel=\"noopener noreferrer\">Dantego</a>.", "Barbara Camille": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Barbara</b>.</p><b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Bipasha": "<p>Bipasha to femininowe imię indyjskiego św. sanskrytu, co oznacza \"rzeka Beas\".</p>", "Bảo Trân": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Barbara Halina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Barbara</b>.</p><b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Burchin": "<p>Burçin to kobiece turskie imię. W języku tureckim oznacza to \"żółta jelenia\" lub \"doe\" i jest używane do wywołania łaski, elegancji i naturalnego piękna, często związane z cechami jelenia w kulturze tureckiej.</p>", "Bao Thy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bao</b>.</p><p>Bao to chińskie nazwisko (Han: 包, Bāo). W liście majątku, znajdują się na 185. miejscu.</p>", "Beata Helena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Beata</b>.</p><b>Beata</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Beat_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Beat</a>, pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>beatus</em> oznaczającego <i>błogosławiona, przynosząca szczęście, szczęśliwa</i>.", "Brenda Yaneth": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Brenda</b>.</p><b>Brenda</b> – żeńskie imię, które jest odpowiednikiem męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Brendan\" target=\"_blank\" rel=\"noopener noreferrer\">Brendan</a>. Imię popularne w kulturze amerykańskiej i angielskiej.", "Bo Kyung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bo</b>.</p><p>Bo lub BO może odnosić się do:</p>", "Bożenna Janina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Bożenna</b>.</p><b>Bożena</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, utworzone poprzez dodanie do rdzenia <i>boż-</i> (od „Bóg”) przyrostka zdrabniającego <i>-ana</i> lub <i>-ena</i>. Imię to zanotowano w dawnych dokumentach w formach <i><b>Bożana</b></i> i <i><b>Bożechna</b></i>, natomiast forma <b>Bożena</b> była znana w języku czeskim, a w Polsce zaczęła się pojawiać regularnie dopiero w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>.", "Barbara Pelagia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Barbara</b>.</p><b>Barbara</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> rozpowszechnione za sprawą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Βαρβάρα (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βαρβαρος – każdy kto nie&#160;był Grekiem) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Barbarzy%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">barbarzyńcę</a>”, a ściślej od jego łacińskiego odpowiednika w rodzaju żeńskim <i>barbara</i>, co oznacza „barbarzynkę”, czyli <b>cudzoziemkę</b>.", "Beatryksa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Beatryks</b>.</p><b>Beatrycze</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Wywodzi się od słowa oznaczającego „przynosząca szczęście”. Użyte w <i><a href=\"https://pl.wikipedia.org/wiki/Boska_komedia\" target=\"_blank\" rel=\"noopener noreferrer\">Boskiej komedii</a></i> <a href=\"https://pl.wikipedia.org/wiki/Dante_Alighieri\" target=\"_blank\" rel=\"noopener noreferrer\">Dantego</a>.", "Bernadine": "<p>Bernadine to żeńskie imię, wariant pisowni Bernardine. Znanymi osobami z nazwiska są: Bernadine Bezuidenhout (ur. 1993), nowozelandzkie krykerka Bernadine Craft, amerykański polityk z Wyomingu Bernadine Custer (1900-1991), amerykańska artystka Bernadina Hayes (1912-1987), amerykańska piosenkarka i aktorka Bernadines Healy (1944-2011), amerykański kardiolog Bernadine Jayasinghe, osobowość telewizyjna, zwycięzca prezydenckich nagród i...</p>", "Beenu": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Benu</b>.</p>Imię jego prawdopodobnie wywodziło się od słowa „weben” (wbn), co oznaczało „wznoszący się w blasku” lub „świecący, błyszczący”.", "Benta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Bent</b>.</p><p>Bent (rosyjski Izb) - duet z Nottingham w Anglii, składający się z Simona Mills i Nilla Tollida.</p>", "Beatta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Beata</b>.</p><b>Beata</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Beat_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Beat</a>, pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>beatus</em> oznaczającego <i>błogosławiona, przynosząca szczęście, szczęśliwa</i>."};
